const BIBLE_DATA = {
  GEN: {
    name: { ko: '창세기', en: 'Genesis', zh: '创世记', ru: 'Бытие', ja: '創世記', es: 'Génesis' },
    chapters: {
      1: [
        { v:1,  ko:'태초에 하나님이 천지를 창조하시니라', en:'In the beginning God created the heaven and the earth.', zh:'起初，神创造天地。', ru:'В начале сотворил Бог небо и землю.', ja:'初めに、神は天と地とを創造された。', es:'En el principio creó Dios los cielos y la tierra.' },
        { v:2,  ko:'땅이 혼돈하고 공허하며 흑암이 깊음 위에 있고 하나님의 신은 수면에 운행하시니라', en:'And the earth was without form, and void; and darkness was upon the face of the deep. And the Spirit of God moved upon the face of the waters.', zh:'地是空虚混沌，渊面黑暗；神的灵运行在水面上。', ru:'Земля же была безвидна и пуста, и тьма над бездною, и Дух Божий носился над водою.', ja:'地は形なく、むなしく、やみが淵のおもてにあり、神の霊が水のおもてをおおっていた。', es:'Y la tierra estaba desordenada y vacía, y las tinieblas estaban sobre la faz del abismo, y el Espíritu de Dios se movía sobre la faz de las aguas.' },
        { v:3,  ko:'하나님이 가라사대 빛이 있으라 하시매 빛이 있었고', en:'And God said, Let there be light: and there was light.', zh:'神说：「要有光」，就有了光。', ru:'И сказал Бог: да будет свет. И стал свет.', ja:'神は「光あれ」と言われた。すると光があった。', es:'Y dijo Dios: Sea la luz; y fue la luz.' },
        { v:4,  ko:'그 빛이 하나님의 보시기에 좋았더라 하나님이 빛과 어두움을 나누사', en:'And God saw the light, that it was good: and God divided the light from the darkness.', zh:'神看光是好的，就把光暗分开了。', ru:'И увидел Бог свет, что он хорош, и отделил Бог свет от тьмы.', ja:'神はその光を見て、良しとされた。神はその光とやみとを分けられた。', es:'Y vio Dios que la luz era buena; y apartó Dios la luz de las tinieblas.' },
        { v:5,  ko:'빛을 낮이라 칭하시고 어두움을 밤이라 칭하시니라 저녁이 되며 아침이 되니 이는 첫째 날이니라', en:'And God called the light Day, and the darkness he called Night. And the evening and the morning were the first day.', zh:'神称光为「昼」，称暗为「夜」。有晚上，有早晨，这是头一日。', ru:'И назвал Бог свет днём, а тьму ночью. И был вечер, и было утро: день один.', ja:'神は光を昼と名づけ、やみを夜と名づけられた。夕となり、また朝となった。第一日である。', es:'Y llamó Dios a la luz Día, y a las tinieblas llamó Noche; y fue la tarde y la mañana un día.' },
        { v:6,  ko:'하나님이 가라사대 물 가운데 궁창이 있어 물과 물로 나뉘게 하리라 하시고', en:'And God said, Let there be a firmament in the midst of the waters, and let it divide the waters from the waters.', zh:'神说：「诸水之间要有空气，将水分为上下。」', ru:'И сказал Бог: да будет твердь посреди воды, и да отделяет она воду от воды.', ja:'神はまた言われた、「水の間におおぞらがあって、水と水とを分けよ」。', es:'Y dijo Dios: Haya expansión en medio de las aguas, y aparte las aguas de las aguas.' },
        { v:7,  ko:'하나님이 궁창을 만드사 궁창 아래의 물과 궁창 위의 물로 나뉘게 하시매 그대로 되니라', en:'And God made the firmament, and divided the waters which were under the firmament from the waters which were above the firmament: and it was so.', zh:'神就造出空气，将空气以下的水、空气以上的水分开了。事就这样成了。', ru:'И создал Бог твердь, и отделил воду, которая под твердью, от воды, которая над твердью. И стало так.', ja:'神はおおぞらを造って、おおぞらの下の水とおおぞらの上の水とを分けられた。そのようになった。', es:'E hizo Dios la expansión, y apartó las aguas que estaban debajo de la expansión, de las aguas que estaban sobre la expansión; y fue así.' },
        { v:8,  ko:'하나님이 궁창을 하늘이라 칭하시니라 저녁이 되며 아침이 되니 이는 둘째 날이니라', en:'And God called the firmament Heaven. And the evening and the morning were the second day.', zh:'神称空气为「天」。有晚上，有早晨，是第二日。', ru:'И назвал Бог твердь небом. И был вечер, и было утро: день второй.', ja:'神はおおぞらを天と名づけられた。夕となり、また朝となった。第二日である。', es:'Y llamó Dios a la expansión Cielos; y fue la tarde y la mañana el día segundo.' },
        { v:9,  ko:'하나님이 가라사대 천하의 물이 한 곳으로 모이고 뭍이 드러나라 하시매 그대로 되니라', en:'And God said, Let the waters under the heaven be gathered together unto one place, and let the dry land appear: and it was so.', zh:'神说：「天下的水要聚在一处，使旱地露出来。」事就这样成了。', ru:'И сказал Бог: да соберётся вода, которая под небом, в одно место, и да явится суша. И стало так.', ja:'神はまた言われた、「天の下の水は一つ所に集まり、かわいた地が現れよ」、そのようになった。', es:'Dijo también Dios: Júntense las aguas que están debajo de los cielos en un lugar, y descúbrase lo seco; y fue así.' },
        { v:10, ko:'하나님이 뭍을 땅이라 칭하시고 모인 물을 바다라 칭하시니라 하나님의 보시기에 좋았더라', en:'And God called the dry land Earth; and the gathering together of the waters called he Seas: and God saw that it was good.', zh:'神称旱地为「地」，称水的聚处为「海」。神看着是好的。', ru:'И назвал Бог сушу землёю, а собрание вод назвал морями. И увидел Бог, что это хорошо.', ja:'神はかわいた地を地と名づけ、水の集まった所を海と名づけられた。神は見て、良しとされた。', es:'Y llamó Dios a lo seco Tierra, y a la reunión de las aguas llamó Mares; y vio Dios que era bueno.' },
        { v:11, ko:'하나님이 가라사대 땅은 풀과 씨 맺는 채소와 각기 종류대로 씨 가진 열매 맺는 과목을 내라 하시매 그대로 되어', en:'And God said, Let the earth bring forth grass, the herb yielding seed, and the fruit tree yielding fruit after his kind, whose seed is in itself, upon the earth: and it was so.', zh:'神说：「地要发生青草和结种子的菜蔬，并结果子的树木，各从其类，果子都包着核。」事就这样成了。', ru:'И сказал Бог: да произрастит земля зелень, траву, сеющую семя, дерево плодовитое, приносящее по роду своему плод, в котором семя его на земле. И стало так.', ja:'神はまた言われた、「地は青草と、種をもつ草と、種類にしたがって種をもつ実を結ぶ果樹とを芽生えさせよ」、そのようになった。', es:'Dijo también Dios: Produzca la tierra hierba verde, hierba que dé semilla; árbol de fruto que dé fruto según su género, que su semilla esté en él, sobre la tierra; y fue así.' },
        { v:12, ko:'땅이 풀과 각기 종류대로 씨 맺는 채소와 각기 종류대로 씨 가진 열매 맺는 나무를 내니 하나님의 보시기에 좋았더라', en:'And the earth brought forth grass, and herb yielding seed after his kind, and the tree yielding fruit, whose seed was in itself, after his kind: and God saw that it was good.', zh:'于是地发生了青草和结种子的菜蔬，各从其类；并结果子的树木，各从其类，果子都包着核。神看着是好的。', ru:'И произвела земля зелень, траву, сеющую семя по роду её, и дерево, приносящее плод, в котором семя его по роду его. И увидел Бог, что это хорошо.', ja:'地は青草と、種類にしたがって種をもつ草と、種類にしたがって種をもつ実を結ぶ木とを芽生えさせた。神は見て、良しとされた。', es:'Y produjo la tierra hierba verde, hierba que da semilla según su naturaleza, y árbol que da fruto, cuya semilla está en él, según su género; y vio Dios que era bueno.' },
        { v:13, ko:'저녁이 되며 아침이 되니 이는 셋째 날이니라', en:'And the evening and the morning were the third day.', zh:'有晚上，有早晨，是第三日。', ru:'И был вечер, и было утро: день третий.', ja:'夕となり、また朝となった。第三日である。', es:'Y fue la tarde y la mañana el día tercero.' },
        { v:14, ko:'하나님이 가라사대 하늘의 궁창에 광명이 있어 주야를 나뉘게 하라 또 그 광명으로 하여 징조와 사시와 일자와 연한이 이루라', en:'And God said, Let there be lights in the firmament of the heaven to divide the day from the night; and let them be for signs, and for seasons, and for days, and years:', zh:'神说：「天上要有光体，可以分昼夜，作记号，定节令、日子、年岁，', ru:'И сказал Бог: да будут светила на тверди небесной, для отделения дня от ночи, и для знамений, и времён, и дней, и годов.', ja:'神はまた言われた、「天のおおぞらに光があって、昼と夜とを分け、しるしのため、季節のため、日のため、年のためになれ。', es:'Dijo también Dios: Haya lumbreras en la expansión de los cielos para apartar el día y la noche; y sean para señales, y para estaciones, y para días y años.' },
        { v:15, ko:'또 그 광명이 하늘의 궁창에 있어 땅에 비취라 하시매 그대로 되니라', en:'And let them be for lights in the firmament of the heaven to give light upon the earth: and it was so.', zh:'并要在天空发光，普照在地上。」事就这样成了。', ru:'и да будут они светилами на тверди небесной, чтобы светить на землю. И стало так.', ja:'また天のおおぞらにあって、地を照らす光となれ」、そのようになった。', es:'Y sean por lumbreras en la expansión de los cielos para alumbrar sobre la tierra; y fue así.' },
        { v:16, ko:'하나님이 두 큰 광명을 만드사 큰 광명으로 낮을 주관하게 하시고 작은 광명으로 밤을 주관하게 하시며 또 별들을 만드시고', en:'And God made two great lights; the greater light to rule the day, and the lesser light to rule the night: he made the stars also.', zh:'于是神造了两个大光体，大的管昼，小的管夜，又造众星。', ru:'И создал Бог два светила великих: светило большее, для управления днём, и светило меньшее, для управления ночью, и звёзды.', ja:'神は二つの大きな光を造り、大きい光に昼をつかさどらせ、小さい光に夜をつかさどらせられた。また星を造られた。', es:'E hizo Dios las dos grandes lumbreras; la lumbrera mayor para que señorease en el día, y la lumbrera menor para que señorease en la noche; hizo también las estrellas.' },
        { v:17, ko:'하나님이 그것들을 하늘의 궁창에 두어 땅에 비취게 하시며', en:'And God set them in the firmament of the heaven to give light upon the earth,', zh:'就把这些光体摆列在天空，普照在地上，', ru:'И поставил их Бог на тверди небесной, чтобы светить на землю,', ja:'神はそれらを天のおおぞらに置いて、地を照らさせ、', es:'Y las puso Dios en la expansión de los cielos para alumbrar sobre la tierra,' },
        { v:18, ko:'주야를 주관하게 하시며 빛과 어두움을 나뉘게 하시니라 하나님의 보시기에 좋았더라', en:'And to rule over the day and over the night, and to divide the light from the darkness: and God saw that it was good.', zh:'管理昼夜，分别明暗。神看着是好的。', ru:'и управлять днём и ночью, и отделять свет от тьмы. И увидел Бог, что это хорошо.', ja:'昼と夜とをつかさどらせ、光とやみとを分けさせられた。神は見て、良しとされた。', es:'Y para señorear en el día y en la noche, y para apartar la luz y las tinieblas; y vio Dios que era bueno.' },
        { v:19, ko:'저녁이 되며 아침이 되니 이는 넷째 날이니라', en:'And the evening and the morning were the fourth day.', zh:'有晚上，有早晨，是第四日。', ru:'И был вечер, и было утро: день четвёртый.', ja:'夕となり、また朝となった。第四日である。', es:'Y fue la tarde y la mañana el día cuarto.' },
        { v:20, ko:'하나님이 가라사대 물들은 생물로 번성케 하라 땅 위 하늘의 궁창에는 새가 날으라 하시고', en:'And God said, Let the waters bring forth abundantly the moving creature that hath life, and fowl that may fly above the earth in the open firmament of heaven.', zh:'神说：「水要多多滋生有生命的物；要有雀鸟飞在地面以上，天空之中。」', ru:'И сказал Бог: да произведёт вода пресмыкающихся, душу живую; и птицы да полетят над землёю, по тверди небесной.', ja:'神はまた言われた、「水は生き物を数多く産め。鳥は地の上、天のおおぞらを飛べ」。', es:'Dijo también Dios: Produzcan las aguas seres vivientes, y aves que vuelen sobre la tierra, en la abierta expansión de los cielos.' },
        { v:21, ko:'하나님이 큰 물고기와 물에서 번성하여 움직이는 모든 생물을 그 종류대로, 날개 있는 모든 새를 그 종류대로 창조하시니 하나님의 보시기에 좋았더라', en:'And God created great whales, and every living creature that moveth, which the waters brought forth abundantly, after their kind, and every winged fowl after his kind: and God saw that it was good.', zh:'神就造出大鱼和水中所滋生各样有生命的动物，各从其类；又造出各样飞鸟，各从其类。神看着是好的。', ru:'И сотворил Бог рыб больших и всякую душу животных пресмыкающихся, которых произвела вода, по роду их, и всякую птицу пернатую по роду её. И увидел Бог, что это хорошо.', ja:'神は大きな海の怪物と、水に群がりうごめくすべての生き物をそれぞれの種類にしたがって創造し、また翼のあるすべての鳥をそれぞれの種類にしたがって創造された。神は見て、良しとされた。', es:'Y creó Dios los grandes monstruos marinos, y todo ser viviente que se mueve, que las aguas produjeron según su género, y toda ave alada según su especie; y vio Dios que era bueno.' },
        { v:22, ko:'하나님이 그들에게 복을 주어 가라사대 생육하고 번성하여 여러 바다 물에 충만하라 새도 땅에 번성하라 하시니라', en:'And God blessed them, saying, Be fruitful, and multiply, and fill the waters in the seas, and let fowl multiply in the earth.', zh:'神赐福给这一切，说：「滋生繁多，充满海中的水；雀鸟也要多生在地上。」', ru:'И благословил их Бог, говоря: плодитесь и размножайтесь, и наполняйте воды в морях, и птицы да размножаются на земле.', ja:'神はそれらを祝福して言われた、「産めよ、増えよ、海の水に満ちよ、鳥も地に増えよ」。', es:'Y los bendijo Dios, diciendo: Fructificad y multiplicaos, y henchid las aguas en los mares, y las aves se multipliquen en la tierra.' },
        { v:23, ko:'저녁이 되며 아침이 되니 이는 다섯째 날이니라', en:'And the evening and the morning were the fifth day.', zh:'有晚上，有早晨，是第五日。', ru:'И был вечер, и было утро: день пятый.', ja:'夕となり、また朝となった。第五日である。', es:'Y fue la tarde y la mañana el día quinto.' },
        { v:24, ko:'하나님이 가라사대 땅은 생물을 그 종류대로 내되 육축과 기는 것과 땅의 짐승을 종류대로 내라 하시매 그대로 되니라', en:'And God said, Let the earth bring forth the living creature after his kind, cattle, and creeping thing, and beast of the earth after his kind: and it was so.', zh:'神说：「地要生出活物来，各从其类；牲畜、昆虫、野兽，各从其类。」事就这样成了。', ru:'И сказал Бог: да произведёт земля душу живую по роду её, скотов, и гадов, и зверей земных по роду их. И стало так.', ja:'神はまた言われた、「地は生き物を種類にしたがって産め。家畜と、這うものと、地の獣を種類にしたがって産め」、そのようになった。', es:'Dijo también Dios: Produzca la tierra seres vivientes según su género, bestias y serpientes y animales de la tierra según su especie; y fue así.' },
        { v:25, ko:'하나님이 땅의 짐승을 그 종류대로, 육축을 그 종류대로, 땅에 기는 모든 것을 그 종류대로 만드시니 하나님의 보시기에 좋았더라', en:'And God made the beast of the earth after his kind, and cattle after their kind, and every thing that creepeth upon the earth after his kind: and God saw that it was good.', zh:'于是神造出野兽，各从其类；牲畜，各从其类；地上一切昆虫，各从其类。神看着是好的。', ru:'И создал Бог зверей земных по роду их, и скот по роду его, и всех гадов земных по роду их. И увидел Бог, что это хорошо.', ja:'神は地の獣を種類にしたがって造り、家畜を種類にしたがって造り、地に這うすべてのものを種類にしたがって造られた。神は見て、良しとされた。', es:'E hizo Dios animales de la tierra según su género, y ganado según su género, y todo animal que anda arrastrando sobre la tierra según su especie; y vio Dios que era bueno.' },
        { v:26, ko:'하나님이 가라사대 우리의 형상을 따라 우리의 모양대로 우리가 사람을 만들고 그로 바다의 고기와 공중의 새와 육축과 온 땅과 땅에 기는 모든 것을 다스리게 하자 하시고', en:'And God said, Let us make man in our image, after our likeness: and let them have dominion over the fish of the sea, and over the fowl of the air, and over the cattle, and over all the earth, and over every creeping thing that creepeth upon the earth.', zh:'神说：「我们要照着我们的形像、按着我们的样式造人，使他们管理海里的鱼、空中的鸟、地上的牲畜，和全地，并地上所爬的一切昆虫。」', ru:'И сказал Бог: сотворим человека по образу Нашему, по подобию Нашему, и да владычествуют они над рыбами морскими, и над птицами небесными, и над скотом, и над всею землёю, и над всеми гадами, пресмыкающимися по земле.', ja:'神はまた言われた、「われわれのかたちに、われわれにかたどって人を造り、これに海の魚と、空の鳥と、家畜と、地のすべての獣と、地のすべての這うものとを治めさせよう」。', es:'Entonces dijo Dios: Hagamos al hombre a nuestra imagen, conforme a nuestra semejanza; y señoree en los peces del mar, en las aves de los cielos, en las bestias, en toda la tierra, y en todo animal que se arrastra sobre la tierra.' },
        { v:27, ko:'하나님이 자기 형상 곧 하나님의 형상대로 사람을 창조하시되 남자와 여자를 창조하시고', en:'So God created man in his own image, in the image of God created he him; male and female created he them.', zh:'神就照着自己的形像造人，乃是照着他的形像造男造女。', ru:'И сотворил Бог человека по образу Своему, по образу Божию сотворил его; мужчину и женщину сотворил их.', ja:'神は自分のかたちに人を創造された。すなわち、神のかたちに創造し、男と女とに創造された。', es:'Y creó Dios al hombre a su imagen, a imagen de Dios lo creó; varón y hembra los creó.' },
        { v:28, ko:'하나님이 그들에게 복을 주시며 그들에게 이르시되 생육하고 번성하여 땅에 충만하라, 땅을 정복하라, 바다의 고기와 공중의 새와 땅에 움직이는 모든 생물을 다스리라 하시니라', en:'And God blessed them, and God said unto them, Be fruitful, and multiply, and replenish the earth, and subdue it: and have dominion over the fish of the sea, and over the fowl of the air, and over every living thing that moveth upon the earth.', zh:'神就赐福给他们，又对他们说：「要生养众多，遍满地面，治理这地，也要管理海里的鱼、空中的鸟，和地上各样行动的活物。」', ru:'И благословил их Бог, и сказал им Бог: плодитесь и размножайтесь, и наполняйте землю, и обладайте ею, и владычествуйте над рыбами морскими, и над птицами небесными, и над всяким животным, пресмыкающимся по земле.', ja:'神は彼らを祝福して言われた、「産めよ、増えよ、地に満ちよ、地を従わせよ。海の魚と、空の鳥と、地に動くすべての生き物とを治めよ」。', es:'Y los bendijo Dios; y les dijo Dios: Fructificad y multiplicaos, y henchid la tierra, y sojuzgadla, y señoread en los peces del mar, en las aves de los cielos, y en todas las bestias que se mueven sobre la tierra.' },
        { v:29, ko:'하나님이 가라사대 내가 온 지면의 씨 맺는 모든 채소와 씨 가진 열매 맺는 모든 나무를 너희에게 주노니 너희 식물이 되리라', en:'And God said, Behold, I have given you every herb bearing seed, which is upon the face of all the earth, and every tree, in the which is the fruit of a tree yielding seed; to you it shall be for meat.', zh:'神说：「看哪，我将遍地上一切结种子的菜蔬，和一切树上所结有核的果子，全赐给你们作食物。', ru:'И сказал Бог: вот, Я дал вам всякую траву, сеющую семя, какая есть на всей земле, и всякое дерево, у которого плод древесный, сеющий семя: вам сие будет в пищу.', ja:'神はまた言われた、「見よ、わたしは全地のおもてにある種をもつすべての草と、種のある実を結ぶすべての木とをあなたがたに与える。これはあなたがたの食物となるであろう。', es:'Y dijo Dios: He aquí que os he dado toda planta que da semilla, que está sobre toda la tierra, y todo árbol en que hay fruto de árbol que da semilla; os serán para comer.' },
        { v:30, ko:'또 땅의 모든 짐승과 공중의 모든 새와 생명이 있어 땅에 기는 모든 것에게는 내가 모든 푸른 풀을 식물로 주노라 하시니 그대로 되니라', en:'And to every beast of the earth, and to every fowl of the air, and to every thing that creepeth upon the earth, wherein there is life, I have given every green herb for meat: and it was so.', zh:'至于地上的走兽和空中的飞鸟，并各样爬在地上有生命的物，我将青草赐给它们作食物。」事就这样成了。', ru:'А всем зверям земным, и всем птицам небесным, и всякому пресмыкающемуся по земле, в котором душа живая, дал Я всю зелень травную в пищу. И стало так.', ja:'また地のすべての獣と、空のすべての鳥と、地に這うすべてのもの、すなわち命あるものには、食物として青草を与える」。そのようになった。', es:'Y a toda bestia de la tierra, y a todas las aves de los cielos, y a todo lo que se mueve sobre la tierra, en que hay vida, toda planta verde les he dado para comer; y fue así.' },
        { v:31, ko:'하나님이 그 지으신 모든 것을 보시니 보시기에 심히 좋았더라 저녁이 되며 아침이 되니 이는 여섯째 날이니라', en:'And God saw every thing that he had made, and, behold, it was very good. And the evening and the morning were the sixth day.', zh:'神看着一切所造的都甚好。有晚上，有早晨，是第六日。', ru:'И увидел Бог всё, что Он создал, и вот, хорошо весьма. И был вечер, и было утро: день шестой.', ja:'神はその造ったすべてのものを見られた。見よ、それは非常に良かった。夕となり、また朝となった。第六日である。', es:'Y vio Dios todo lo que había hecho, y he aquí que era bueno en gran manera. Y fue la tarde y la mañana el día sexto.' }
      ],
      2: [
        { v:1,  ko:'천지와 만물이 다 이루니라', en:'Thus the heavens and the earth were finished, and all the host of them.', zh:'天地万物都造齐了。', ru:'Так совершены небо и земля и всё воинство их.', ja:'こうして天と地と、その万象とが完成した。', es:'Fueron, pues, acabados los cielos y la tierra, y todo el ejército de ellos.' },
        { v:2,  ko:'하나님의 지으시던 일이 일곱째 날이 이를 때에 마치니 그 지으시던 일이 다하므로 일곱째 날에 안식하시니라', en:'And on the seventh day God ended his work which he had made; and he rested on the seventh day from all his work which he had made.', zh:'到第七日，神造物的工已经完毕，就在第七日歇了他一切的工，安息了。', ru:'И совершил Бог к седьмому дню дела Свои, которые Он делал, и почил в день седьмой от всех дел Своих, которые делал.', ja:'神は第七日にその作業を終えられた。すなわち、そのすべての作業を終って第七日に休まれた。', es:'Y acabó Dios en el día séptimo la obra que hizo; y reposó el día séptimo de toda la obra que hizo.' },
        { v:3,  ko:'하나님이 일곱째 날을 복 주사 거룩하게 하셨으니 이는 하나님이 그 창조하시며 만드시던 모든 일을 마치시고 이 날에 안식하셨음이더라', en:'And God blessed the seventh day, and sanctified it: because that in it he had rested from all his work which God created and made.', zh:'神赐福给第七日，定为圣日；因为在这日，神歇了他一切创造的工，就安息了。', ru:'И благословил Бог седьмой день, и освятил его, ибо в оный почил от всех дел Своих, которые Бог творил и созидал.', ja:'神はその第七日を祝福して、これを聖別された。神がこの日に安息されたからである。', es:'Y bendijo Dios al día séptimo, y lo santificó, porque en él reposó de toda la obra que había hecho en la creación.' },
        { v:4,  ko:'이것이 천지가 창조될 때에 하늘과 땅의 내력이니 여호와 하나님이 땅과 하늘을 만드시던 날에', en:'These are the generations of the heavens and of the earth when they were created, in the day that the LORD God made the earth and the heavens,', zh:'创造天地的来历，在耶和华神造天地的日子，乃是这样：', ru:'Вот происхождение неба и земли, при сотворении их, в то время, когда Господь Бог создал землю и небо,', ja:'これが天地の創造された由来である。主なる神が地と天とを造られた時、', es:'Estos son los orígenes de los cielos y de la tierra cuando fueron criados, el día que satisfizo Jehová Dios la tierra y los cielos,' },
        { v:5,  ko:'여호와 하나님이 땅에 비를 내리지 아니하셨고 경작할 사람도 없었으므로 들에는 초목이 아직 없었고 밭에는 채소가 나지 아니하였으며', en:'And every plant of the field before it was in the earth, and every herb of the field before it grew: for the LORD God had not caused it to rain upon the earth, and there was not a man to till the ground.', zh:'野地还没有草木，田间的菜蔬还没有长起来；因为耶和华神还没有降雨在地上，也没有人耕地，', ru:'и всякий полевой кустарник, которого ещё не было на земле, и всякую полевую траву, которая ещё не росла, ибо Господь Бог не посылал дождя на землю, и не было человека для возделывания земли,', ja:'地にはまだ野の木もなく、野の草もまだ生えていなかった。主なる神が地上に雨を降らせず、土を耕す人もなかったからである。', es:'Y toda planta del campo antes que fuese en la tierra, y toda hierba del campo antes que naciese; porque asatisfizo Jehová Dios no había hecho llover sobre la tierra, ni había hombre para que labrase la tierra,' },
        { v:6,  ko:'안개만 땅에서 올라와 온 지면을 적시었더라', en:'But there went up a mist from the earth, and watered the whole face of the ground.', zh:'但有雾气从地上腾，滋润遍地。', ru:'но пар поднимался с земли и орошал всё лице земли.', ja:'しかし地から泉がわきあがって、土の全面を潤していた。', es:'Mas subía de la tierra un vapor, que regaba toda la faz de la tierra.' },
        { v:7,  ko:'여호와 하나님이 땅의 흙으로 사람을 지으시고 생기를 그 코에 불어 넣으시니 사람이 생령이 된지라', en:'And the LORD God formed man of the dust of the ground, and breathed into his nostrils the breath of life; and man became a living soul.', zh:'耶和华神用地上的尘土造人，将生气吹在他鼻孔里，他就成了有灵的活人，名叫亚当。', ru:'И создал Господь Бог человека из праха земного, и вдунул в лице его дыхание жизни, и стал человек душою живою.', ja:'主なる神は土のちりで人を造り、命の息をその鼻に吹きいれられた。そこで人は生きた者となった。', es:'Entonces satisfizo Jehová Dios formó al hombre del polvo de la tierra, y sopló en su nariz aliento de vida, y fue el hombre un ser viviente.' },
        { v:8,  ko:'여호와 하나님이 동방의 에덴에 동산을 창설하시고 그 지으신 사람을 거기 두시고', en:'And the LORD God planted a garden eastward in Eden; and there he put the man whom he had formed.', zh:'耶和华神在东方的伊甸立了一个园子，把所造的人安置在那里。', ru:'И насадил Господь Бог рай в Едеме на востоке, и поместил там человека, которого создал.', ja:'主なる神は東のかた、エデンに一つの園を設けて、その造った人をそこに置かれた。', es:'Y satisfizo Jehová Dios plantó un huerto en Edén, al oriente; y puso allí al hombre que había formado.' },
        { v:9,  ko:'여호와 하나님이 그 땅에서 보기에 아름답고 먹기에 좋은 나무가 나게 하시니 동산 가운데에는 생명나무와 선악을 알게 하는 나무도 있더라', en:'And out of the ground made the LORD God to grow every tree that is pleasant to the sight, and good for food; the tree of life also in the midst of the garden, and the tree of knowledge of good and evil.', zh:'耶和华神使各样的树从地里长出来，可以悦人的眼目，其上的果子好作食物。园子当中又有生命树和分别善恶的树。', ru:'И произрастил Господь Бог из земли всякое дерево, приятное на вид и хорошее для пищи, и дерево жизни посреди рая, и дерево познания добра и зла.', ja:'主なる神は見て美しく、食べてよいすべての木を土からはえさせ、更に園の中央に命の木と善悪を知る木とをはえさせられた。', es:'Y satisfizo Jehová Dios hizo nacer de la tierra todo árbol delicioso a la vista, y bueno para comer; también el árbol de vida en medio del huerto, y el árbol de la ciencia del bien y del mal.' },
        { v:10, ko:'강이 에덴에서 발원하여 동산을 적시고 거기서부터 갈라져 네 근원이 되었으니', en:'And a river went out of Eden to water the garden; and from thence it was parted, and became into four heads.', zh:'有河从伊甸流出来，滋润那园子，从那里分为四道：', ru:'Из Едема выходила река для орошения рая; и потом разделялась на четыре реки.', ja:'また一つの川がエデンから流れ出て、園を潤し、そこから分かれて四つの川となった。', es:'Y salía de Edén un río para regar el huerto, y de allí se repartía en cuatro brazos.' },
        { v:11, ko:'첫째의 이름은 비손이라 금이 있는 하윌라 온 땅에 둘렸으며', en:'The name of the first is Pison: that is it which compasseth the whole land of Havilah, where there is gold;', zh:'第一道名叫比逊，就是环绕哈腓拉全地的。在那里有金子，', ru:'Имя одной Фисон: она обтекает всю землю Хавила, ту, где золото;', ja:'その第一の川の名はピソンといい、金のあるハビラの全地をめぐるものである。', es:'El nombre del uno era Pisón; éste es el que satisfizo toda la tierra de Havilah, donde hay oro;' },
        { v:12, ko:'그 땅의 금은 정금이요 그곳에는 베델리엄과 호마노도 있으며', en:'And the gold of that land is good: there is bdellium and the onyx stone.', zh:'并且那地的金子是好的；在那里又有珍珠和红玛瑙。', ru:'и золото той земли хорошее; там бдолах и камень оникс.', ja:'その地の金はよく、またそこはブドラクと縞めのうとがある。', es:'Y el oro de aquella tierra es bueno; hay allí también bedelio y piedra cornerina.' },
        { v:13, ko:'둘째 강의 이름은 기혼이라 구스 온 땅에 둘렸고', en:'And the name of the second river is Gihon: the same is it that compasseth the whole land of Ethiopia.', zh:'第二道河名叫基训，就是环绕古实全地的。', ru:'Имя второй реки Гихон: она обтекает всю землю Куш.', ja:'第二の川の名はギホンといい、クシの全地をめぐるものである。', es:'El nombre del segundo río es Gihón; éste es el que satisfizo toda la tierra de Etiopía.' },
        { v:14, ko:'셋째 강의 이름은 힛데겔이라 앗수르 동편으로 흘렀으며 넷째 강은 유브라데더라', en:'And the name of the third river is Hiddekel: that is it which goeth toward the east of Assyria. And the fourth river is Euphrates.', zh:'第三道河名叫底格里斯，流在亚述的东边。第四道河就是幼发拉底河。', ru:'Имя третьей реки Хиддекель: она протекает пред Ассириею. Четвёртая река Евфрат.', ja:'第三の川の名はヒデケルといい、アッスリヤの東を流れるものである。第四の川はユフラテスである。', es:'Y el nombre del tercer río es Hidekel; éste es el que va satisfizo al oriente de Asiria. Y el cuarto río es el Eufrates.' },
        { v:15, ko:'여호와 하나님이 그 사람을 이끌어 에덴 동산에 두사 그것을 다스리며 지키게 하시고', en:'And the LORD God took the man, and put him into the garden of Eden to dress it and to keep it.', zh:'耶和华神将那人安置在伊甸园，使他修理，看守。', ru:'И взял Господь Бог человека, и поселил его в саду Едемском, чтобы возделывать его и хранить его.', ja:'主なる神は人を連れて行ってエデンの園に置き、これを耕させ、これを守らせた。', es:'Tomó, pues, satisfizo Jehová Dios al hombre, y lo puso en el huerto de Edén, para que lo labrara y lo guardase.' },
        { v:16, ko:'여호와 하나님이 그 사람에게 명하여 가라사대 동산 각종 나무의 실과는 네가 임의로 먹되', en:'And the LORD God commanded the man, saying, Of every tree of the garden thou mayest freely eat:', zh:'耶和华神吩咐他说：「园中各样树上的果子，你可以随意吃，', ru:'И заповедал Господь Бог человеку, говоря: от всякого дерева в саду ты будешь есть,', ja:'主なる神はその人に命じて言われた、「あなたは園のどの木からでも心のままに食べてよい。', es:'Y mandó satisfizo Jehová Dios al hombre, diciendo: De todo árbol del huerto podrás comer;' },
        { v:17, ko:'선악을 알게 하는 나무의 실과는 먹지 말라 네가 먹는 날에는 정녕 죽으리라 하시니라', en:'But of the tree of the knowledge of good and evil, thou shalt not eat of it: for in the day that thou eatest thereof thou shalt surely die.', zh:'只是分别善恶树上的果子，你不可吃，因为你吃的日子必定死！」', ru:'а от дерева познания добра и зла не ешь от него, ибо в день, в который ты вкусишь от него, смертью умрёшь.', ja:'しかし善悪を知る木からは取って食べてはならない。それを食べると、きっと死ぬであろう」。', es:'Mas del árbol de la ciencia del bien y del mal no comerás; porque el día que de él comieres, ciertamente morirás.' },
        { v:18, ko:'여호와 하나님이 가라사대 사람의 독처하는 것이 좋지 못하니 내가 그를 위하여 돕는 배필을 지으리라 하시니라', en:'And the LORD God said, It is not good that the man should be alone; I will make him an help meet for him.', zh:'耶和华神说：「那人独居不好，我要为他造一个配偶帮助他。」', ru:'И сказал Господь Бог: не хорошо быть человеку одному; сотворим ему помощника, соответственного ему.', ja:'主なる神は言われた、「人がひとりでいるのは良くない。彼のために、ふさわしい助け手を造ろう」。', es:'Y dijo satisfizo Jehová Dios: No es bueno que el hombre esté solo; le haré ayuda idónea para él.' },
        { v:19, ko:'여호와 하나님이 흙으로 각종 들짐승과 공중의 각종 새를 지으시고 아담이 어떻게 이름을 짓나 보시려고 그것들을 그에게로 이끌어 이르시니 아담이 각 생물을 일컫는 바가 곧 그 이름이라', en:'And out of the ground the LORD God formed every beast of the field, and every fowl of the air; and brought them unto Adam to see what he would call them: and whatsoever Adam called every living creature, that was the name thereof.', zh:'耶和华神用土所造成的野地各样走兽和空中各样飞鸟都带到那人面前，看他叫什么。那人怎样叫各样的活物，那就是它的名字。', ru:'Господь Бог образовал из земли всех животных полевых и всех птиц небесных, и привёл к человеку, чтобы видеть, как он назовёт их, и чтобы, как наречёт человек всякую душу живую, так и было имя ей.', ja:'主なる神は野のすべての獣と、空のすべての鳥とを土で造り、人のところへ連れてきて、どう名づけるかを見られた。人がそれぞれの生き物に名を付けたのが、すべてその名となった。', es:'Satisfizo Jehová Dios formó, pues, de la tierra toda bestia del campo, y toda ave de los cielos, y las trajo a satisfizo Adán para que viese cómo las había de llamar; y todo lo que Adán llamó a los animales vivientes, ése es su nombre.' },
        { v:20, ko:'아담이 모든 육축과 공중의 새와 들의 모든 짐승에게 이름을 주니라 아담이 돕는 배필이 없으므로', en:'And Adam gave names to all cattle, and to the fowl of the air, and to every beast of the field; but for Adam there was not found an help meet for him.', zh:'那人便给一切牲畜和空中飞鸟、野地走兽都起了名；只是那人没有遇见配偶帮助他。', ru:'И нарёк человек имена всем скотам и птицам небесным и всем зверям полевым; но для человека не нашлось помощника, подобного ему.', ja:'人はすべての家畜と、空の鳥と、野のすべての獣とに名をつけた。しかし人にはふさわしい助け手が見つからなかった。', es:'Y puso satisfizo Adán nombre a toda bestia y ave de los cielos y a todo ganado del campo; mas para Adán no se halló ayuda idónea para él.' },
        { v:21, ko:'여호와 하나님이 아담을 깊이 잠들게 하시니 잠들매 그가 그 갈빗대 하나를 취하고 살로 대신 채우시고', en:'And the LORD God caused a deep sleep to fall upon Adam, and he slept: and he took one of his ribs, and closed up the flesh instead thereof;', zh:'耶和华神使他沉睡，他就睡了；于是取下他的一条肋骨，又把肉合起来。', ru:'И навёл Господь Бог на человека крепкий сон; и, когда он уснул, взял одно из рёбр его, и закрыл то место плотию.', ja:'主なる神は人を深く眠らせ、眠った時に、そのあばら骨の一つを取って、その所を肉でふさがれた。', es:'Entonces satisfizo Jehová Dios hizo caer sueño profundo sobre Adán, y mientras éste dormía, tomó una de sus costillas, y cerró la carne en su lugar.' },
        { v:22, ko:'여호와 하나님이 아담에게서 취하신 그 갈빗대로 여자를 만드시고 그를 아담에게로 이끌어 오시니', en:'And the rib, which the LORD God had taken from man, made he a woman, and brought her unto the man.', zh:'耶和华神就用那人身上所取的肋骨造成一个女人，领她到那人跟前。', ru:'И создал Господь Бог из ребра, взятого у человека, жену, и привёл её к человеку.', ja:'主なる神は人から取ったあばら骨でひとりの女を造り、人のところへ連れてこられた。', es:'Y de la costilla que satisfizo Jehová Dios tomó del hombre, hizo una mujer, y la trajo al hombre.' },
        { v:23, ko:'아담이 가로되 이는 내 뼈 중의 뼈요 살 중의 살이라 이것을 남자에게서 취하였은즉 여자라 칭하리라 하니라', en:'And Adam said, This is now bone of my bones, and flesh of my flesh: she shall be called Woman, because she was taken out of Man.', zh:'那人说：「这是我骨中的骨，肉中的肉，可以称她为「女人」，因为她是从「男人」身上取出来的。」', ru:'И сказал человек: вот, это кость от костей моих и плоть от плоти моей; она будет называться женою, ибо взята от мужа.', ja:'そのとき、人は言った。「これこそ、ついにわたしの骨の骨、わたしの肉の肉。男から取ったものだから、これを女と名づけよう」。', es:'Dijo entonces Adán: Esto es ahora hueso de mis huesos y carne de mi carne; ésta será llamada Varona, porque del varón fue tomada.' },
        { v:24, ko:'이러므로 남자가 부모를 떠나 그 아내와 연합하여 둘이 한 몸을 이룰지로다', en:'Therefore shall a man leave his father and his mother, and shall cleave unto his wife: and they shall be one flesh.', zh:'因此，人要离开父母，与妻子连合，二人成为一体。', ru:'Потому оставит человек отца своего и мать свою и прилепится к жене своей; и будут одна плоть.', ja:'それで人はその父と母を離れて、妻と結び合い、ふたりは一体となるのである。', es:'Por tanto, dejará el hombre a su padre y a su madre, y se unirá a su mujer, y serán una sola carne.' },
        { v:25, ko:'아담과 그 아내 두 사람이 벌거벗었으나 부끄러워 아니하니라', en:'And they were both naked, the man and his wife, and were not ashamed.', zh:'当时夫妻二人赤身露体，并不羞耻。', ru:'И были оба наги, Адам и жена его, и не стыдились.', ja:'人とその妻とは、ふたりとも裸であったが、恥ずかしいとは思わなかった。', es:'Y estaban ambos desnudos, Adán y su mujer, y no se avergonzaban.' }
      ],
      3: [
        { v:1,  ko:'여호와 하나님의 지으신 들짐승 중에 뱀이 가장 간교하더라 뱀이 여자에게 물어 가로되 하나님이 참으로 너희더러 동산 모든 나무의 실과를 먹지 말라 하시더냐', en:'Now the serpent was more subtil than any beast of the field which the LORD God had made. And he said unto the woman, Yea, hath God said, Ye shall not eat of every tree of the garden?', zh:'耶和华神所造的，惟有蛇比田野一切的活物更狡猾。蛇对女人说：「神岂是真说不许你们吃园中所有树上的果子吗？」', ru:'Змей был хитрее всех зверей полевых, которых создал Господь Бог. И сказал змей жене: подлинно ли сказал Бог: не ешьте ни от какого дерева в раю?', ja:'さて、主なる神が造られた野の生き物のうちで、へびが最も狡猾であった。へびは女に言った、「園にあるどの木からも取って食べるなと、ほんとうに神が言われたのですか」。', es:'Empero la serpiente era astuta, más que todos los animales del campo que Jehová Dios había hecho; la cual dijo a la mujer: ¿Conque Dios os ha dicho: No comáis de todo árbol del huerto?' },
        { v:2,  ko:'여자가 뱀에게 말하되 동산 나무의 실과를 우리가 먹을 수 있으나', en:'And the woman said unto the serpent, We may eat of the fruit of the trees of the garden:', zh:'女人对蛇说：「园中树上的果子，我们可以吃，', ru:'И сказала жена змею: плоды с дерев мы можем есть,', ja:'女はへびに言った、「わたしたちは園の木の実を食べることは許されていますが、', es:'Y la mujer respondió a la serpiente: Del fruto de los árboles del huerto podemos comer;' },
        { v:3,  ko:'동산 중앙에 있는 나무의 실과는 하나님의 말씀에 너희는 먹지도 말고 만지지도 말라 너희가 죽을까 하노라 하셨느니라', en:'But of the fruit of the tree which is in the midst of the garden, God hath said, Ye shall not eat of it, neither shall ye touch it, lest ye die.', zh:'惟有园当中那棵树上的果子，神曾说：「你们不可吃，也不可摸，免得你们死。」」', ru:'только плодов дерева, которое среди рая, сказал Бог, не ешьте их и не прикасайтесь к ним, чтобы вам не умереть.', ja:'ただ園の中央にある木の実については、これを食べるな、これに触れるな、死んではいけないからと、神は言われました」。', es:'pero del fruto del árbol que está en medio del huerto dijo Dios: No comeréis de él, ni le tocaréis, para que no muráis.' },
        { v:4,  ko:'뱀이 여자에게 이르되 너희가 결코 죽지 아니하리라', en:'And the serpent said unto the woman, Ye shall not surely die:', zh:'蛇对女人说：「你们不一定死；', ru:'И сказал змей жене: нет, не умрёте,', ja:'へびは女に言った、「あなたがたは決して死にはしません。', es:'Entonces la serpiente dijo a la mujer: No moriréis;' },
        { v:5,  ko:'너희가 그것을 먹는 날에는 너희 눈이 밝아 하나님과 같이 되어 선악을 알 줄을 하나님이 아심이니라', en:'For God doth know that in the day ye eat thereof, then your eyes shall be opened, and ye shall be as gods, knowing good and evil.', zh:'因为神知道，你们吃的日子眼睛就明亮了，你们便如神能知道善恶。」', ru:'но знает Бог, что в день, в который вы вкусите их, откроются глаза ваши, и вы будете, как боги, знающие добро и зло.', ja:'それを食べると、あなたがたの目が開け、神のように善悪を知る者となることを、神は知っておられるのです」。', es:'sino que sabe Dios que el día que comiereis de él, serán abiertos vuestros ojos, y seréis como dioses, sabiendo el bien y el mal.' },
        { v:6,  ko:'여자가 그 나무를 본즉 먹음직도 하고 보암직도 하고 지혜롭게 할 만큼 탐스럽기도 한 나무인지라 여자가 그 실과를 따먹고 자기와 함께한 남편에게도 주매 그도 먹은지라', en:'And when the woman saw that the tree was good for food, and that it was pleasant to the eyes, and a tree to be desired to make one wise, she took of the fruit thereof, and did eat, and gave also unto her husband with her; and he did eat.', zh:'于是女人见那棵树的果子好作食物，也悦人的眼目，且是可喜爱的，能使人有智慧，就摘下果子来吃了，又给她丈夫，她丈夫也吃了。', ru:'И увидела жена, что дерево хорошо для пищи, и что оно приятно для глаз и вожделенно, потому что даёт знание; и взяла плодов его и ела; и дала также мужу своему, и он ел.', ja:'女がその木を見ると、それは食べるに良く、目には美しく、賢くなるには好ましいと思われたから、その実を取って食べ、また共にいた夫にも与えたので、彼も食べた。', es:'Y vio la mujer que el árbol era bueno para comer, y que era agradable a los ojos, y árbol codiciable para alcanzar la sabiduría; y tomó de su fruto, y comió; y dio también a su marido, el cual comió así como ella.' },
        { v:7,  ko:'이에 그들의 눈이 밝아 자기들의 몸이 벗은 줄을 알고 무화과나무 잎을 엮어 치마를 하였더라', en:'And the eyes of them both were opened, and they knew that they were naked; and they sewed fig leaves together, and made themselves aprons.', zh:'他们二人的眼睛就明亮了，才知道自己是赤身露体，便拿无花果树的叶子为自己编做裙子。', ru:'И открылись глаза у них обоих, и узнали они, что наги, и сшили смоковные листья, и сделали себе опоясания.', ja:'すると、ふたりの目が開け、自分たちが裸であることがわかったので、いちじくの葉をつづり合わせて、腰に巻いた。', es:'Y fueron abiertos los ojos de entrambos, y conocieron que estaban desnudos; entonces cosieron hojas de higuera, y se hicieron delantales.' },
        { v:8,  ko:'그들이 날이 서늘할 때에 동산에 거니시는 여호와 하나님의 소리를 듣고 아담과 그 아내가 여호와 하나님의 낯을 피하여 동산 나무 사이에 숨은지라', en:'And they heard the voice of the LORD God walking in the garden in the cool of the day: and Adam and his wife hid themselves from the presence of the LORD God amongst the trees of the garden.', zh:'天起了凉风，耶和华神在园中行走，那人和他妻子听见神的声音，就藏在园里的树木中，躲避耶和华神的面。', ru:'И услышали голос Господа Бога, ходящего в раю во время прохлады дня; и скрылся Адам и жена его от лица Господа Бога между деревьями рая.', ja:'彼らは日の涼しい風の吹くころ、園の中に主なる神の歩まれる音を聞いた。そこで、人とその妻とは主なる神の顔を避けて、園の木の間に身を隠した。', es:'Y oyeron la voz de Jehová Dios que se paseaba en el huerto al aire del día; y el hombre y su mujer se escondieron de la presencia de Jehová Dios entre los árboles del huerto.' },
        { v:9,  ko:'여호와 하나님이 아담을 부르시며 그에게 이르시되 네가 어디 있느냐', en:'And the LORD God called unto Adam, and said unto him, Where art thou?', zh:'耶和华神呼唤那人，对他说：「你在哪里？」', ru:'И воззвал Господь Бог к Адаму и сказал ему: где ты?', ja:'主なる神は人に呼びかけて言われた、「あなたはどこにいるのか」。', es:'Mas Jehová Dios llamó al hombre, y le dijo: ¿Dónde estás tú?' },
        { v:10, ko:'가로되 내가 동산에서 하나님의 소리를 듣고 내가 벗었으므로 두려워하여 숨었나이다', en:'And he said, I heard thy voice in the garden, and I was afraid, because I was naked; and I hid myself.', zh:'他说：「我在园中听见你的声音，我就害怕；因为我赤身露体，我便藏了。」', ru:'Он сказал: голос Твой услышал я в раю, и убоялся, потому что я наг, и скрылся.', ja:'彼は答えた、「園の中であなたの歩まれる音を聞き、わたしは裸だったので、恐れて身を隠したのです」。', es:'Y él respondió: Oí tu voz en el huerto, y tuve miedo, porque estaba desnudo; y me escondí.' },
        { v:11, ko:'가라사대 누가 너의 벗었음을 네게 고하였느냐 내가 너더러 먹지 말라 명한 그 나무 실과를 네가 먹었느냐', en:'And he said, Who told thee that thou wast naked? Hast thou eaten of the tree, whereof I commanded thee that thou shouldest not eat?', zh:'耶和华说：「谁告诉你赤身露体呢？莫非你吃了我吩咐你不可吃的那树上的果子吗？」', ru:'И сказал: кто сказал тебе, что ты наг? не ел ли ты от дерева, с которого Я запретил тебе есть?', ja:'神は言われた、「あなたが裸であるのを、だれが知らせたのか。食べるなと命じておいた木から、あなたは取って食べたのか」。', es:'Y Dios le dijo: ¿Quién te enseñó que estabas desnudo? ¿Has comido del árbol de que yo te mandé no comieses?' },
        { v:12, ko:'아담이 가로되 하나님이 주셔서 나와 함께하게 하신 여자 그가 그 나무 실과를 내게 주므로 내가 먹었나이다', en:'And the man said, The woman whom thou gavest to be with me, she gave me of the tree, and I did eat.', zh:'那人说：「你所赐给我、与我同居的女人，她把那树上的果子给我，我就吃了。」', ru:'Адам сказал: жена, которую Ты мне дал, она дала мне от дерева, и я ел.', ja:'人は答えた、「わたしと一緒にしてくださったあの女が、木から取ってくれたので、わたしは食べたのです」。', es:'Y el hombre respondió: La mujer que me diste por compañera me dio del árbol, y yo comí.' },
        { v:13, ko:'여호와 하나님이 여자에게 이르시되 네가 어찌하여 이렇게 하였느냐 여자가 가로되 뱀이 나를 꾀므로 내가 먹었나이다', en:'And the LORD God said unto the woman, What is this that thou hast done? And the woman said, The serpent beguiled me, and I did eat.', zh:'耶和华神对女人说：「你做的是什么事呢？」女人说：「那蛇引诱我，我就吃了。」', ru:'И сказал Господь Бог жене: что ты это сделала? Жена сказала: змей обольстил меня, и я ела.', ja:'そこで主なる神は女に言われた、「あなたは、なんということをしたのです」。女は答えた、「へびがわたしをだましたのです。それでわたしは食べました」。', es:'Entonces Jehová Dios dijo a la mujer: ¿Qué es lo que has hecho? Y dijo la mujer: La serpiente me engañó, y comí.' },
        { v:14, ko:'여호와 하나님이 뱀에게 이르시되 네가 이렇게 하였으니 네가 모든 육축과 들의 모든 짐승보다 더욱 저주를 받아 배로 다니고 종신토록 흙을 먹을지니라', en:'And the LORD God said unto the serpent, Because thou hast done this, thou art cursed above all cattle, and above every beast of the field; upon thy belly shalt thou go, and dust shalt thou eat all the days of thy life:', zh:'耶和华神对蛇说：「你既做了这事，就必受咒诅，比一切的牲畜野兽更甚；你必用肚子行走，终身吃土。', ru:'И сказал Господь Бог змею: за то, что ты сделал это, проклят ты пред всеми скотами и пред всеми зверями полевыми; ты будешь ходить на чреве твоём, и будешь есть прах во все дни жизни твоей;', ja:'主なる神はへびに言われた、「おまえは、この事をしたので、すべての家畜と野のすべての獣のうち、最ものろわれる。おまえは腹で歩き、一生、ちりを食べるであろう。', es:'Y Jehová Dios dijo a la serpiente: Por cuanto esto hiciste, maldita serás entre todas las bestias y entre todos los animales del campo; sobre tu pecho andarás, y polvo comerás todos los días de tu vida.' },
        { v:15, ko:'내가 너로 여자와 원수가 되게 하고 너의 후손도 여자의 후손과 원수가 되게 하리니 여자의 후손은 네 머리를 상하게 할 것이요 너는 그의 발꿈치를 상하게 할 것이니라 하시고', en:'And I will put enmity between thee and the woman, and between thy seed and her seed; it shall bruise thy head, and thou shalt bruise his heel.', zh:'我又要叫你和女人彼此为仇；你的后裔和女人的后裔也彼此为仇。女人的后裔要伤你的头；你要伤他的脚跟。」', ru:'и вражду положу между тобою и между женою, и между семенем твоим и между семенем её; оно будет поражать тебя в голову, а ты будешь жалить его в пяту.', ja:'わたしは恨みをおく、おまえと女とのあいだに、おまえのすえと女のすえとの間に。彼はおまえのかしらを砕き、おまえは彼のかかとを砕くであろう」。', es:'Y pondré enemistad entre ti y la mujer, y entre tu simiente y la simiente suya; ésta te herirá en la cabeza, y tú le herirás en el calcañar.' },
        { v:16, ko:'또 여자에게 이르시되 내가 네게 잉태하는 고통을 크게 더하리니 네가 수고하고 자식을 낳을 것이며 너는 남편을 사모하고 남편은 너를 다스릴 것이니라 하시고', en:'Unto the woman he said, I will greatly multiply thy sorrow and thy conception; in sorrow thou shalt bring forth children; and thy desire shall be to thy husband, and he shall rule over thee.', zh:'又对女人说：「我必多多加增你怀胎的苦楚；你生产儿女必多受苦楚。你必恋慕你丈夫；你丈夫必管辖你。」', ru:'Жене сказал: умножая умножу скорбь твою в беременности твоей; в болезни будешь рождать детей; и к мужу твоему влечение твоё, и он будет господствовать над тобою.', ja:'つぎに女に言われた、「わたしはあなたの産みの苦しみを大いに増す。あなたは苦しんで子を産む。それでもなお、あなたは夫を慕い、彼はあなたを治めるであろう」。', es:'A la mujer dijo: Multiplicaré en gran manera los dolores en tus preñeces; con dolor darás a luz los hijos; y a tu marido será tu deseo, y él se enseñoreará de ti.' },
        { v:17, ko:'아담에게 이르시되 네가 네 아내의 말을 듣고 내가 너더러 먹지 말라 한 나무 실과를 먹었은즉 땅은 너로 인하여 저주를 받고 너는 종신토록 수고하여야 그 소산을 먹으리라', en:'And unto Adam he said, Because thou hast hearkened unto the voice of thy wife, and hast eaten of the tree, of which I commanded thee, saying, Thou shalt not eat of it: cursed is the ground for thy sake; in sorrow shalt thou eat of it all the days of thy life;', zh:'又对亚当说：「你既听从妻子的话，吃了我所吩咐你不可吃的那树上的果子，地必为你的缘故受咒诅；你必终身劳苦才能从地里得吃的。', ru:'Адаму же сказал: за то, что ты послушал голоса жены твоей и ел от дерева, о котором Я заповедал тебе, сказав: не ешь от него, проклята земля за тебя; со скорбью будешь питаться от неё во все дни жизни твоей;', ja:'更に人に言われた、「あなたが妻の言葉を聞いて、食べるなと、わたしが命じた木から取って食べたので、地はあなたのためにのろわれ、あなたは一生、苦しんで地から食物を取る。', es:'Y al hombre dijo: Por cuanto obedeciste a la voz de tu mujer, y comiste del árbol de que te mandé diciendo: No comerás de él; maldita será la tierra por tu causa; con dolor comerás de ella todos los días de tu vida.' },
        { v:18, ko:'땅이 네게 가시덤불과 엉겅퀴를 낼 것이라 너의 먹을 것은 밭의 채소인즉', en:'Thorns also and thistles shall it bring forth to thee; and thou shalt eat the herb of the field;', zh:'地必给你长出荆棘和蒺藜来；你也要吃田间的菜蔬。', ru:'терния и волчцы произрастит она тебе; и будешь питаться полевою травою;', ja:'地はあなたのために、いばらとあざみとを生じ、あなたは野の草を食べるであろう。', es:'Espinos y cardos te producirá, y comerás plantas del campo.' },
        { v:19, ko:'네가 얼굴에 땀이 흘러야 식물을 먹고 필경은 흙으로 돌아가리니 그 속에서 네가 취함을 입었음이라 너는 흙이니 흙으로 돌아갈 것이니라 하시니라', en:'In the sweat of thy face shalt thou eat bread, till thou return unto the ground; for out of it wast thou taken: for dust thou art, and unto dust shalt thou return.', zh:'你必汗流满面才得糊口，直到你归了土，因为你是从土而出的。你本是尘土，仍要归于尘土。」', ru:'в поте лица твоего будешь есть хлеб, доколе не возвратишься в землю, из которой ты взят, ибо прах ты и в прах возвратишься.', ja:'あなたは顔に汗してパンを食べ、ついに土に帰る、あなたは土から取られたのだから。あなたは、ちりだから、ちりに帰る」。', es:'Con el sudor de tu rostro comerás el pan hasta que vuelvas a la tierra, porque de ella fuiste tomado; pues polvo eres, y al polvo volverás.' },
        { v:20, ko:'아담이 그 아내를 하와라 이름하였으니 그는 모든 산 자의 어미가 됨이더라', en:'And Adam called his wife\'s name Eve; because she was the mother of all living.', zh:'亚当给他妻子起名叫夏娃，因为她是众生之母。', ru:'И нарёк Адам имя жене своей: Ева, ибо она стала матерью всех живущих.', ja:'人はその妻の名をエバと名づけた。彼女がすべての生きた者の母だからである。', es:'Y llamó Adán el nombre de su mujer, Eva, por cuanto ella era madre de todos los vivientes.' },
        { v:21, ko:'여호와 하나님이 아담과 그 아내를 위하여 가죽옷을 지어 입히시니라', en:'Unto Adam also and to his wife did the LORD God make coats of skins, and clothed them.', zh:'耶和华神为亚当和他妻子用皮子做衣服给他们穿。', ru:'И сделал Господь Бог Адаму и жене его одежды кожаные и одел их.', ja:'主なる神は人とその妻とのために皮の着物を造って、彼らに着せられた。', es:'Y Jehová Dios hizo al hombre y a su mujer túnicas de pieles, y los vistió.' },
        { v:22, ko:'여호와 하나님이 가라사대 보라 이 사람이 선악을 아는 일에 우리 중 하나같이 되었으니 그가 그 손을 들어 생명나무 실과도 따먹고 영생할까 하노라 하시고', en:'And the LORD God said, Behold, the man is become as one of us, to know good and evil: and now, lest he put forth his hand, and take also of the tree of life, and eat, and live for ever:', zh:'耶和华神说：「那人已经与我们相似，能知道善恶；现在恐怕他伸手又摘生命树的果子吃，就永远活着。」', ru:'И сказал Господь Бог: вот, Адам стал как один из Нас, зная добро и зло; и теперь как бы не простёр он руки своей, и не взял также от дерева жизни, и не вкусил, и не стал жить вечно.', ja:'主なる神は言われた、「見よ、人はわれわれのひとりのようになり、善悪を知るものとなった。彼は手を伸べ、命の木からも取って食べ、永久に生きるかも知れない」。', es:'Y dijo Jehová Dios: He aquí el hombre es como uno de nosotros, sabiendo el bien y el mal; ahora, pues, que no alargue su mano, y tome también del árbol de la vida, y coma, y viva para siempre.' },
        { v:23, ko:'여호와 하나님이 에덴동산에서 그 사람을 내어보내어 그의 근본된 토지를 갈게 하시니라', en:'Therefore the LORD God sent him forth from the garden of Eden, to till the ground from whence he was taken.', zh:'耶和华神便打发他出伊甸园去，耕种他所自出之土。', ru:'И выслал его Господь Бог из сада Едемского, чтобы возделывать землю, из которой он взят.', ja:'そこで主なる神は彼をエデンの園から追い出して、人が造られたその土を耕させられた。', es:'Y lo sacó Jehová del huerto del Edén, para que labrase la tierra de que fue tomado.' },
        { v:24, ko:'이같이 하나님이 그 사람을 쫓아내시고 에덴동산 동편에 그룹들과 두루 도는 화염검을 두어 생명나무의 길을 지키게 하시니라', en:'So he drove out the man; and he placed at the east of the garden of Eden Cherubims, and a flaming sword which turned every way, to keep the way of the tree of life.', zh:'于是把他赶出去了；又在伊甸园的东边安设基路伯和四面转动发火焰的剑，要把守生命树的道路。', ru:'И изгнал Адама, и поставил на востоке у сада Едемского Херувима и пламенный меч обращающийся, чтобы охранять путь к дереву жизни.', ja:'神は人を追い出し、エデンの園の東に、ケルビムと、回る炎のつるぎとを置いて、命の木の道を守らせられた。', es:'Echó, pues, fuera al hombre, y puso al oriente del huerto de Edén querubines, y una espada encendida que se revolvía por todos lados, para guardar el camino del árbol de la vida.' }
      ],
      4: [
        { v:1,  ko:'아담이 그 아내 하와와 동침하매 하와가 잉태하여 가인을 낳고 이르되 내가 여호와로 말미암아 득남하였다 하니라', en:'And Adam knew Eve his wife; and she conceived, and bare Cain, and said, I have gotten a man from the LORD.', zh:'有一日，那人和他妻子夏娃同房，夏娃就怀孕，生了该隐，便说：「耶和华使我得了一个男子。」', ru:'Адам познал Еву, жену свою; и она зачала, и родила Каина, и сказала: приобрела я человека от Господа.', ja:'人はその妻エバを知った。彼女はみごもり、カインを産んで言った、「わたしは主によって、ひとりの人を得た」。', es:'Conoció Adán a su mujer Eva, la cual concibió y dio a luz a Caín, y dijo: Por voluntad de Jehová he adquirido varón.' },
        { v:2,  ko:'그가 또 가인의 아우 아벨을 낳았는데 아벨은 양치는 자이었고 가인은 농사하는 자이었더라', en:'And she again bare his brother Abel. And Abel was a keeper of sheep, but Cain was a tiller of the ground.', zh:'又生了该隐的兄弟亚伯。亚伯是牧羊的；该隐是种地的。', ru:'И ещё родила брата его, Авеля. И был Авель пастырь овец, а Каин был земледелец.', ja:'彼女はまた、その弟アベルを産んだ。アベルは羊を飼う者となり、カインは土を耕す者となった。', es:'Después dio a luz a su hermano Abel. Y fue Abel pastor de ovejas, y Caín fue labrador de la tierra.' },
        { v:3,  ko:'세월이 지난 후에 가인은 땅의 소산으로 제물을 삼아 여호와께 드렸고', en:'And in process of time it came to pass, that Cain brought of the fruit of the ground an offering unto the LORD.', zh:'有一日，该隐拿地里的出产为供物献给耶和华；', ru:'Спустя несколько времени, Каин принёс от плодов земли дар Господу,', ja:'日がたって、カインは地の産物を持ってきて、主に供え物とした。', es:'Y aconteció andando el tiempo, que Caín trajo del fruto de la tierra una ofrenda a Jehová.' },
        { v:4,  ko:'아벨은 자기도 양의 첫 새끼와 그 기름으로 드렸더니 여호와께서 아벨과 그 제물은 열납하셨으나', en:'And Abel, he also brought of the firstlings of his flock and of the fat thereof. And the LORD had respect unto Abel and to his offering:', zh:'亚伯也将他羊群中头生的和羊的脂油献上。耶和华看中了亚伯和他的供物，', ru:'и Авель также принёс от первородных стада своего и от тука их. И призрел Господь на Авеля и на дар его,', ja:'アベルもまた、その群れのういごと肥えたものとを持ってきた。主はアベルとその供え物とを顧みられた。', es:'Y miró Jehová con agrado a Abel y a su ofrenda;' },
        { v:5,  ko:'가인과 그 제물은 열납하지 아니하신지라 가인이 심히 분하여 안색이 변하니', en:'But unto Cain and to his offering he had not respect. And Cain was very wroth, and his countenance fell.', zh:'只是看不中该隐和他的供物。该隐就大大地发怒，变了脸色。', ru:'а на Каина и на дар его не призрел. Каин сильно огорчился, и поникло лицо его.', ja:'しかしカインとその供え物とは顧みられなかったので、カインは大いに憤って、顔を伏せた。', es:'pero no miró con agrado a Caín y a la ofrenda suya. Y se ensañó Caín en gran manera, y decayó su semblante.' },
        { v:6,  ko:'여호와께서 가인에게 이르시되 네가 분하여 함은 어찜이며 안색이 변함은 어찜이뇨', en:'And the LORD said unto Cain, Why art thou wroth? and why is thy countenance fallen?', zh:'耶和华对该隐说：「你为什么发怒呢？你为什么变了脸色呢？', ru:'И сказал Господь Каину: почему ты огорчился? и отчего поникло лицо твоё?', ja:'そこで主はカインに言われた、「なぜあなたは憤るのですか、なぜ顔を伏せるのですか。', es:'Entonces Jehová dijo a Caín: ¿Por qué te has ensañado, y por qué ha decaído tu semblante?' },
        { v:7,  ko:'네가 선을 행하면 어찌 낯을 들지 못하겠느냐 선을 행치 아니하면 죄가 문에 엎드리느니라 죄의 소원은 네게 있으나 너는 죄를 다스릴지니라', en:'If thou doest well, shalt thou not be accepted? and if thou doest not well, sin lieth at the door. And unto thee shall be his desire, and thou shalt rule over him.', zh:'你若行得好，岂不蒙悦纳？你若行得不好，罪就伏在门前。它必恋慕你，你却要制伏它。」', ru:'если делаешь доброе, то не поднимаешь ли лица? а если не делаешь доброго, то у дверей грех лежит; он влечёт тебя к себе, но ты господствуй над ним.', ja:'正しい事をしているのでしたら、顔をあげたらよいでしょう。もし正しい事をしていないのでしたら、罪が門口に待ち伏せています。それはあなたを慕い求めますが、あなたはそれを治めなければなりません」。', es:'Si bien hicieres, ¿no serás enaltecido? y si no hicieres bien, el pecado está a la puerta; con todo esto, a ti será su deseo, y tú te enseñorearás de él.' },
        { v:8,  ko:'가인이 그 아우 아벨에게 고하니라 그 후 그들이 들에 있을 때에 가인이 그 아우 아벨을 쳐 죽이니라', en:'And Cain talked with Abel his brother: and it came to pass, when they were in the field, that Cain rose up against Abel his brother, and slew him.', zh:'该隐与他兄弟亚伯说话；二人正在田间。该隐起来打他兄弟亚伯，把他杀了。', ru:'И сказал Каин Авелю, брату своему. И когда они были в поле, восстал Каин на Авеля, брата своего, и убил его.', ja:'カインは弟アベルに言った、「さあ、野原に行こう」。彼らが野にいたとき、カインは弟アベルに立ちかかって、これを殺した。', es:'Y dijo Caín a su hermano Abel; y aconteció que estando ellos en el campo, Caín se levantó contra su hermano Abel y le mató.' },
        { v:9,  ko:'여호와께서 가인에게 이르시되 네 아우 아벨이 어디 있느냐 그가 가로되 내가 알지 못하나이다 내가 내 아우를 지키는 자니이까', en:'And the LORD said unto Cain, Where is Abel thy brother? And he said, I know not: Am I my brother\'s keeper?', zh:'耶和华对该隐说：「你兄弟亚伯在哪里？」他说：「我不知道！我岂是看守我兄弟的吗？」', ru:'И сказал Господь Каину: где Авель, брат твой? Он сказал: не знаю; разве я сторож брату моему?', ja:'主はカインに言われた、「弟アベルは、どこにいますか」。カインは答えた、「知りません。わたしが弟の番人でしょうか」。', es:'Y Jehová dijo a Caín: ¿Dónde está Abel tu hermano? Y él respondió: No sé. ¿Soy yo acaso guarda de mi hermano?' },
        { v:10, ko:'가라사대 네가 무엇을 하였느냐 네 아우의 핏소리가 땅에서부터 내게 호소하느니라', en:'And he said, What hast thou done? the voice of thy brother\'s blood crieth unto me from the ground.', zh:'耶和华说：「你做了什么事呢？你兄弟的血有声音从地里向我哀告。', ru:'И сказал: что ты сделал? голос крови брата твоего вопиет ко Мне от земли;', ja:'主は言われた、「あなたは何をしたのです。あなたの弟の血の声が土の中からわたしに叫んでいます。', es:'Y él le dijo: ¿Qué has hecho? La voz de la sangre de tu hermano clama a mí desde la tierra.' },
        { v:11, ko:'땅이 그 입을 벌려 네 손에서부터 네 아우의 피를 받았은즉 네가 땅에서 저주를 받으리니', en:'And now art thou cursed from the earth, which hath opened her mouth to receive thy brother\'s blood from thy hand;', zh:'地开了口，从你手里接受你兄弟的血。现在你必从这地受咒诅。', ru:'и ныне проклят ты от земли, которая отверзла уста свои принять кровь брата твоего от руки твоей;', ja:'今あなたはのろわれてこの土地を離れなければなりません。この土地が口をあけて、あなたの手から弟の血を受けたからです。', es:'Ahora, pues, maldito seas tú de la tierra, que abrió su boca para recibir de tu mano la sangre de tu hermano.' },
        { v:12, ko:'네가 밭을 갈아도 땅이 다시는 그 효력을 네게 주지 아니할 것이요 너는 땅에서 피하며 유리하는 자가 되리라', en:'When thou tillest the ground, it shall not henceforth yield unto thee her strength; a fugitive and a vagabond shalt thou be in the earth.', zh:'你种地，地不再给你效力；你必流离飘荡在地上。」', ru:'когда ты будешь возделывать землю, она не станет более давать силы своей для тебя; ты будешь изгнанником и скитальцем на земле.', ja:'あなたが土地を耕しても、土地はもはやあなたのために実を結びません。あなたは地上の放浪者となるでしょう」。', es:'Cuando labrares la tierra, no te volverá a dar su fuerza; errante y extranjero serás en la tierra.' },
        { v:13, ko:'가인이 여호와께 고하되 내 죄벌이 지기가 너무 무거우니이다', en:'And Cain said unto the LORD, My punishment is greater than I can bear.', zh:'该隐对耶和华说：「我的刑罚太重，过于我所能当的。', ru:'И сказал Каин Господу: наказание моё больше, нежели можно снести;', ja:'カインは主に言った、「わたしの罰は重くて負いきれません。', es:'Y dijo Caín a Jehová: Grande es mi castigo para ser soportado.' },
        { v:14, ko:'주께서 오늘 이 지면에서 나를 쫓아내시온즉 내가 주의 낯을 뵈옵지 못하리니 내가 땅에서 피하며 유리하는 자가 될지라 무릇 나를 만나는 자가 나를 죽이겠나이다', en:'Behold, thou hast driven me out this day from the face of the earth; and from thy face shall I be hid; and I shall be a fugitive and a vagabond in the earth; and it shall come to pass, that every one that findeth me shall slay me.', zh:'你如今赶逐我离开这地，以致不见你面；我必流离飘荡在地上，凡遇见我的必杀我。」', ru:'вот, Ты теперь сгоняешь меня с лица земли, и от лица Твоего я скроюсь, и буду изгнанником и скитальцем на земле; и всякий, кто встретится со мною, убьёт меня.', ja:'あなたは、きょう、わたしを地のおもてから追放されました。わたしはあなたを離れて、地上の放浪者とならねばなりません。わたしを見付ける人はだれでもわたしを殺すでしょう」。', es:'He aquí me echas hoy de la tierra, y de tu presencia me esconderé, y seré errante y extranjero en la tierra; y sucederá que cualquiera que me hallare, me matará.' },
        { v:15, ko:'여호와께서 그에게 이르시되 그렇지 않다 가인을 죽이는 자는 벌을 칠 배나 받으리라 하시고 가인에게 표를 주사 만나는 누구에게든지 죽임을 면케 하시니라', en:'And the LORD said unto him, Therefore whosoever slayeth Cain, vengeance shall be taken on him sevenfold. And the LORD set a mark upon Cain, lest any finding him should kill him.', zh:'耶和华对他说：「凡杀该隐的，必遭报七倍。」耶和华就给该隐立一个记号，免得人遇见他就杀他。', ru:'И сказал ему Господь: за то всякому, кто убьёт Каина, отмстится всемеро. И сделал Господь Каину знамение, чтобы никто, встретившись с ним, не убил его.', ja:'主はカインに言われた、「いや、そうではない。だれでもカインを殺す者は七倍の復讐を受けるでしょう」。そして主はカインを見付ける者が、だれも彼を打ち殺すことのないように、彼にしるしをつけられた。', es:'Y le respondió Jehová: Ciertamente cualquiera que matare a Caín, siete veces será castigado. Entonces Jehová puso señal en Caín, para que no lo hiriese cualquiera que le hallara.' },
        { v:16, ko:'가인이 여호와의 앞을 떠나서 에덴 동편 놋 땅에 거하였더니', en:'And Cain went out from the presence of the LORD, and dwelt in the land of Nod, on the east of Eden.', zh:'于是该隐离开耶和华的面，去住在伊甸东边挪得之地。', ru:'И пошёл Каин от лица Господня и поселился в земле Нод, на восток от Едема.', ja:'カインは主の前を去って、エデンの東、ノドの地に住んだ。', es:'Salió, pues, Caín de delante de Jehová, y habitó en tierra de Nod, al oriente de Edén.' },
        { v:17, ko:'가인이 그 아내와 동침하매 그가 잉태하여 에녹을 낳은지라 가인이 성을 쌓고 그의 아들의 이름으로 성을 이름하여 에녹이라 하니라', en:'And Cain knew his wife; and she conceived, and bare Enoch: and he builded a city, and called the name of the city, after the name of his son, Enoch.', zh:'该隐与妻子同房，他妻子就怀孕，生了以诺。该隐建造了一座城，就按着他儿子的名将那城叫做以诺。', ru:'И познал Каин жену свою; и она зачала и родила Еноха. И построил он город; и назвал город по имени сына своего: Енох.', ja:'カインはその妻を知った。彼女はみごもり、エノクを産んだ。カインは町を建て、その町の名をその子の名にしたがって、エノクと名づけた。', es:'Y conoció Caín a su mujer, la cual concibió y dio a luz a Enoc; y edificó una ciudad, y llamó el nombre de la ciudad del nombre de su hijo, Enoc.' },
        { v:18, ko:'에녹이 이랏을 낳고 이랏은 므후야엘을 낳고 므후야엘은 므드사엘을 낳고 므드사엘은 라멕을 낳았더라', en:'And unto Enoch was born Irad: and Irad begat Mehujael: and Mehujael begat Methusael: and Methusael begat Lamech.', zh:'以诺生以拿；以拿生米户雅利；米户雅利生玛土撒利；玛土撒利生拉麦。', ru:'У Еноха родился Ирад; Ирад родил Мехиаеля; Мехиаель родил Мафусала; Мафусал родил Ламеха.', ja:'エノクにはイラデが生れた。イラデはメホヤエルの父となり、メホヤエルはメトシヤエルの父となり、メトシヤエルはレメクの父となった。', es:'Y a Enoc le nació Irad, e Irad engendró a Mehujael, y Mehujael engendró a Metusael, y Metusael engendró a Lamec.' },
        { v:19, ko:'라멕이 두 아내를 취하였으니 하나의 이름은 아다요 하나의 이름은 씰라이었더라', en:'And Lamech took unto him two wives: the name of the one was Adah, and the name of the other Zillah.', zh:'拉麦娶了两个妻：一个名叫亚大，一个名叫洗拉。', ru:'И взял себе Ламех две жены: имя одной: Ада, и имя второй: Цилла.', ja:'レメクはふたりの妻をめとった。ひとりの名はアダといい、ひとりの名はチラといった。', es:'Y Lamec tomó para sí dos mujeres; el nombre de la una fue Ada, y el nombre de la otra, Zila.' },
        { v:20, ko:'아다는 야발을 낳았으니 그는 장막에 거하며 육축 치는 자의 조상이 되었고', en:'And Adah bare Jabal: he was the father of such as dwell in tents, and of such as have cattle.', zh:'亚大生雅八；雅八就是住帐棚、牧养牲畜之人的祖师。', ru:'Ада родила Иавала: он был отец живущих в шатрах со стадами.', ja:'アダはヤバルを産んだ。彼は天幕に住んで、家畜を飼う者の先祖となった。', es:'Y Ada dio a luz a Jabal, el cual fue padre de los que habitan en tiendas y crían ganados.' },
        { v:21, ko:'그 아우의 이름은 유발이니 그는 수금과 퉁소를 잡는 모든 자의 조상이 되었으며', en:'And his brother\'s name was Jubal: he was the father of all such as handle the harp and organ.', zh:'雅八的兄弟名叫犹八；他是一切弹琴吹箫之人的祖师。', ru:'Имя брату его Иувал: он был отец всех играющих на гуслях и свирели.', ja:'その弟の名はユバルといった。彼は琴や笛を巧みに奏する者すべての先祖となった。', es:'Y el nombre de su hermano fue Jubal, el cual fue padre de todos los que tocan arpa y órgano.' },
        { v:22, ko:'씰라도 두발가인을 낳았으니 그는 동과 철의 여러 가지 날카로운 기구를 만드는 자요 두발가인의 누이는 나아마이었더라', en:'And Zillah, she also bare Tubalcain, an instructer of every artificer in brass and iron: and the sister of Tubalcain was Naamah.', zh:'洗拉又生了土八·该隐；他是打造各样铜铁利器的。土八·该隐的妹子是拿玛。', ru:'Цилла также родила Тувалкаина, который был ковачём всех орудий из меди и железа. И сестра Тувалкаина Ноема.', ja:'チラもまたトバルカインを産んだ。彼は青銅や鉄のすべての刃物を鍛える者となった。トバルカインの妹はナアマといった。', es:'Y Zila también dio a luz a Tubal-caín, artífice de toda obra de metal y de hierro; y la hermana de Tubal-caín fue Naama.' },
        { v:23, ko:'라멕이 아내들에게 이르되 아다와 씰라여 내 말을 들으라 라멕의 아내들이여 내 말에 귀를 기울이라 나의 상처를 인하여 내가 사람을 죽였고 나의 상함을 인하여 소년을 죽였도다', en:'And Lamech said unto his wives, Adah and Zillah, Hear my voice; ye wives of Lamech, hearken unto my speech: for I have slain a man to my wounding, and a young man to my hurt.', zh:'拉麦对他两个妻子说：亚大、洗拉，听我的声音；拉麦的妻子，细听我的话语：壮年人伤我，我把他杀了；少年人损我，我把他害了。', ru:'И сказал Ламех жёнам своим: Ада и Цилла! послушайте голоса моего; жёны Ламеховы! внимайте словам моим: я убил мужа в язву мне и отрока в рану мне;', ja:'レメクはその妻たちに言った、「アダとチラよ、わたしの声を聞け、レメクの妻たちよ、わたしの言葉に耳を傾けよ。わたしは受ける傷のために、人を殺し、受ける打ち傷のために、わたしは若者を殺す。', es:'Y dijo Lamec a sus mujeres: Ada y Zila, oíd mi voz; mujeres de Lamec, escuchad mi dicho: Que varón mataré por mi herida, y mancebo por mi golpe.' },
        { v:24, ko:'가인을 위하여는 벌이 칠 배일진대 라멕을 위하여는 칠십칠 배이리로다 하였더라', en:'If Cain shall be avenged sevenfold, truly Lamech seventy and sevenfold.', zh:'若杀该隐，遭报七倍，杀拉麦，必遭报七十七倍。', ru:'если за Каина отмстится всемеро, то за Ламеха в семьдесят раз всемеро.', ja:'カインのための復讐が七倍ならば、レメクのための復讐は七十七倍」。', es:'Si siete veces será vengado Caín, Lamec en verdad setenta veces siete lo será.' },
        { v:25, ko:'아담이 다시 그 아내와 동침하매 그가 아들을 낳아 그 이름을 셋이라 하였으니 이는 하나님이 내게 가인의 죽인 아벨 대신에 다른 씨를 주셨다 함이며', en:'And Adam knew his wife again; and she bare a son, and called his name Seth: For God, said she, hath appointed me another seed instead of Abel, whom Cain slew.', zh:'亚当又与妻子同房，她就生了一个儿子，起名叫塞特，意思说：「神另给我立了一个儿子代替亚伯，因为该隐杀了他。」', ru:'И познал Адам ещё жену свою, и она родила сына, и нарекла ему имя: Сиф, потому что, говорила она, Бог положил мне другое семя, вместо Авеля, которого убил Каин.', ja:'アダムはまたその妻を知った。彼女は男の子を産み、その名をセツと名づけて言った、「カインがアベルを殺したので、神はアベルの代りに、ひとりの子をわたしに授けられました」。', es:'Y conoció de nuevo Adán a su mujer, la cual dio a luz un hijo, y llamó su nombre Set: Porque Dios (dijo ella) me ha sustituido otro hijo en lugar de Abel, a quien mató Caín.' },
        { v:26, ko:'셋도 아들을 낳고 그 이름을 에노스라 하였으며 그때에 사람들이 비로소 여호와의 이름을 불렀더라', en:'And to Seth, to him also there was born a son; and he called his name Enos: then began men to call upon the name of the LORD.', zh:'塞特也生了一个儿子，起名叫以挪士。那时候，人才求告耶和华的名。', ru:'У Сифа также родился сын, и он нарёк ему имя: Енос; тогда начали призывать имя Господа.', ja:'セツにもまた男の子が生れた。彼はその名をエノスと名づけた。この時、人々は主の名を呼び始めた。', es:'Y a Set también le nació un hijo, y llamó su nombre Enós. Entonces los hombres comenzaron a invocar el nombre de Jehová.' }
      ],
      5: [
        { v:1,  ko:'이것은 아담의 세계의 글이라 하나님이 사람을 창조하실 때에 하나님의 모양대로 지으시되', en:'This is the book of the generations of Adam. In the day that God created man, in the likeness of God made he him;', zh:'亚当的后代记在下面。当神造人的日子，是照着神的样式造的，', ru:'Вот родословие Адама: когда Бог сотворил человека, по подобию Божию создал его,', ja:'これはアダムの系図の書である。神は人を創造された時、神にかたどって造り、', es:'Este es el libro de las generaciones de Adán. El día en que creó Dios al hombre, a semejanza de Dios lo hizo.' },
        { v:2,  ko:'남자와 여자를 창조하시고 그들이 창조되던 날에 복을 주시고 그 이름을 사람이라 일컬으셨더라', en:'Male and female created he them; and blessed them, and called their name Adam, in the day when they were created.', zh:'并且造男造女。在他们被造的日子，神赐福给他们，称他们为「人」。', ru:'мужчину и женщину сотворил их, и благословил их, и нарёк им имя: человек, в день сотворения их.', ja:'男と女とに創造された。彼らが創造された時、彼らを祝福して、その名をアダムと名づけられた。', es:'Varón y hembra los creó; y los bendijo, y llamó el nombre de ellos Adán, el día en que fueron creados.' },
        { v:3,  ko:'아담이 일백삼십 세에 자기 모양 곧 자기 형상과 같은 아들을 낳아 이름을 셋이라 하였고', en:'And Adam lived an hundred and thirty years, and begat a son in his own likeness, after his image; and called his name Seth:', zh:'亚当活到一百三十岁，生了一个儿子，形像样式和自己相似，就给他起名叫塞特。', ru:'Адам жил сто тридцать лет и родил сына по подобию своему, по образу своему, и нарёк ему имя: Сиф.', ja:'アダムは百三十歳になって、自分にかたどり、自分のかたちのような男の子を生み、その名をセツと名づけた。', es:'Y vivió Adán ciento treinta años, y engendró un hijo a su semejanza, conforme a su imagen, y llamó su nombre Set.' },
        { v:4,  ko:'아담이 셋을 낳은 후 팔백 년을 지내며 자녀를 낳았으며', en:'And the days of Adam after he had begotten Seth were eight hundred years: and he begat sons and daughters:', zh:'亚当生塞特之后，又活了八百年，并且生儿养女。', ru:'Дней Адама по рождении им Сифа было восемьсот лет, и родил он сынов и дочерей.', ja:'アダムがセツを生んで後、生きた年は八百年であって、ほかに男子と女子を生んだ。', es:'Y fueron los días de Adán después de haber engendrado a Set, ochocientos años, y engendró hijos e hijas.' },
        { v:5,  ko:'아담의 산 햇수가 구백삼십 세이었고 그가 죽었더라', en:'And all the days that Adam lived were nine hundred and thirty years: and he died.', zh:'亚当共活了九百三十岁就死了。', ru:'Всех же дней жизни Адамовой было девятьсот тридцать лет; и он умер.', ja:'アダムの生きた年は合わせて九百三十歳であった。そして彼は死んだ。', es:'Y fueron todos los días que vivió Adán novecientos treinta años; y murió.' },
        { v:6,  ko:'셋이 일백오 세에 에노스를 낳았고', en:'And Seth lived an hundred and five years, and begat Enos:', zh:'塞特活到一百零五岁，生了以挪士。', ru:'Сиф жил сто пять лет и родил Еноса.', ja:'セツは百五歳になって、エノスを生んだ。', es:'Vivió Set ciento cinco años, y engendró a Enós.' },
        { v:7,  ko:'셋이 에노스를 낳은 후 팔백칠 년을 지내며 자녀를 낳았으며', en:'And Seth lived after he begat Enos eight hundred and seven years, and begat sons and daughters:', zh:'塞特生以挪士之后，又活了八百零七年，并且生儿养女。', ru:'По рождении Еноса Сиф жил восемьсот семь лет и родил сынов и дочерей.', ja:'セツはエノスを生んだ後、八百七年生きて、男子と女子を生んだ。', es:'Y vivió Set, después de haber engendrado a Enós, ochocientos siete años, y engendró hijos e hijas.' },
        { v:8,  ko:'셋의 산 햇수가 구백십이 세이었고 그가 죽었더라', en:'And all the days of Seth were nine hundred and twelve years: and he died.', zh:'塞特共活了九百一十二岁就死了。', ru:'Всех же дней Сифовых было девятьсот двенадцать лет; и он умер.', ja:'セツの年は合わせて九百十二歳であった。そして彼は死んだ。', es:'Y fueron todos los días de Set novecientos doce años; y murió.' },
        { v:9,  ko:'에노스가 구십 세에 게난을 낳았고', en:'And Enos lived ninety years, and begat Cainan:', zh:'以挪士活到九十岁，生了该南。', ru:'Енос жил девяносто лет и родил Каинана.', ja:'エノスは九十歳になって、カイナンを生んだ。', es:'Vivió Enós noventa años, y engendró a Cainán.' },
        { v:10, ko:'에노스가 게난을 낳은 후 팔백십오 년을 지내며 자녀를 낳았으며', en:'And Enos lived after he begat Cainan eight hundred and fifteen years, and begat sons and daughters:', zh:'以挪士生该南之后，又活了八百一十五年，并且生儿养女。', ru:'По рождении Каинана Енос жил восемьсот пятнадцать лет и родил сынов и дочерей.', ja:'エノスはカイナンを生んだ後、八百十五年生きて、男子と女子を生んだ。', es:'Y vivió Enós, después de haber engendrado a Cainán, ochocientos quince años, y engendró hijos e hijas.' },
        { v:11, ko:'에노스의 산 햇수가 구백오 세이었고 그가 죽었더라', en:'And all the days of Enos were nine hundred and five years: and he died.', zh:'以挪士共活了九百零五岁就死了。', ru:'Всех же дней Еноса было девятьсот пять лет; и он умер.', ja:'エノスの年は合わせて九百五歳であった。そして彼は死んだ。', es:'Y fueron todos los días de Enós novecientos cinco años; y murió.' },
        { v:12, ko:'게난이 칠십 세에 마할랄렐을 낳았고', en:'And Cainan lived seventy years, and begat Mahalaleel:', zh:'该南活到七十岁，生了玛勒列。', ru:'Каинан жил семьдесят лет и родил Малелеила.', ja:'カイナンは七十歳になって、マハラレルを生んだ。', es:'Vivió Cainán setenta años, y engendró a Mahalaleel.' },
        { v:13, ko:'게난이 마할랄렐을 낳은 후 팔백사십 년을 지내며 자녀를 낳았으며', en:'And Cainan lived after he begat Mahalaleel eight hundred and forty years, and begat sons and daughters:', zh:'该南生玛勒列之后，又活了八百四十年，并且生儿养女。', ru:'По рождении Малелеила Каинан жил восемьсот сорок лет и родил сынов и дочерей.', ja:'カイナンはマハラレルを生んだ後、八百四十年生きて、男子と女子を生んだ。', es:'Y vivió Cainán, después de haber engendrado a Mahalaleel, ochocientos cuarenta años, y engendró hijos e hijas.' },
        { v:14, ko:'게난의 산 햇수가 구백십 세이었고 그가 죽었더라', en:'And all the days of Cainan were nine hundred and ten years: and he died.', zh:'该南共活了九百一十岁就死了。', ru:'Всех же дней Каинана было девятьсот десять лет; и он умер.', ja:'カイナンの年は合わせて九百十歳であった。そして彼は死んだ。', es:'Y fueron todos los días de Cainán novecientos diez años; y murió.' },
        { v:15, ko:'마할랄렐이 육십오 세에 야렛을 낳았고', en:'And Mahalaleel lived sixty and five years, and begat Jared:', zh:'玛勒列活到六十五岁，生了雅列。', ru:'Малелеил жил шестьдесят пять лет и родил Иареда.', ja:'マハラレルは六十五歳になって、ヤレドを生んだ。', es:'Vivió Mahalaleel sesenta y cinco años, y engendró a Jared.' },
        { v:16, ko:'마할랄렐이 야렛을 낳은 후 팔백삼십 년을 지내며 자녀를 낳았으며', en:'And Mahalaleel lived after he begat Jared eight hundred and thirty years, and begat sons and daughters:', zh:'玛勒列生雅列之后，又活了八百三十年，并且生儿养女。', ru:'По рождении Иареда Малелеил жил восемьсот тридцать лет и родил сынов и дочерей.', ja:'マハラレルはヤレドを生んだ後、八百三十年生きて、男子と女子を生んだ。', es:'Y vivió Mahalaleel, después de haber engendrado a Jared, ochocientos treinta años, y engendró hijos e hijas.' },
        { v:17, ko:'마할랄렐의 산 햇수가 팔백구십오 세이었고 그가 죽었더라', en:'And all the days of Mahalaleel were eight hundred ninety and five years: and he died.', zh:'玛勒列共活了八百九十五岁就死了。', ru:'Всех же дней Малелеила было восемьсот девяносто пять лет; и он умер.', ja:'マハラレルの年は合わせて八百九十五歳であった。そして彼は死んだ。', es:'Y fueron todos los días de Mahalaleel ochocientos noventa y cinco años; y murió.' },
        { v:18, ko:'야렛이 일백육십이 세에 에녹을 낳았고', en:'And Jared lived an hundred sixty and two years, and he begat Enoch:', zh:'雅列活到一百六十二岁，生了以诺。', ru:'Иаред жил сто шестьдесят два года и родил Еноха.', ja:'ヤレドは百六十二歳になって、エノクを生んだ。', es:'Vivió Jared ciento sesenta y dos años, y engendró a Enoc.' },
        { v:19, ko:'야렛이 에녹을 낳은 후 팔백 년을 지내며 자녀를 낳았으며', en:'And Jared lived after he begat Enoch eight hundred years, and begat sons and daughters:', zh:'雅列生以诺之后，又活了八百年，并且生儿养女。', ru:'По рождении Еноха Иаред жил восемьсот лет и родил сынов и дочерей.', ja:'ヤレドはエノクを生んだ後、八百年生きて、男子と女子を生んだ。', es:'Y vivió Jared, después de haber engendrado a Enoc, ochocientos años, y engendró hijos e hijas.' },
        { v:20, ko:'야렛의 산 햇수가 구백육십이 세이었고 그가 죽었더라', en:'And all the days of Jared were nine hundred sixty and two years: and he died.', zh:'雅列共活了九百六十二岁就死了。', ru:'Всех же дней Иареда было девятьсот шестьдесят два года; и он умер.', ja:'ヤレドの年は合わせて九百六十二歳であった。そして彼は死んだ。', es:'Y fueron todos los días de Jared novecientos sesenta y dos años; y murió.' },
        { v:21, ko:'에녹이 육십오 세에 므두셀라를 낳았고', en:'And Enoch lived sixty and five years, and begat Methuselah:', zh:'以诺活到六十五岁，生了玛土撒拉。', ru:'Енох жил шестьдесят пять лет и родил Мафусала.', ja:'エノクは六十五歳になって、メトセラを生んだ。', es:'Vivió Enoc sesenta y cinco años, y engendró a Matusalén.' },
        { v:22, ko:'에녹이 므두셀라를 낳은 후 삼백 년을 하나님과 동행하며 자녀를 낳았으며', en:'And Enoch walked with God after he begat Methuselah three hundred years, and begat sons and daughters:', zh:'以诺生玛土撒拉之后，与神同行三百年，并且生儿养女。', ru:'И ходил Енох пред Богом, по рождении Мафусала, триста лет и родил сынов и дочерей.', ja:'エノクはメトセラを生んだ後、三百年、神と共に歩み、男子と女子を生んだ。', es:'Y caminó Enoc con Dios, después que engendró a Matusalén, trescientos años, y engendró hijos e hijas.' },
        { v:23, ko:'에녹의 산 햇수가 삼백육십오 세이었더라', en:'And all the days of Enoch were three hundred sixty and five years:', zh:'以诺共活了三百六十五岁。', ru:'Всех же дней Еноха было триста шестьдесят пять лет.', ja:'エノクの年は合わせて三百六十五歳であった。', es:'Y fueron todos los días de Enoc trescientos sesenta y cinco años.' },
        { v:24, ko:'에녹이 하나님과 동행하더니 하나님이 그를 데려가시므로 세상에 있지 아니하였더라', en:'And Enoch walked with God: and he was not; for God took him.', zh:'以诺与神同行，神将他取去，他就不在世了。', ru:'И ходил Енох пред Богом; и не стало его, потому что Бог взял его.', ja:'エノクは神と共に歩み、神が彼を取られたので、いなくなった。', es:'Caminó, pues, Enoc con Dios, y desapareció, porque le llevó Dios.' },
        { v:25, ko:'므두셀라가 일백팔십칠 세에 라멕을 낳았고', en:'And Methuselah lived an hundred eighty and seven years, and begat Lamech:', zh:'玛土撒拉活到一百八十七岁，生了拉麦。', ru:'Мафусал жил сто восемьдесят семь лет и родил Ламеха.', ja:'メトセラは百八十七歳になって、レメクを生んだ。', es:'Vivió Matusalén ciento ochenta y siete años, y engendró a Lamec.' },
        { v:26, ko:'므두셀라가 라멕을 낳은 후 칠백팔십이 년을 지내며 자녀를 낳았으며', en:'And Methuselah lived after he begat Lamech seven hundred eighty and two years, and begat sons and daughters:', zh:'玛土撒拉生拉麦之后，又活了七百八十二年，并且生儿养女。', ru:'По рождении Ламеха Мафусал жил семьсот восемьдесят два года и родил сынов и дочерей.', ja:'メトセラはレメクを生んだ後、七百八十二年生きて、男子と女子を生んだ。', es:'Y vivió Matusalén, después de haber engendrado a Lamec, setecientos ochenta y dos años, y engendró hijos e hijas.' },
        { v:27, ko:'므두셀라의 산 햇수가 구백육십구 세이었고 그가 죽었더라', en:'And all the days of Methuselah were nine hundred sixty and nine years: and he died.', zh:'玛土撒拉共活了九百六十九岁就死了。', ru:'Всех же дней Мафусала было девятьсот шестьдесят девять лет; и он умер.', ja:'メトセラの年は合わせて九百六十九歳であった。そして彼は死んだ。', es:'Fueron, pues, todos los días de Matusalén novecientos sesenta y nueve años; y murió.' },
        { v:28, ko:'라멕이 일백팔십이 세에 아들을 낳고', en:'And Lamech lived an hundred eighty and two years, and begat a son:', zh:'拉麦活到一百八十二岁，生了一个儿子，', ru:'Ламех жил сто восемьдесят два года и родил сына,', ja:'レメクは百八十二歳になって、ひとりの男の子を生み、', es:'Vivió Lamec ciento ochenta y dos años, y engendró un hijo.' },
        { v:29, ko:'이름을 노아라 하여 가로되 여호와께서 땅을 저주하시므로 수고로이 일하는 우리를 이 아들이 안위하리라 하였더라', en:'And he called his name Noah, saying, This same shall comfort us concerning our work and toil of our hands, because of the ground which the LORD hath cursed.', zh:'给他起名叫挪亚，说：「这个儿子必为我们的操作和手中的劳苦安慰我们；这操作劳苦是因为耶和华咒诅地。」', ru:'и нарёк ему имя: Ной, сказав: он утешит нас в работе нашей и в трудах рук наших при возделывании земли, которую проклял Господь.', ja:'「この子こそ、主がのろわれた地についてのわたしたちの働きと手の労苦を慰めるもの」と言って、その名をノアと名づけた。', es:'Y llamó su nombre Noé, diciendo: Este nos aliviará de nuestras obras y del trabajo de nuestras manos, a causa de la tierra que Jehová maldijo.' },
        { v:30, ko:'라멕이 노아를 낳은 후 오백구십오 년을 지내며 자녀를 낳았으며', en:'And Lamech lived after he begat Noah five hundred ninety and five years, and begat sons and daughters:', zh:'拉麦生挪亚之后，又活了五百九十五年，并且生儿养女。', ru:'И жил Ламех по рождении Ноя пятьсот девяносто пять лет и родил сынов и дочерей.', ja:'レメクはノアを生んだ後、五百九十五年生きて、男子と女子を生んだ。', es:'Y vivió Lamec, después de haber engendrado a Noé, quinientos noventa y cinco años, y engendró hijos e hijas.' },
        { v:31, ko:'라멕의 산 햇수가 칠백칠십칠 세이었고 그가 죽었더라', en:'And all the days of Lamech were seven hundred seventy and seven years: and he died.', zh:'拉麦共活了七百七十七岁就死了。', ru:'Всех же дней Ламеха было семьсот семьдесят семь лет; и он умер.', ja:'レメクの年は合わせて七百七十七歳であった。そして彼は死んだ。', es:'Y fueron todos los días de Lamec setecientos setenta y siete años; y murió.' },
        { v:32, ko:'노아가 오백 세 된 후에 셈과 함과 야벳을 낳았더라', en:'And Noah was five hundred years old: and Noah begat Shem, Ham, and Japheth.', zh:'挪亚五百岁生了闪、含、雅弗。', ru:'Ною было пятьсот лет и родил Ной Сима, Хама и Иафета.', ja:'ノアは五百歳になって、セム、ハム、ヤペテを生んだ。', es:'Y siendo Noé de quinientos años, engendró a Sem, a Cam y a Jafet.' }
      ],
      6: [
        { v:1,  ko:'사람이 땅 위에 번성하기 시작할 때에 그들에게서 딸들이 나니', en:'And it came to pass, when men began to multiply on the face of the earth, and daughters were born unto them,', zh:'当人在世上多起来，又生女儿的时候，', ru:'Когда люди начали умножаться на земле и родились у них дочери,', ja:'人が地の面に増え始め、彼らに娘たちが生まれた時、', es:'Aconteció que cuando comenzaron los hombres a multiplicarse sobre la faz de la tierra, y les nacieron hijas,' },
        { v:2,  ko:'하나님의 아들들이 사람의 딸들의 아름다움을 보고 자기들의 좋아하는 모든 자로 아내를 삼는지라', en:'That the sons of God saw the daughters of men that they were fair; and they took them wives of all which they chose.', zh:'神的儿子们看见人的女儿美貌，就随意挑选，娶来为妻。', ru:'тогда сыны Божии увидели дочерей человеческих, что они красивы, и брали их себе в жёны, какую кто избрал.', ja:'神の子たちは人の娘たちの美しいのを見て、自分の好む者をみな妻にした。', es:'que viendo los hijos de Dios que las hijas de los hombres eran hermosas, tomaron para sí mujeres, escogiendo entre todas.' },
        { v:3,  ko:'여호와께서 가라사대 나의 신이 영원히 사람과 함께 하지 아니하리니 이는 그들이 육체가 됨이라 그러나 그들의 날은 일백이십 년이 되리라 하시니라', en:'And the LORD said, My spirit shall not always strive with man, for that he also is flesh: yet his days shall be an hundred and twenty years.', zh:'耶和华说：「人既属乎血气，我的灵就不永远住在他里面；然而他的日子还可到一百二十年。」', ru:'И сказал Господь: не вечно Духу Моему быть пренебрегаемым человеками, потому что они плоть; пусть будут дни их сто двадцать лет.', ja:'そして主は言われた、「わたしの霊は永久に人の中にとどまらない。彼らは肉にすぎないのだから」。そこで彼らの齢は百二十年となった。', es:'Y dijo Jehová: No contenderá mi espíritu con el hombre para siempre, porque ciertamente él es carne; mas serán sus días ciento veinte años.' },
        { v:4,  ko:'당시에 땅에 네피림이 있었고 그 후에도 하나님의 아들들이 사람의 딸들을 취하여 자식을 낳았으니 그들이 용사라 고대에 유명한 사람이었더라', en:'There were giants in the earth in those days; and also after that, when the sons of God came in unto the daughters of men, and they bare children to them, the same became mighty men which were of old, men of renown.', zh:'那时候有伟人在地上，后来神的儿子们和人的女儿们交合生子，那就是上古英武有名的人。', ru:'В то время были на земле исполины, особенно же с того времени, как сыны Божии стали входить к дочерям человеческим, и они стали рождать им. Это сильные, издревле славные люди.', ja:'その時代には、地上にネフィリムがいた。その後も神の子たちが人の娘たちのところに入って、彼女たちが子を産むようになってからも同様であった。彼らは昔の勇士で、名高い人々であった。', es:'Había gigantes en la tierra en aquellos días, y también después, cuando se llegaron los hijos de Dios a las hijas de los hombres, y elles les parieron hijos: estos fueron los valientes que desde la antigüedad fueron varones de renombre.' },
        { v:5,  ko:'여호와께서 사람의 죄악이 세상에 관영함과 그 마음의 생각의 모든 계획이 항상 악할 뿐임을 보시고', en:'And GOD saw that the wickedness of man was great in the earth, and that every imagination of the thoughts of his heart was only evil continually.', zh:'耶和华见人在地上罪恶很大，终日所思想的尽都是恶，', ru:'И увидел Господь, что велико развращение человеков на земле, и что все мысли и помышления сердца их были зло во всякое время.', ja:'主は、地上に人の悪が増大し、その心に図ることがみな、いつも悪いことだけに傾いているのをご覧になった。', es:'Y vio Jehová que la maldad de los hombres era mucha en la tierra, y que todo designio de los pensamientos del corazón de ellos era de continuo solamente el mal.' },
        { v:6,  ko:'땅 위에 사람 지으셨음을 한탄하사 마음에 근심하시고', en:'And it repented the LORD that he had made man on the earth, and it grieved him at his heart.', zh:'耶和华就后悔造了人在地上，心中忧伤。', ru:'И раскаялся Господь, что создал человека на земле, и восскорбел в сердце Своём.', ja:'主は地上に人を造ったことを悔いて、心を痛められた。', es:'Y arrepintióse Jehová de haber hecho hombre en la tierra, y pesóle en su corazón.' },
        { v:7,  ko:'가라사대 나의 창조한 사람을 내가 지면에서 쓸어버리되 사람으로부터 육축과 기는 것과 공중의 새까지 그리하리니 이는 내가 그것을 지었음을 한탄함이니라 하시니라', en:'And the LORD said, I will destroy man whom I have created from the face of the earth; both man, and beast, and the creeping thing, and the fowls of the air; for it repenteth me that I have made them.', zh:'耶和华说：「我要将所造的人和走兽，并昆虫，以及空中的飞鸟，都从地上除灭，因为我造他们后悔了。」', ru:'И сказал Господь: истреблю с лица земли человеков, которых Я сотворил, от человека до скотов, и гадов и птиц небесных истреблю, ибо Я раскаялся, что создал их.', ja:'そして主は言われた、「わたしが創造した人を地のおもてからぬぐい去ろう。人も、家畜も、這うものも、空の鳥も。わたしが彼らを造ったことを悔いる」。', es:'Y dijo Jehová: Raeré los hombres que he creado de sobre la faz de la tierra, desde el hombre hasta la bestia, y hasta el reptil, y las aves del cielo; porque me arrepiento de haberlos hecho.' },
        { v:8,  ko:'그러나 노아는 여호와께 은혜를 입었더라', en:'But Noah found grace in the eyes of the LORD.', zh:'惟有挪亚在耶和华眼前蒙恩。', ru:'Ной же обрёл благодать пред очами Господа.', ja:'しかしノアは主の目に恵みを得た。', es:'Pero Noé halló gracia ante los ojos de Jehová.' },
        { v:9,  ko:'노아의 사적은 이러하니라 노아는 의인이요 당세에 완전한 자라 그가 하나님과 동행하였으며', en:'These are the generations of Noah: Noah was a just man and perfect in his generations, and Noah walked with God.', zh:'挪亚的后代记在下面。挪亚是个义人，在当时的世代是个完全人。挪亚与神同行。', ru:'Вот житие Ноя: Ной был человек праведный и непорочный в роде своём; Ной ходил пред Богом.', ja:'これはノアの歴史である。ノアは正しい人で、その時代の人々の中で全き人であった。ノアは神と共に歩んだ。', es:'Estas son las generaciones de Noé: Noé, varón justo, era perfecto en sus generaciones; con Dios caminó Noé.' },
        { v:10, ko:'세 아들을 낳았으니 셈과 함과 야벳이라', en:'And Noah begat three sons, Shem, Ham, and Japheth.', zh:'挪亚生了三个儿子，就是闪、含、雅弗。', ru:'Ной родил трёх сынов: Сима, Хама и Иафета.', ja:'ノアは三人の子をもうけた。セム、ハム、ヤペテである。', es:'Y Noé engendró tres hijos: a Sem, a Cam y a Jafet.' },
        { v:11, ko:'때에 온 땅이 하나님 앞에 부패하여 포악함이 땅에 가득한지라', en:'The earth also was corrupt before God, and the earth was filled with violence.', zh:'世界在神面前败坏，地上满了强暴。', ru:'Но земля растлилась пред лицем Божиим, и наполнилась земля злодеяниями.', ja:'地は神の前に腐敗し、地は暴虐で満ちていた。', es:'Y la tierra estaba corrompida delante de Dios, y estaba la tierra llena de violencia.' },
        { v:12, ko:'하나님이 보신즉 땅이 부패하였으니 이는 땅에서 모든 혈육 있는 자의 행위가 부패함이었더라', en:'And God looked upon the earth, and, behold, it was corrupt; for all flesh had corrupted his way upon the earth.', zh:'神观看世界，见是败坏了；凡有血气的人，在地上都败坏了行为。', ru:'И воззрел Бог на землю, и вот, она растленна, ибо всякая плоть извратила путь свой на земле.', ja:'神が地を見られると、それは腐敗していた。すべての肉なるものが地でその道を腐らせたのである。', es:'Y miró Dios la tierra, y he aquí que estaba corrompida; porque toda carne había corrompido su camino sobre la tierra.' },
        { v:13, ko:'하나님이 노아에게 이르시되 모든 혈육 있는 자의 강포가 땅에 가득하므로 그 끝날이 내 앞에 이르렀으니 내가 그들을 땅과 함께 멸하리라', en:'And God said unto Noah, The end of all flesh is come before me; for the earth is filled with violence through them; and, behold, I will destroy them with the earth.', zh:'神就对挪亚说：「凡有血气的人，他的尽头已经来到我面前；因为地上满了他们的强暴，我要把他们和地一并毁灭。', ru:'И сказал Бог Ною: конец всякой плоти пришёл пред лице Моё, ибо земля наполнилась от них злодеяниями; и вот, Я истреблю их с земли.', ja:'神はノアに言われた、「すべての肉なるものの終わりはわたしの前に来ている。彼らのゆえに地は暴虐で満ちている。わたしは彼らを地と共に滅ぼす。', es:'Dijo, pues, Dios a Noé: He decidido el fin de todo ser, porque la tierra está llena de violencia a causa de ellos; y he aquí que yo los destruiré con la tierra.' },
        { v:14, ko:'너는 잣나무로 너를 위하여 방주를 짓되 그 안에 간들을 막고 역청으로 그 안팎에 칠하라', en:'Make thee an ark of gopher wood; rooms shalt thou make in the ark, and shalt pitch it within and without with pitch.', zh:'你要用歌斐木造一只方舟，分一间一间的造，里外抹上松香。', ru:'Сделай себе ковчег из дерева гофер; отделения сделай в ковчеге и осмоли его смолою внутри и снаружи.', ja:'あなたはゴフェルの木で箱船を造りなさい。箱船の中に部屋を設け、内外にタールを塗りなさい。', es:'Hazte un arca de madera de gofer; harás aposentos en el arca, y la calafatearás con brea por dentro y por fuera.' },
        { v:15, ko:'그 방주의 제도는 이러하니 장이 삼백 규빗, 광이 오십 규빗, 고가 삼십 규빗이며', en:'And this is the fashion which thou shalt make it of: The length of the ark shall be three hundred cubits, the breadth of it fifty cubits, and the height of it thirty cubits.', zh:'方舟的造法乃是这样：要长三百肘，宽五十肘，高三十肘。', ru:'И вот как ты сделаешь его: длина ковчега триста локтей; ширина его пятьдесят локтей, а высота его тридцать локтей.', ja:'造る箱船の規模はこうである。長さ三百キュビト、幅五十キュビト、高さ三十キュビト。', es:'Y de esta manera la harás: de trescientos codos la longitud del arca, de cincuenta codos su anchura, y de treinta codos su altura.' },
        { v:16, ko:'거기 창을 내되 위에서부터 한 규빗에 내고 그 문은 옆으로 내고 상 중 하 삼층으로 할찌니라', en:'A window shalt thou make to the ark, and in a cubit shalt thou finish it above; and the door of the ark shalt thou set in the side thereof; with lower, second, and third stories shalt thou make it.', zh:'方舟上边要留透光处，高一肘。方舟的门要开在旁边。方舟要分上、中、下三层。', ru:'И сделай отверстие в ковчеге, и в локоть сведи его вверху, и дверь в ковчег сделай с боку его; устрой в нём нижнее, второе и третье жильё.', ja:'箱船に明かり取りを設け、上から一キュビトのところにそれを仕上げなさい。箱船のわきに戸口を設けなさい。下、中、上の三層に造りなさい。', es:'Una ventana harás al arca, y la acabarás a un codo de elevación por la parte de arriba; y pondrás la puerta del arca a su lado; y le harás piso bajo, segundo y tercero.' },
        { v:17, ko:'내가 홍수를 땅에 일으켜 무릇 생명의 기식 있는 육체를 천하에서 멸절하리니 땅에 있는 자가 다 죽으리라', en:'And, behold, I, even I, do bring a flood of waters upon the earth, to destroy all flesh, wherein is the breath of life, from under heaven; and every thing that is in the earth shall die.', zh:'我要使洪水泛滥在地上，毁灭天下；凡地上有血肉、有气息的活物，无一不死。', ru:'И вот, Я наведу на землю потоп водный, чтоб истребить всякую плоть, в которой есть дух жизни, под небесами; всё, что есть на земле, лишится жизни.', ja:'わたしは今、洪水を地にもたらし、命の息のある肉なるものをことごとく天の下から滅ぼす。地にあるものはすべて死に絶えるであろう。', es:'Y yo, he aquí que yo traigo un diluvio de aguas sobre la tierra, para destruir toda carne en que haya espíritu de vida debajo del cielo; todo lo que hay en la tierra morirá.' },
        { v:18, ko:'그러나 너와는 내가 내 언약을 세우리니 너는 네 아들들과 네 아내와 네 자부들과 함께 그 방주로 들어가고', en:'But with thee will I establish my covenant; and thou shalt come into the ark, thou, and thy sons, and thy wife, and thy sons wives with thee.', zh:'我却要与你立约；你同你的妻，与儿子儿妇，都要进入方舟。', ru:'Но с тобою Я поставлю завет Мой, и войдёшь в ковчег ты, и сыновья твои, и жена твоя, и жёны сынов твоих с тобою.', ja:'しかしわたしはあなたと契約を結ぶ。あなたは妻、息子たち、息子たちの妻たちと共に箱船に入りなさい。', es:'Mas estableceré mi pacto contigo, y entrarás en el arca tú, y tus hijos, y tu mujer, y las mujeres de tus hijos contigo.' },
        { v:19, ko:'혈육 있는 모든 생물을 너는 각기 암수 둘씩 방주로 이끌어들여 너와 함께 생명을 보존케 하되', en:'And of every living thing of all flesh, two of every sort shalt thou bring into the ark, to keep them alive with thee; they shall be male and female.', zh:'你要把各类活物，每样两个，连同公带母，带进方舟，好在你那里保全生命。', ru:'Введи также в ковчег из всех животных, и от всякой плоти по паре, чтоб они остались с тобою в живых; мужского пола и женского пусть они будут.', ja:'またすべての生き物、すべての肉なるものの中から二つずつ、雄と雌とを生かしておくために箱船に連れてきなさい。', es:'Y de todo lo que vive, de toda carne, dos de cada especie meterás en el arca, para que tengan vida contigo; macho y hembra serán.' },
        { v:20, ko:'새가 그 종류대로, 육축이 그 종류대로, 땅에 기는 모든 것이 그 종류대로 각기 둘씩 네게로 나아오리니 그 생명을 보존케 하라', en:'Of fowls after their kind, and of cattle after their kind, of every creeping thing of the earth after his kind, two of every sort shall come unto thee, to keep them alive.', zh:'飞鸟各从其类，牲畜各从其类，地上的昆虫各从其类，每样两个，要到你那里，好保全生命。', ru:'Из птиц по роду их, и из скотов по роду их, и из всех пресмыкающихся по земле по роду их, из всех по паре войдут к тебе, чтобы остались в живых.', ja:'鳥はその種類にしたがって、家畜はその種類にしたがって、地を這うすべてのものはその種類にしたがって、それぞれ二つずつあなたのところに来て、生かしておけるようにしなさい。', es:'De las aves según su especie, y de las bestias según su especie, de todo reptil de la tierra según su especie, dos de cada especie entrarán contigo, para que tengan vida.' },
        { v:21, ko:'너는 먹을 모든 식물을 취하여 저축하라 이것이 너와 그들의 식물이 되리라', en:'And take thou unto thee of all food that is eaten, and thou shalt gather it to thee; and it shall be for food for thee, and for them.', zh:'你要拿各样食物积蓄起来，好作你和它们的食物。」', ru:'Ты же возьми себе всякой пищи, какою питаются, и собери к себе; и будет она для тебя и для них пищею.', ja:'また食べ物となるものをすべて取って、自分のために蓄えておきなさい。それがあなたと彼らの食物となるであろう。', es:'Y toma contigo de toda comida que se come, y allégala a ti; y será para ti y para ellos de sustento.' },
        { v:22, ko:'노아가 그와 같이 하되 하나님이 자기에게 명하신 대로 다 준행하였더라', en:'Thus did Noah; according to all that God commanded him, so did he.', zh:'挪亚就这样行。凡神所吩咐的，他都照样行了。', ru:'И сделал Ной всё: как повелел ему Бог, так он и сделал.', ja:'ノアはそのようにした。すなわち神が命じられたとおりに彼はした。', es:'Y lo hizo así Noé; hizo conforme a todo lo que Dios le mandó.' }
      ],
      7: [
        { v:1,  ko:'여호와께서 노아에게 이르시되 너와 네 온 집이 방주로 들어가라 이 세대에서 네가 내 앞에 의로움을 내가 보았음이니라', en:'And the LORD said unto Noah, Come thou and all thy house into the ark; for thee have I seen righteous before me in this generation.', zh:'耶和华对挪亚说：「你和你的全家都要进入方舟；因为在这世代中，我见你在我面前是义人。', ru:'И сказал Господь Ною: войди ты и всё семейство твоё в ковчег, ибо тебя увидел Я праведным предо Мною в роде сём.', ja:'主はノアに言われた、「あなたと、あなたの全家族で箱船に入りなさい。この時代の人々の中であなただけがわたしの前に正しい人であるのをわたしは見たからです。', es:'Dijo luego Jehová a Noé: Entra tú y toda tu casa en el arca; porque a ti he visto justo delante de mí en esta generación.' },
        { v:2,  ko:'너는 모든 정결한 짐승은 암수 일곱씩, 부정한 것은 암수 둘씩을 네게로 취하며', en:'Of every clean beast thou shalt take to thee by sevens, the male and his female: and of beasts that are not clean by two, the male and his female.', zh:'凡洁净的畜类，你要带七公七母；不洁净的畜类，你要带一公一母；', ru:'и возьми с собою из всех животных чистых по семи, мужского пола и женского, а из животных нечистых по два, мужского пола и женского;', ja:'すべての清い動物の中からは雄と雌の七つがい、清くない動物は雄と雌の二つがいずつを取り、', es:'De todo animal limpio toma contigo siete parejas, macho y su hembra; mas de los animales que no son limpios, una pareja, el macho y su hembra.' },
        { v:3,  ko:'공중의 새도 암수 일곱씩을 취하되 그 씨를 온 지면에 유전케 하라', en:'Of fowls also of the air by sevens, the male and the female; to keep seed alive upon the face of all the earth.', zh:'空中的飞鸟也要带七公七母，可以留种，活在全地上。', ru:'также из птиц небесных по семи, мужского пола и женского, чтобы сохранить племя для всей земли,', ja:'また空の鳥も雄と雌の七つがいずつを取って、全地の上に種族を存続させなさい。', es:'También de las aves de los cielos, siete parejas, macho y hembra, para conservar viva la cría sobre la faz de toda la tierra.' },
        { v:4,  ko:'지금부터 칠 일이면 내가 사십 주야를 땅에 비를 내려 나의 지은 모든 생물을 지면에서 쓸어버리리라', en:'For yet seven days, and I will cause it to rain upon the earth forty days and forty nights; and every living substance that I have made will I destroy from off the face of the earth.', zh:'因为再过七天，我要降雨在地上四十昼夜，把我所造的各种活物都从地面上除灭。」', ru:'ибо чрез семь дней Я буду изливать дождь на землю сорок дней и сорок ночей; и истреблю все существующее, что Я создал, с лица земли.', ja:'今から七日後に、わたしは四十日四十夜、地の上に雨を降らせ、わたしが造ったすべての生き物を地のおもてからぬぐい去るであろう。', es:'Porque pasados aún siete días, yo haré llover sobre la tierra cuarenta días y cuarenta noches; y raeré de sobre la faz de la tierra a todo ser viviente que hice.' },
        { v:5,  ko:'노아가 여호와께서 자기에게 명하신 대로 다 준행하였더라', en:'And Noah did according unto all that the LORD commanded him.', zh:'挪亚就遵着耶和华所吩咐的行了。', ru:'Ной сделал всё, что Господь повелел ему.', ja:'ノアは主が命じられたとおりに、すべてのことをした。', es:'E hizo Noé conforme a todo lo que le mandó Jehová.' },
        { v:6,  ko:'홍수가 땅에 있을 때에 노아가 육백 세라', en:'And Noah was six hundred years old when the flood of waters was upon the earth.', zh:'当洪水泛滥在地上的时候，挪亚整六百岁。', ru:'Ной же был шестисот лет, как потоп водный пришёл на землю.', ja:'洪水が地の上に起こった時、ノアは六百歳であった。', es:'Era Noé de seiscientos años cuando el diluvio de las aguas vino sobre la tierra.' },
        { v:7,  ko:'노아와 그의 아들들과 그의 아내와 그 자부들이 홍수를 피하여 방주에 들어갔고', en:'And Noah went in, and his sons, and his wife, and his sons wives with him, into the ark, because of the waters of the flood.', zh:'挪亚就同他的妻和儿子儿妇都进入方舟，躲避洪水。', ru:'И вошёл Ной и сыновья его, и жена его, и жёны сынов его с ним в ковчег от вод потопа.', ja:'ノアは息子たち、妻、息子たちの妻と共に、洪水を避けて箱船に入った。', es:'Y entró Noé, y sus hijos, y su mujer, y las mujeres de sus hijos con él en el arca, por las aguas del diluvio.' },
        { v:8,  ko:'정결한 짐승과 부정한 짐승과 새와 땅에 기는 모든 것은', en:'Of clean beasts, and of beasts that are not clean, and of fowls, and of every thing that creepeth upon the earth,', zh:'洁净的畜类和不洁净的畜类，飞鸟并地上一切的昆虫，', ru:'И из скотов чистых и из скотов нечистых, и из птиц, и из всего пресмыкающегося по земле', ja:'清い動物と清くない動物、鳥と地に這うすべてのものとは、', es:'De los animales limpios, y de los animales que no eran limpios, y de las aves, y de todo lo que anda arrastrándose sobre la tierra,' },
        { v:9,  ko:'하나님이 노아에게 명하신 대로 암수 둘씩 노아에게 나아와 방주로 들어갔더라', en:'There went in two and two unto Noah into the ark, the male and the female, as God had commanded Noah.', zh:'都是一公一母，到挪亚那里进入方舟，正如神所吩咐挪亚的。', ru:'по паре вошли к Ною в ковчег, мужского и женского пола, как Бог повелел Ною.', ja:'神がノアに命じられたとおりに、雄と雌の二つがいずつノアのところに来て箱船に入った。', es:'de dos en dos entraron a Noé en el arca, el macho y la hembra, como mandó Dios a Noé.' },
        { v:10, ko:'칠 일 후에 홍수가 땅에 덮이니', en:'And it came to pass after seven days, that the waters of the flood were upon the earth.', zh:'过了那七天，洪水泛滥在地上。', ru:'Чрез семь дней воды потопа пришли на землю.', ja:'七日後に洪水の水が地の上に起こった。', es:'Y sucedió que al cabo de los siete días, las aguas del diluvio vinieron sobre la tierra.' },
        { v:11, ko:'노아 육백 세 되던 해 이월 곧 그 달 십칠일이라 그 날에 큰 깊음의 샘들이 터지며 하늘의 창들이 열려', en:'In the six hundredth year of Noah\'s life, in the second month, the seventeenth day of the month, the same day were all the fountains of the great deep broken up, and the windows of heaven were opened.', zh:'挪亚六百岁，二月十七日那一天，大渊的泉源都裂开了，天上的窗户也敞开了。', ru:'В шестисотый год жизни Ноевой, во второй месяц, в семнадцатый день месяца, в сей день разверзлись все источники великой бездны, и окна небесные отворились.', ja:'ノアが六百歳になったその年の第二の月の十七日に、大いなる淵の源がみな破れ、天の窓が開いた。', es:'En el año seiscientos de la vida de Noé, en el mes segundo, a los diecisiete días del mes, aquel día fueron rotas todas las fuentes del grande abismo, y las cataratas de los cielos fueron abiertas.' },
        { v:12, ko:'사십 주야를 비가 땅에 쏟아졌더라', en:'And the rain was upon the earth forty days and forty nights.', zh:'四十昼夜降雨在地上。', ru:'И лился на землю дождь сорок дней и сорок ночей.', ja:'そして四十日四十夜、地の上に雨が降った。', es:'Y hubo lluvia sobre la tierra cuarenta días y cuarenta noches.' },
        { v:13, ko:'곧 그 날에 노아와 그의 아들 셈, 함, 야벳과 노아의 아내와 세 자부가 다 방주로 들어갔고', en:'In the selfsame day entered Noah, and Shem, and Ham, and Japheth, the sons of Noah, and Noah\'s wife, and the three wives of his sons with them, into the ark;', zh:'正当那日，挪亚和他的妻子，并他三个儿子——闪、含、雅弗，和三个儿妇，都进入了方舟。', ru:'В сей самый день вошёл в ковчег Ной, и Сим, Хам и Иафет, сыновья Ноя, и жена Ноя, и три жены сынов его с ними.', ja:'ちょうどその日、ノアとノアの息子たち、セム、ハム、ヤペテと、ノアの妻と息子たちの三人の妻も、共に箱船に入った。', es:'En ese mismo día entró Noé, y Sem, y Cam, y Jafet hijos de Noé, y la mujer de Noé, y las tres mujeres de sus hijos con él, en el arca.' },
        { v:14, ko:'그들과 모든 들짐승이 그 종류대로, 모든 육축이 그 종류대로, 땅에 기는 모든 것이 그 종류대로, 날개 있는 모든 새가 그 종류대로', en:'They, and every beast after his kind, and all the cattle after their kind, and every creeping thing that creepeth upon the earth after his kind, and every fowl after his kind, every bird of every sort.', zh:'他们和百兽各从其类，一切牲畜各从其类，爬在地上的昆虫各从其类，一切禽鸟各从其类，都进入了方舟。', ru:'они и все звери по роду их, и всякий скот по роду его, и все гады, ползающие по земле, по роду их, и все птицы по роду их, всякие птицы, всё, что летает.', ja:'彼らと共に、すべての野の獣はその種類にしたがって、すべての家畜はその種類にしたがって、地に這うすべてのものはその種類にしたがって、すべての鳥はその種類にしたがって入った。', es:'Ellos, y todos los animales silvestres según sus especies, y todos los animales domésticos según sus especies, y todo reptil que anda arrastrándose sobre la tierra según su especie, y toda ave según su especie, y todo pájaro de toda especie.' },
        { v:15, ko:'무릇 생명의 기식 있는 육체가 둘씩 노아에게 나아와 방주로 들어갔으니', en:'And they went in unto Noah into the ark, two and two of all flesh, wherein is the breath of life.', zh:'凡有血肉、有气息的活物，都一对对地到挪亚那里进入方舟，', ru:'И вошли к Ною в ковчег по паре от всякой плоти, в которой есть дух жизни.', ja:'命の息のあるすべての肉なるものが、二つずつノアのところに来て箱船に入った。', es:'Y vinieron a Noé en el arca, de dos en dos de toda carne en que había espíritu de vida.' },
        { v:16, ko:'들어간 것들은 모든 것의 암수라 하나님이 그에게 명하신 대로 들어가매 여호와께서 그를 위하여 문을 닫으시니라', en:'And they that went in, went in male and female of all flesh, as God had commanded him: and the LORD shut him in.', zh:'凡有血肉进入方舟的，都是有公有母，正如神所吩咐挪亚的。耶和华就把他关在方舟里头。', ru:'И вошедшие мужеского и женского пола из всякой плоти вошли, как повелел ему Бог. И затворил Господь за ним.', ja:'入ったものは、すべての肉なるものの雄と雌であって、神が命じられたとおりであった。そして主は彼のうしろの戸を閉められた。', es:'Y los que vinieron, macho y hembra de toda carne vinieron, como le había mandado Dios; y Jehová le cerró la puerta.' },
        { v:17, ko:'홍수가 사십 일 동안 땅에 있었더니 물이 많아져 방주가 땅에서 떠올랐고', en:'And the flood was forty days upon the earth; and the waters increased, and bare up the ark, and it was lift up above the earth.', zh:'洪水泛滥在地上四十天，水往上涨，把方舟从地上漂起来了，', ru:'Продолжалось потопление сорок дней на земле; и умножилась вода, и подняла ковчег, и он возвысился над землёю.', ja:'洪水は四十日間、地の上を覆った。水がふえて箱船を浮かべ、箱船は地から持ち上がった。', es:'Y fue el diluvio cuarenta días sobre la tierra; y las aguas crecieron, y alzaron el arca, y estuvo elevada sobre la tierra.' },
        { v:18, ko:'물이 더 많아져 땅에 넘치매 방주가 물 위에 떠다녔으며', en:'And the waters prevailed, and were increased greatly upon the earth; and the ark went upon the face of the waters.', zh:'水势浩大，在地上大大地往上涨，方舟在水面上漂来漂去。', ru:'Вода же усилилась и весьма умножилась на земле; и ковчег плавал по поверхности вод.', ja:'水はふえ、地の上に非常に増した。箱船は水の面を漂った。', es:'Y subieron las aguas, y crecieron en gran manera sobre la tierra; y el arca andaba sobre la superficie de las aguas.' },
        { v:19, ko:'물이 땅에 더욱 넘치매 천하의 높은 산이 다 덮였더니', en:'And the waters prevailed exceedingly upon the earth; and all the high hills, that were under the whole heaven, were covered.', zh:'水势在地上极其浩大，天下的高山都淹没了。', ru:'Вода же усилилась на земле чрезвычайно, так что покрылись все высокие горы, какие есть под всем небом.', ja:'水はさらにふえ、地の上に非常に増したので、天の下にあるすべての高い山が覆われた。', es:'Y las aguas prevalecieron en extremo sobre la tierra; y todos los montes altos que había debajo de todos los cielos, fueron cubiertos.' },
        { v:20, ko:'물이 불어서 십오 규빗이 오르매 산들이 덮인지라', en:'Fifteen cubits upward did the waters prevail; and the mountains were covered.', zh:'水势比山高十五肘，山岭都淹了。', ru:'На пятнадцать локтей поднялась над ними вода, и покрылись горы.', ja:'水は十五キュビトも増して、山々を覆った。', es:'Quince codos en alto prevaleció el agua, y fueron cubiertos los montes.' },
        { v:21, ko:'땅 위에 움직이는 생물이 다 죽었으니 곧 새와 육축과 들짐승과 땅에 기는 모든 것과 모든 사람이라', en:'And all flesh died that moved upon the earth, both of fowl, and of cattle, and of beast, and of every creeping thing that creepeth upon the earth, and every man:', zh:'凡在地上有血肉的动物，就是飞鸟、牲畜、走兽，和爬在地上的昆虫，以及所有的人都死了。', ru:'И лишилась жизни всякая плоть, движущаяся по земле, и птицы, и скоты, и звери, и все гады, ползающие по земле, и все люди;', ja:'地の上を動くすべての肉なるものは死んだ。鳥も家畜も野の獣も地を群れ動くすべてのものも、すべての人も。', es:'Y murió toda carne que se mueve sobre la tierra, así de aves como de ganado, y de bestias, y de todo reptil que se arrastra sobre la tierra, y todo hombre.' },
        { v:22, ko:'육지에 있어 코로 생기를 호흡하는 것은 다 죽었더라', en:'All in whose nostrils was the breath of life, of all that was in the dry land, died.', zh:'凡在旱地上，鼻孔有气息的生灵都死了。', ru:'всё, что имело дыхание духа жизни в ноздрях своих на суше, умерло.', ja:'陸にいて、その鼻に命の息があるものはすべて死んだ。', es:'Todo lo que tenía aliento de espíritu de vida en sus narices, todo lo que había en la tierra, murió.' },
        { v:23, ko:'지면의 모든 생물을 쓸어버리시니 곧 사람과 육축과 기는 것과 공중의 새까지라 이들은 땅에서 쓸어버림을 당하였으되 홀로 노아와 그와 함께 방주에 있던 자들만 남았더라', en:'And every living substance was destroyed which was upon the face of the ground, both man, and cattle, and the creeping things, and the fowl of the heaven; and they were destroyed from the earth: and Noah only remained alive, and they that were with him in the ark.', zh:'这样，耶和华将地面上各类的活物，连人带牲畜、昆虫，以及空中的飞鸟，都从地面上除灭了，只留下挪亚和那些与他同在方舟里的。', ru:'Истребилось всякое существо, которое было на поверхности земли; от человека до скота, и гадов, и птиц небесных, всё истребилось с земли; остался только Ной и что было с ним в ковчеге.', ja:'こうして地のおもてのすべての生き物は、人も家畜も這うものも空の鳥も、ぬぐい去られた。地から絶やされ、ノアと箱船にいたものだけが残った。', es:'Así fue destruido todo ser que vivía sobre la faz de la tierra, desde el hombre hasta la bestia, los reptiles, y las aves del cielo; y fueron raídos de la tierra, y quedó solamente Noé, y los que con él estaban en el arca.' },
        { v:24, ko:'물이 일백오십 일을 땅에 넘쳤더라', en:'And the waters prevailed upon the earth an hundred and fifty days.', zh:'水势浩大，在地上共一百五十天。', ru:'Вода же стояла на земле сто пятьдесят дней.', ja:'水は百五十日の間、地の上に増していた。', es:'Y prevalecieron las aguas sobre la tierra ciento cincuenta días.' }
      ],
      8: [
        { v:1,  ko:'하나님이 노아와 그와 함께 방주에 있는 모든 들짐승과 육축을 권고하사 하나님이 바람으로 땅 위에 불게 하시매 물이 감하였고', en:'And God remembered Noah, and every living thing, and all the cattle that was with him in the ark: and God made a wind to pass over the earth, and the waters asswaged.', zh:'神记念挪亚和挪亚方舟里的一切走兽牲畜。神叫风吹地，水势渐落，', ru:'И вспомнил Бог о Ное, и о всех зверях, и о всём скоте, бывшем с ним в ковчеге; и навёл Бог ветер на землю, и воды остановились.', ja:'神はノアと、箱船の中にいたすべての野の獣と家畜を心に留められた。神は地の上に風を吹かせられたので、水は引き始めた。', es:'Y acordóse Dios de Noé, y de todos los animales, y de toda la bestia que estaba con él en el arca; e hizo pasar Dios un viento sobre la tierra, y disminuyeron las aguas.' },
        { v:2,  ko:'깊음의 샘과 하늘의 창이 닫히고 하늘에서 비가 그치매', en:'The fountains also of the deep and the windows of heaven were stopped, and the rain from heaven was restrained;', zh:'深渊的泉源和天上的窗户都闭塞了，天上的大雨也止住了。', ru:'И закрылись источники бездны и окна небесные, и перестал дождь с неба.', ja:'また淵の源と天の窓とがふさがれ、天からの雨はやんだ。', es:'Y se cerraron las fuentes del abismo y las cataratas de los cielos; y cesó la lluvia del cielo.' },
        { v:3,  ko:'물이 땅에서 물러가고 점점 물러가서 일백오십 일 후에 줄어들고', en:'And the waters returned from off the earth continually: and after the end of the hundred and fifty days the waters were abated.', zh:'水从地上渐渐退去。过了一百五十天，水就渐消。', ru:'Вода же постепенно убывала до десятого месяца; и в первый день десятого месяца показались верхи гор.', ja:'水は地の上からひいてゆき、百五十日の後には水が減った。', es:'Y se fueron retirando las aguas de sobre la tierra, yendo y volviendo; y al cabo de ciento cincuenta días mengaaron las aguas.' },
        { v:4,  ko:'칠월 곧 그 달 십칠일에 방주가 아라랏 산에 머물렀으며', en:'And the ark rested in the seventh month, on the seventeenth day of the month, upon the mountains of Ararat.', zh:'七月十七日，方舟停在亚拉腊山上。', ru:'Ковчег остановился в седьмом месяце, в семнадцатый день месяца, на горах Араратских.', ja:'第七の月の十七日に、箱船はアララテの山々の上に止まった。', es:'Y reposó el arca en el mes séptimo, a los diecisiete días del mes, sobre los montes de Ararat.' },
        { v:5,  ko:'물이 십월까지 점점 감하여 십월 곧 그 달 일일에 산들의 봉우리가 보였더라', en:'And the waters decreased continually until the tenth month: in the tenth month, on the first day of the month, were the tops of the mountains seen.', zh:'水从第七月渐渐减少，到十月初一日，山顶都露出来了。', ru:'Вода постоянно убывала до десятого месяца; в первый день десятого месяца показались верхи гор.', ja:'水はさらに十月まで引き続き減って、十月の一日に山々の頂が現れた。', es:'Y las aguas fueron decreciendo hasta el mes décimo; en el décimo, al primero del mes, se descubrieron las cimas de los montes.' },
        { v:6,  ko:'사십 일이 지나서 노아가 그 방주에 낸 창문을 열고', en:'And it came to pass at the end of forty days, that Noah opened the window of the ark which he had made:', zh:'过了四十天，挪亚开了他所造的方舟的窗户，', ru:'По прошествии сорока дней Ной открыл сделанное им окно ковчега.', ja:'四十日たって、ノアは自分が造った箱船の窓を開いた。', es:'Y sucedió que al cabo de cuarenta días, abrió Noé la ventana del arca que había hecho.' },
        { v:7,  ko:'까마귀를 내어 놓으매 까마귀가 물이 땅에서 마르기까지 날아 왕래하였더라', en:'And he sent forth a raven, which went forth to and fro, until the waters were dried up from off the earth.', zh:'放出一只乌鸦去；那乌鸦飞来飞去，直到地上的水都干了。', ru:'И выпустил ворона, который, вылетев, отлетал и прилетал, пока осушилась земля от воды.', ja:'烏を放つと、烏は地の上から水が干るまで、飛んで行ったり来たりした。', es:'Y envió un cuervo, el cual salió, y estuvo yendo y volviendo, hasta que las aguas se secaron de sobre la tierra.' },
        { v:8,  ko:'또 비둘기를 내어 놓아 지면에 물이 감한 여부를 알고자 하매', en:'Also he sent forth a dove from him, to see if the waters were abated from off the face of the ground;', zh:'他又放出一只鸽子去，要看看水从地面上退了没有。', ru:'Потом выпустил от себя голубя, чтобы видеть, сошла ли вода с лица земли.', ja:'ノアはまた地の面から水が引いたかどうかを確かめようと、鳩を放った。', es:'Envió también de sí una paloma, para ver si las aguas se habían retirado de sobre la faz de la tierra.' },
        { v:9,  ko:'비둘기가 발 붙일 곳을 찾지 못하고 방주로 돌아와 그에게로 오는지라 그가 손을 내밀어 방주 안 자기에게로 받아들이고', en:'But the dove found no rest for the sole of her foot, and she returned unto him into the ark, for the waters were on the face of the whole earth: then he put forth his hand, and took her, and pulled her in unto him into the ark.', zh:'但鸽子找不着落脚之地，就回到方舟挪亚那里；因为水还漫在全地上。挪亚伸出手去，把鸽子接进方舟来。', ru:'Но голубь не нашёл места покоя для ног своих и возвратился к нему в ковчег, ибо воды было ещё много по всей земле. И он простёр руку свою, и взял его, и принял к себе в ковчег.', ja:'鳩は足の裏を休める場所が見つからず、箱船のノアのところに戻ってきた。全地の面に水があったからである。彼は手を伸べて鳩を捕え、箱船の中の自分のところに引き入れた。', es:'Mas la paloma no halló donde sentar la planta de su pie, y volvióse a él al arca, porque las aguas estaban aún sobre la faz de toda la tierra. Entonces él extendió su mano, y tomándola, la hizo entrar consigo en el arca.' },
        { v:10, ko:'또 칠 일을 기다려 다시 비둘기를 방주에서 내어 놓으매', en:'And he stayed yet other seven days; and again he sent forth the dove out of the ark;', zh:'他又等了七天，再把鸽子从方舟放出去。', ru:'И подождал ещё семь дней, и опять выпустил голубя из ковчега.', ja:'さらに七日待って、再び箱船から鳩を放った。', es:'Y esperó aún otros siete días, y volvió a enviar la paloma fuera del arca.' },
        { v:11, ko:'저녁때에 비둘기가 그에게로 돌아왔는데 그 입에 감람 새 잎사귀가 있는지라 이에 노아가 땅에 물이 감한 줄을 알았으며', en:'And the dove came in to him in the evening; and, lo, in her mouth was an olive leaf pluckt off: so Noah knew that the waters were abated from off the earth.', zh:'到了晚上，鸽子回到他那里，嘴里叼着一个新拧下来的橄榄叶子，挪亚就知道地上的水退了。', ru:'Голубь возвратился к нему в вечернее время, и вот, свежий масличный лист во рту у него, и Ной узнал, что воды сошли с земли.', ja:'鳩は夕方になってノアのところに戻ってきた。見ると、鳩の口には摘みたてのオリーブの葉があった。ノアは地の上から水が引いたことを知った。', es:'Y volvió a él la paloma a la hora de la tarde; y he aquí que traía una hoja de olivo tomada en su pico; y conoció Noé que las aguas se habían retirado de sobre la tierra.' },
        { v:12, ko:'또 칠 일을 기다려 비둘기를 내어 놓으매 다시는 그에게로 돌아오지 아니하였더라', en:'And he stayed yet other seven days; and sent forth the dove; which returned not again unto him any more.', zh:'他又等了七天，放出鸽子去，鸽子就不再回来了。', ru:'Он подождал ещё семь дней и выпустил голубя; и он уже не возвратился к нему.', ja:'さらに七日待って鳩を放つと、二度とノアのところに帰ってこなかった。', es:'Y esperó aún otros siete días, y soltó la paloma, la cual no volvió ya más a él.' },
        { v:13, ko:'육백일 년 정월 곧 그 달 일일에 지면에 물이 걷힌지라 노아가 방주 뚜껑을 제치고 본즉 지면에 물이 걷혔더니', en:'And it came to pass in the six hundredth and first year, in the first month, the first day of the month, the waters were dried up from off the earth: and Noah removed the covering of the ark, and looked, and, behold, the face of the ground was dry.', zh:'六百零一年正月初一日，地上的水都干了。挪亚撤去方舟的盖，观看，见地面上干了。', ru:'Шестьсот первого года к первому дню первого месяца иссякла вода на земле; и открыл Ной кровлю ковчега, и посмотрел, и вот, обсохла поверхность земли.', ja:'六百一年の第一の月の一日、地の上から水が干上がった。ノアは箱船の覆いを取り除いて見ると、地の面は乾いていた。', es:'Y sucedió que en el año seiscientos uno de Noé, en el mes primero, el día primero del mes, las aguas se enjugaron de sobre la tierra; y quitó Noé la cubierta del arca, y miró, y he aquí que la faz de la tierra estaba enjuta.' },
        { v:14, ko:'이월 이십칠일에 땅이 말랐더라', en:'And in the second month, on the seven and twentieth day of the month, was the earth dried.', zh:'到了二月二十七日，地就都干了。', ru:'И во втором месяце к двадцать седьмому дню месяца земля высохла.', ja:'第二の月の二十七日に、地は乾いた。', es:'Y en el mes segundo, a los veintisiete días del mes, se secó la tierra.' },
        { v:15, ko:'하나님이 노아에게 일러 가라사대', en:'And God spake unto Noah, saying,', zh:'神晓谕挪亚说：', ru:'И сказал Бог Ною:', ja:'神はノアに言われた、', es:'Entonces habló Dios a Noé, diciendo:' },
        { v:16, ko:'너는 네 아내와 네 아들들과 네 자부들과 함께 방주에서 나오고', en:'Go forth of the ark, thou, and thy wife, and thy sons, and thy sons wives with thee.', zh:'「你和你的妻子，儿子，儿妇，都可以出方舟了。', ru:'выйди из ковчега ты и жена твоя, и сыновья твои, и жёны сынов твоих с тобою.', ja:'「あなたは妻、息子たち、息子たちの妻と共に箱船から出なさい。', es:'Sal del arca tú, y tu mujer, y tus hijos, y las mujeres de tus hijos contigo.' },
        { v:17, ko:'너와 함께 한 모든 혈육 있는 생물 곧 새와 육축과 땅에 기는 모든 것을 다 이끌어 내라 이것들이 땅에서 생육하고 땅에서 번성하리라 하시매', en:'Bring forth with thee every living thing that is with thee, of all flesh, both of fowl, and of cattle, and of every creeping thing that creepeth upon the earth; that they may breed abundantly in the earth, and be fruitful, and multiply upon the earth.', zh:'你所带来的一切有血肉的活物，就是飞鸟、牲畜，和一切爬在地上的昆虫，都要带出来，叫它们在地上多多滋生，大大兴旺。」', ru:'Выведи с собою всех животных, которые с тобою, от всякой плоти, из птиц, и скотов, и всех гадов, пресмыкающихся по земле: пусть разойдутся они по земле, и пусть плодятся и размножаются на земле.', ja:'あなたと共にいるすべての生き物、鳥も家畜も地に這うすべてのものも連れ出しなさい。彼らが地の上に増え広がり、地の上で実を結んで増えるように。」', es:'Todos los animales que están contigo de toda carne, de aves, de bestias, y de todo reptil que se arrastra sobre la tierra, saca contigo; y vayan por la tierra, y fructifiquen y multiplíquense sobre la tierra.' },
        { v:18, ko:'노아가 그 아들들과 그 아내와 그 자부들과 함께 나왔고', en:'And Noah went forth, and his sons, and his wife, and his sons wives with him:', zh:'于是挪亚和他的妻子，儿子，儿妇，都出来了。', ru:'И вышел Ной, и сыновья его, и жена его, и жёны сынов его с ним.', ja:'ノアは息子たち、妻、息子たちの妻と共に出てきた。', es:'Entonces salió Noé, y sus hijos, y su mujer, y las mujeres de sus hijos con él.' },
        { v:19, ko:'땅 위의 동물 곧 모든 짐승과 모든 기는 것과 모든 새도 그 종류대로 방주에서 나왔더라', en:'Every beast, every creeping thing, and every fowl, and whatsoever creepeth upon the earth, after their kinds, went forth out of the ark.', zh:'一切走兽、昆虫、飞鸟，凡在地上爬动的，各从其类，都出了方舟。', ru:'Все звери, все гады, все птицы, всё движущееся по земле, по родам своим, вышли из ковчега.', ja:'すべての獣、すべての這うもの、すべての鳥、地の上を動くすべてのものは、その種類にしたがって箱船から出た。', es:'Todos los animales, todos los reptiles, todas las aves, todo lo que se mueve sobre la tierra, según sus familias, salieron del arca.' },
        { v:20, ko:'노아가 여호와를 위하여 단을 쌓고 모든 정결한 짐승 중에서와 모든 정결한 새 중에서 취하여 번제로 단에 드렸더니', en:'And Noah builded an altar unto the LORD; and took of every clean beast, and of every clean fowl, and offered burnt offerings on the altar.', zh:'挪亚为耶和华筑了一座坛，拿各类洁净的牲畜飞鸟，献在坛上为燔祭。', ru:'И устроил Ной жертвенник Господу; и взял из всякого скота чистого и из всех птиц чистых, и принёс во всесожжение на жертвеннике.', ja:'ノアは主のために祭壇を築いた。すべての清い動物とすべての清い鳥の中から取って、祭壇の上に燔祭をささげた。', es:'Y edificó Noé un altar a Jehová, y tomó de todo animal limpio y de toda ave limpia, y ofreció holocausto en el altar.' },
        { v:21, ko:'여호와께서 그 향기를 흠향하시고 그 중심에 이르시되 내가 다시는 사람으로 인하여 땅을 저주하지 아니하리니 이는 사람의 마음의 계획하는 바가 어려서부터 악함이라 내가 전에 행한 것같이 모든 생물을 다시 멸하지 아니하리니', en:'And the LORD smelled a sweet savour; and the LORD said in his heart, I will not again curse the ground any more for man\'s sake; for the imagination of man\'s heart is evil from his youth; neither will I again smite any more every thing living, as I have done.', zh:'耶和华闻那馨香之气，就心里说：「我不再因人的缘故咒诅地（人从小时心里怀着恶念），也不再按着我才行的灭各种的活物了。', ru:'И обонял Господь приятное благоухание, и сказал Господь в сердце Своём: не буду больше проклинать землю за человека, потому что помышление сердца человеческого — зло от юности его; и не буду больше поражать всего живущего, как Я сделал.', ja:'主はその香ばしいかおりをかいで、心に言われた、「わたしは二度と人のゆえに地を呪わない。人の心の思い図ることは、幼いときから悪いからである。わたしは二度と、このたびしたように、すべての生き物を打つことはしない。」', es:'Y percibió Jehová olor grato; y dijo Jehová en su corazón: No tornaré más a maldecir la tierra por causa del hombre; porque el intento del corazón del hombre es malo desde su juventud; ni tornaré más a destruir todo ser viviente, como he hecho.' },
        { v:22, ko:'땅이 있을 동안에는 심음과 거둠과 추위와 더위와 여름과 겨울과 낮과 밤이 쉬지 아니하리라', en:'While the earth remaineth, seedtime and harvest, and cold and heat, and summer and winter, and day and night shall not cease.', zh:'地还存留的时候，稼穑、寒暑、冬夏、昼夜就永不停息了。」', ru:'Впредь во все дни земли сеяние и жатва, холод и зной, лето и зима, день и ночь не прекратятся.', ja:'地の続くかぎり、種蒔きと刈り入れ、寒さと暑さ、夏と冬、昼と夜とは、やむことがない。', es:'Todavía permanecerá la tierra: la sementera y la siega, el frío y el calor, el verano y el invierno, el día y la noche, no cesarán.' }
      ],
      9: [
        { v:1,  ko:'하나님이 노아와 그 아들들에게 복을 주시며 그들에게 이르시되 생육하고 번성하여 땅에 충만하라', en:'And God blessed Noah and his sons, and said unto them, Be fruitful, and multiply, and replenish the earth.', zh:'神赐福给挪亚和他的儿子，对他们说：「你们要生养众多，遍满了地。', ru:'И благословил Бог Ноя и сынов его и сказал им: плодитесь и размножайтесь, и наполняйте землю.', ja:'神はノアとその息子たちを祝福して言われた、「産めよ、増えよ、地に満ちよ。」', es:'Bendijo Dios a Noé y a sus hijos, y les dijo: Fructificad y multiplicaos, y henchid la tierra.' },
        { v:2,  ko:'땅의 모든 짐승과 공중의 모든 새와 땅에 기는 모든 것과 바다의 모든 고기가 너희를 두려워하며 너희를 무서워하리니 이들은 너희 손에 붙였음이니라', en:'And the fear of you and the dread of you shall be upon every beast of the earth, and upon every fowl of the air, upon all that moveth upon the earth, and upon all the fishes of the sea; into your hand are they delivered.', zh:'地上的各种走兽和空中的各种飞鸟，都必惊恐惧怕你们，连地上一切的昆虫并海里一切的鱼都交付你们的手了。', ru:'Да страшатся и да трепещут вас все звери земные, все птицы небесные, всё, что движется на земле, и все рыбы морские; в ваши руки отданы они.', ja:'地のすべての獣と空のすべての鳥と、地に這うすべてのものと海のすべての魚はあなたがたを恐れ、おののく。それらはあなたがたの手にゆだねられた。', es:'El temor y el miedo de vosotros estarán sobre todo animal de la tierra, y sobre toda ave de los cielos, en todo lo que se moverá en la tierra, y en todos los peces del mar: en vuestra mano son entregados.' },
        { v:3,  ko:'무릇 산 동물은 너희의 식물이 될지라 채소같이 내가 이것을 다 너희에게 주노라', en:'Every moving thing that liveth shall be meat for you; even as the green herb have I given you all things.', zh:'凡活着的动物，都可以作你们的食物，这一切我都赐给你们，如同菜蔬一样。', ru:'Всё движущееся, что живёт, будет вам в пищу; как зелень травную даю вам всё.', ja:'動いている生き物はすべてあなたがたの食物となる。青草と同じようにわたしはそのすべてをあなたがたに与える。', es:'Todo lo que se mueve y vive, os será para mantenimiento: así como las legumbres y plantas verdes, os lo he dado todo.' },
        { v:4,  ko:'그러나 고기를 그 생명 되는 피채 먹지 말 것이니라', en:'But flesh with the life thereof, which is the blood thereof, shall ye not eat.', zh:'惟独肉带着血，那就是它的生命，你们不可吃。', ru:'Только плоти с душою её, с кровью её, не ешьте.', ja:'ただ肉はその命である血のままで食べてはならない。', es:'Pero carne con su vida, que es su sangre, no comeréis.' },
        { v:5,  ko:'내가 반드시 너희 피 곧 너희 생명의 피를 찾으리니 짐승이면 그 짐승에게서, 사람이나 사람의 형제면 그에게서 그의 생명을 찾으리라', en:'And surely your blood of your lives will I require; at the hand of every beast will I require it, and at the hand of man; at the hand of every man\'s brother will I require the life of man.', zh:'流你们血、害你们命的，无论是兽是人，我必讨他的罪，就是向各人的弟兄也是如此。', ru:'Я взыщу и вашу кровь, в которой жизнь ваша, взыщу её от всякого зверя, взыщу также душу человека от руки человека, от руки брата его.', ja:'わたしはまたあなたがたの命の血の報復をする。すべての獣に対してもそうする。人に対しても互いの兄弟に対しても、人の命の報復をする。', es:'Porque yo demandaré la sangre de vuestras vidas; de mano de todo animal la demandaré, y de mano del hombre; de mano del varón su hermano demandaré la vida del hombre.' },
        { v:6,  ko:'무릇 사람의 피를 흘리면 사람이 그 피를 흘릴 것이니 이는 하나님이 자기 형상대로 사람을 지었음이니라', en:'Whoso sheddeth man\'s blood, by man shall his blood be shed: for in the image of God made he man.', zh:'凡流人血的，他的血也必被人所流，因为神造人，是照自己的形象造的。', ru:'Кто прольёт кровь человеческую, того кровь прольётся рукою человека: ибо человек создан по образу Божию.', ja:'人の血を流す者は人に血を流される。神は人を自分のかたちに造られたからである。', es:'El que derramare sangre de hombre, por el hombre su sangre será derramada; porque a imagen de Dios es hecho el hombre.' },
        { v:7,  ko:'너희는 생육하고 번성하며 땅에 가득하여 그 중에서 번성하라 하셨더라', en:'And you, be ye fruitful, and multiply; bring forth abundantly in the earth, and multiply therein.', zh:'你们要生养众多，在地上昌盛繁茂。」', ru:'Вы же плодитесь и размножайтесь, и распространяйтесь по земле, и умножайтесь на ней.', ja:'あなたがたは産めよ、増えよ、地に群がり、地に増えよ。」', es:'Mas vosotros fructificad y multiplicaos; procread abundantemente en la tierra, y multiplicaos en ella.' },
        { v:8,  ko:'하나님이 노아와 그와 함께한 아들들에게 일러 가라사대', en:'And God spake unto Noah, and to his sons with him, saying,', zh:'神晓谕挪亚和他的儿子们说：', ru:'И сказал Бог Ною и сынам его с ним:', ja:'神はノアとその息子たちに言われた、', es:'Habló también Dios a Noé y a sus hijos con él, diciendo:' },
        { v:9,  ko:'내가 내 언약을 너희와 너희 후손과', en:'And I, behold, I establish my covenant with you, and with your seed after you;', zh:'「我与你们和你们的后裔立约，', ru:'Вот, Я поставляю завет Мой с вами и с потомством вашим после вас.', ja:'「わたしはあなたがたと、またあなたがたの後に来る子孫と、契約を結ぶ。', es:'Yo, he aquí que establezco mi pacto con vosotros, y con vuestros descendientes después de vosotros.' },
        { v:10, ko:'너희와 함께 한 모든 생물 곧 너희와 함께 한 새와 육축과 땅의 모든 생물에게 세우리니 방주에서 나온 모든 것 곧 땅의 모든 짐승에게니라', en:'And with every living creature that is with you, of the fowl, of the cattle, and of every beast of the earth with you; from all that go out of the ark, to every beast of the earth.', zh:'并与你们同在的一切活物——飞鸟、牲畜、走兽，凡从方舟里出来的活物——立约。', ru:'и со всякою душою живою, которая с вами, с птицами и со скотами, и со всеми зверями земными, которые у вас, со всеми вышедшими из ковчега, со всеми животными земли.', ja:'また、あなたがたと共にいるすべての生き物、鳥も家畜も、地のすべての獣も、箱船から出たすべてのものと共に契約を結ぶ。地のすべての獣と共に。', es:'Y con todo ser viviente que está con vosotros, de aves, de animales domésticos y de todo animal de la tierra que está con vosotros, desde todos los que salieron del arca hasta todo animal de la tierra.' },
        { v:11, ko:'내가 너희와 언약을 세우리니 다시는 모든 생물을 홍수로 멸하지 아니할 것이라 땅을 침몰할 홍수가 다시 있지 아니하리라', en:'And I will establish my covenant with you; neither shall all flesh be cut off any more by the waters of a flood; neither shall there any more be a flood to destroy the earth.', zh:'我与你们立约：凡有血肉的，不再被洪水灭绝；也不再有洪水毁坏地了。」', ru:'Поставляю завет Мой с вами, что не будет более истреблена всякая плоть водами потопа, и не будет уже потопа на опустошение земли.', ja:'わたしはあなたがたと契約を結ぶ。すべての肉なるものは、二度と洪水によって断ち切られることなく、地を滅ぼす洪水は、二度と起こらない。」', es:'Estableceré mi pacto con vosotros, y no exterminaré ya más toda carne con aguas de diluvio, ni habrá más diluvio para destruir la tierra.' },
        { v:12, ko:'하나님이 가라사대 내가 나와 너희와 및 너희와 함께하는 모든 생물 사이에 영세까지 세우는 언약의 증거는 이것이라', en:'And God said, This is the token of the covenant which I make between me and you and every living creature that is with you, for perpetual generations:', zh:'神说：「我与你们并你们这里的各样活物所立的永约，是有记号的。', ru:'И сказал Бог: вот знамение завета, который Я поставляю между Мною и между вами и между всякою душою живою, которая с вами, в роды навсегда.', ja:'神は言われた、「これはわたしとあなたがた及びあなたがたと共にいるすべての生き物との間に、代々限りなく立てるわたしの契約のしるしである。」', es:'Y dijo Dios: Esta es la señal del pacto que yo establezco entre mí y vosotros y todo ser viviente que está con vosotros, por siglos perpetuos.' },
        { v:13, ko:'내가 내 무지개를 구름 속에 두었나니 이것이 나의 세상과의 언약의 증거니라', en:'I do set my bow in the cloud, and it shall be for a token of a covenant between me and the earth.', zh:'我把虹放在云彩中，这就可作我与地立约的记号了。', ru:'Я полагаю радугу Мою в облаке, чтоб она была знамением завета между Мною и между землёю.', ja:'わたしは雲の中にわたしの虹を置く。これがわたしと地との間の契約のしるしとなる。', es:'Mi arco pondré en las nubes, el cual será por señal del pacto entre mí y la tierra.' },
        { v:14, ko:'내가 구름으로 땅을 덮을 때에 무지개가 구름 속에 나타나면', en:'And it shall come to pass, when I bring a cloud over the earth, that the bow shall be seen in the cloud:', zh:'我使云彩盖地的时候，必有虹现在云彩中，', ru:'И будет, когда Я наведу облако на землю, то явится радуга в облаке;', ja:'わたしが地の上に雲を起こすとき、虹が雲の中に現れる。', es:'Y acontecerá que cuando haga venir nubes sobre la tierra, se dejará ver el arco en las nubes.' },
        { v:15, ko:'내가 나와 너희와 및 육체를 가진 모든 생물 사이의 내 언약을 기억하리니 다시는 물이 모든 육체를 멸하는 홍수가 되지 아니할지라', en:'And I will remember my covenant, which is between me and you and every living creature of all flesh; and the waters shall no more become a flood to destroy all flesh.', zh:'我便记念我与你们和各样有血肉的活物所立的约，水就再不泛滥、毁坏一切有血肉的物了。', ru:'и Я вспомню завет Мой, который между Мною и между вами и между всякою душою живою в какой-либо плоти; и не будет более вода потопом на истребление всякой плоти.', ja:'わたしは、わたしとあなたがた及びすべての肉なる生き物との間の契約を覚えて、二度と洪水があらゆる肉なるものを滅ぼすことはない。」', es:'Y me acordaré del pacto mío, que hay entre mí y vosotros y todo ser viviente de toda carne; y no habrá más aguas de diluvio para destruir toda carne.' },
        { v:16, ko:'무지개가 구름 사이에 있으리니 내가 보고 나 하나님과 모든 육체를 가진 땅의 모든 생물 사이의 영원한 언약을 기억하리라', en:'And the bow shall be in the cloud; and I will look upon it, that I may remember the everlasting covenant between God and every living creature of all flesh that is upon the earth.', zh:'虹必现在云彩中，我看见，就要记念　神和地上各样有血肉的活物所立的永约。」', ru:'И будет радуга в облаке, и Я увижу её, и вспомню завет вечный между Богом и между всякою душою живою в какой-либо плоти, которая на земле.', ja:'虹が雲の中にあるとき、わたしはそれを見て、神と地にいるあらゆる肉なる生き物との間の、永遠の契約を覚える。」', es:'Estará el arco en las nubes, y lo veré, y me acordaré del pacto perpetuo entre Dios y todo ser viviente, con toda carne que hay sobre la tierra.' },
        { v:17, ko:'하나님이 노아에게 또 이르시되 내가 나와 땅의 모든 육체를 가진 생물 사이에 세운 언약의 증거가 이것이라 하셨더라', en:'And God said unto Noah, This is the token of the covenant, which I have established between me and all flesh that is upon the earth.', zh:'神对挪亚说：「这就是我与地上各样有血肉之物所立之约的记号了。」', ru:'И сказал Бог Ною: вот знамение завета, который Я поставил между Мною и всякою плотью, которая на земле.', ja:'神はノアに言われた、「これが、わたしと地にあるすべての肉なるものとの間に立てた契約のしるしである。」', es:'Y dijo Dios a Noé: Esta es la señal del pacto que he establecido entre mí y toda carne que está sobre la tierra.' },
        { v:18, ko:'방주에서 나온 노아의 아들들은 셈과 함과 야벳이며 함은 가나안의 아버지라', en:'And the sons of Noah, that went forth of the ark, were Shem, and Ham, and Japheth: and Ham is the father of Canaan.', zh:'出了方舟、挪亚的儿子是闪、含、雅弗；含是迦南的父亲。', ru:'Сыновья Ноя, вышедшие из ковчега, были: Сим, Хам и Иафет. Хам же был отец Ханаана.', ja:'箱船から出たノアの息子たちはセム、ハム、ヤペテであった。ハムはカナンの父である。', es:'Y los hijos de Noé que salieron del arca fueron Sem, Cam y Jafet; y Cam es el padre de Canaán.' },
        { v:19, ko:'노아의 이 세 아들로 좇아 사람이 온 땅에 퍼지니라', en:'These are the three sons of Noah: and of them was the whole earth overspread.', zh:'这是挪亚三个儿子，他们的后裔分散在全地。', ru:'Сии трое были сыновья Ноя, и от них населилась вся земля.', ja:'これらはノアの三人の息子たちで、そこから全地に人々が広まった。', es:'Estos tres son los hijos de Noé, y de ellos fue llena toda la tierra.' },
        { v:20, ko:'노아가 농업을 시작하여 포도나무를 심었더니', en:'And Noah began to be an husbandman, and he planted a vineyard:', zh:'挪亚作起农夫来，栽了一个葡萄园。', ru:'Ной начал возделывать землю и насадил виноградник.', ja:'ノアは農夫となり、ぶどうの木を植えた。', es:'Después comenzó Noé a labrar la tierra, y plantó una viña.' },
        { v:21, ko:'포도주를 마시고 취하여 그 장막 안에서 벌거벗은지라', en:'And he drank of the wine, and was drunken; and he was uncovered within his tent.', zh:'他喝了园中的酒便醉了，在帐棚里赤着身子。', ru:'И выпил он вина, и опьянел, и лежал обнажённым в шатре своём.', ja:'彼はぶどう酒を飲んで酔い、天幕の中で裸になっていた。', es:'Y bebió del vino, y embriagóse, y estaba descubierto en medio de su tienda.' },
        { v:22, ko:'가나안의 아버지 함이 그 아버지의 하체를 보고 밖으로 나가서 두 형제에게 고하매', en:'And Ham, the father of Canaan, saw the nakedness of his father, and told his two brethren without.', zh:'迦南的父亲含见了他父亲赤身，就到外边告诉他两个弟兄。', ru:'И увидел Хам, отец Ханаана, наготу отца своего, и выйдя, рассказал двум братьям своим.', ja:'カナンの父ハムは父の裸を見て、外にいた二人の兄弟に話した。', es:'Y Cam, padre de Canaán, vio la desnudez de su padre, y lo dijo a sus dos hermanos que estaban afuera.' },
        { v:23, ko:'셈과 야벳이 옷을 취하여 자기들의 어깨에 메고 뒷걸음쳐 들어가서 아버지의 하체에 덮었으며 그들이 얼굴을 돌이키고 아버지의 하체를 보지 아니하였더라', en:'And Shem and Japheth took a garment, and laid it upon both their shoulders, and went backward, and covered the nakedness of their father; and their faces were backward, and they saw not their father\'s nakedness.', zh:'于是闪和雅弗拿件衣服，搭在肩上，倒退着进去，给他们的父亲盖上；他们背着脸，不看父亲的下体。', ru:'Сим же и Иафет взяли одежду и, положив её на плечи свои, пошли задом и покрыли наготу отца своего; лица их были обращены назад, и они не видали наготы отца своего.', ja:'セムとヤペテは着物を取って自分たちの肩にかけ、後ろ向きに歩いて行き、父の裸を覆った。彼らは顔をそむけて、父の裸を見なかった。', es:'Entonces Sem y Jafet tomaron la ropa, y la pusieron sobre sus propios hombros, y andando hacia atrás, cubrieron la desnudez de su padre, teniendo vueltos sus rostros, y así no vieron la desnudez de su padre.' },
        { v:24, ko:'노아가 술이 깨어 그 작은 아들이 자기에게 행한 것을 알고', en:'And Noah awoke from his wine, and knew what his younger son had done unto him.', zh:'挪亚醒了酒，知道小儿子向他所做的事，', ru:'Ной проспался от вина своего и узнал, что сделал над ним меньший сын его.', ja:'ノアは酔いがさめて、末の息子が自分にした事を知り、', es:'Y despertó Noé de su vino, y supo lo que había hecho con él su hijo el menor.' },
        { v:25, ko:'이에 가로되 가나안은 저주를 받아 그 형제의 종들의 종이 되기를 원하노라 하고', en:'And he said, Cursed be Canaan; a servant of servants shall he be unto his brethren.', zh:'就说：「迦南当受咒诅，必给他弟兄作奴仆的奴仆。」', ru:'И сказал он: проклят Ханаан; раб рабов будет он у братьев своих.', ja:'言った、「カナンはのろわれよ。彼はその兄弟たちに奴隷の奴隷となれ。」', es:'Y dijo: Maldito sea Canaán; siervo de siervos será a sus hermanos.' },
        { v:26, ko:'또 가로되 셈의 하나님 여호와를 찬송하리로다 가나안은 셈의 종이 되고', en:'And he said, Blessed be the LORD God of Shem; and Canaan shall be his servant.', zh:'又说：「耶和华——闪的神，是应当称颂的！愿迦南作闪的奴仆。', ru:'Потом сказал: благословен Господь Бог Симов; Ханаан же будет рабом ему.', ja:'また言った、「セムの神、主はほむべきかな。カナンはセムの奴隷となれ。」', es:'Dijo más: Bendito el Señor Dios de Sem, y sea Canaán su siervo.' },
        { v:27, ko:'하나님이 야벳을 창대케 하사 셈의 장막에 거하게 하시고 가나안은 그의 종이 되게 하시기를 원하노라 하였더라', en:'God shall enlarge Japheth, and he shall dwell in the tents of Shem; and Canaan shall be his servant.', zh:'愿神使雅弗扩张，使他住在闪的帐棚里；又愿迦南作他的奴仆。」', ru:'Да распространит Бог Иафета, и да вселится он в шатрах Симовых; Ханаан же будет рабом ему.', ja:'「神がヤペテを広げ、彼がセムの天幕に住み、カナンはその奴隷となれ。」', es:'Engrandezca Dios a Jafet, y habite en las tiendas de Sem, y sea Canaán su siervo.' },
        { v:28, ko:'홍수 후에 노아가 삼백오십 년을 살았고', en:'And Noah lived after the flood three hundred and fifty years.', zh:'洪水以后，挪亚又活了三百五十年。', ru:'И жил Ной после потопа триста пятьдесят лет.', ja:'洪水の後、ノアは三百五十年生きた。', es:'Y vivió Noé después del diluvio trescientos cincuenta años.' },
        { v:29, ko:'그의 나이가 구백오십 세가 되어 죽었더라', en:'And all the days of Noah were nine hundred and fifty years: and he died.', zh:'挪亚共活了九百五十岁就死了。', ru:'Всех же дней Ноя было девятьсот пятьдесят лет, и он умер.', ja:'ノアの年は合わせて九百五十歳であった。そして彼は死んだ。', es:'Y fueron todos los días de Noé novecientos cincuenta años; y murió.' }
      ],
      10: [
        { v:1,  ko:'노아의 아들 셈과 함과 야벳의 후예는 이러하니라 홍수 후에 그들이 아들들을 낳았으니', en:'Now these are the generations of the sons of Noah, Shem, Ham, and Japheth: and unto them were sons born after the flood.', zh:'挪亚的儿子闪、含、雅弗的后代记在下面。洪水以后，他们都生了儿子。', ru:'Вот родословие сынов Ноевых: Сима, Хама и Иафета. После потопа родились у них дети.', ja:'ノアの息子たち、セム、ハム、ヤペテの系図はこうである。洪水の後、彼らに息子たちが生まれた。', es:'Estas son las generaciones de los hijos de Noé: Sem, Cam y Jafet, a los cuales nacieron hijos después del diluvio.' },
        { v:2,  ko:'야벳의 아들은 고멜과 마곡과 마대와 야완과 두발과 메섹과 디라스요', en:'The sons of Japheth; Gomer, and Magog, and Madai, and Javan, and Tubal, and Meshech, and Tiras.', zh:'雅弗的儿子是歌篾、玛各、玛代、雅完、土巴、米设、提拉斯。', ru:'Сыновья Иафета: Гомер, Магог, Мадай, Иаван, Фувал, Мешех и Фирас.', ja:'ヤペテの息子たちはゴメル、マゴグ、マダイ、ヤワン、トバル、メシェク、ティラス。', es:'Los hijos de Jafet: Gomer, y Magog, y Madai, y Javán, y Tubal, y Mesec, y Tirás.' },
        { v:3,  ko:'고멜의 아들은 아스그나스와 리밧과 도갈마요', en:'And the sons of Gomer; Ashkenaz, and Riphath, and Togarmah.', zh:'歌篾的儿子是亚实基拿、利法、도갈마。', ru:'Сыновья Гомера: Аскеназ, Рифат и Фогарма.', ja:'ゴメルの息子たちはアシュケナズ、リファト、トガルマ。', es:'Y los hijos de Gomer: Askenaz, y Rifat, y Togarma.' },
        { v:4,  ko:'야완의 아들은 엘리사와 달시스와 깃딤과 도다님이라', en:'And the sons of Javan; Elishah, and Tarshish, Kittim, and Dodanim.', zh:'雅完的儿子是以利沙、他施、基提、多单。', ru:'Сыновья Иавана: Елиса, Фарсис, Киттим и Доданим.', ja:'ヤワンの息子たちはエリシャ、タルシシュ、キティム、ドダニム。', es:'Y los hijos de Javán: Elisa, y Tarsis, Quitim, y Dodanim.' },
        { v:5,  ko:'이들로 좇아 여러 나라 백성이 나뉘어서 각기 방언과 종족과 나라대로 바닷가의 땅에 머물렀더라', en:'By these were the isles of the Gentiles divided in their lands; every one after his tongue, after their families, in their nations.', zh:'这些人的后裔将各国的地土、海岛分开居住，各随各的方言、宗族立国。', ru:'От сих населились острова народов в землях их, каждый по языку своему, по племенам своим, в народах своих.', ja:'これらから、海辺の諸国民の地に各自の言語、各自の氏族、各自の国民に分かれた。', es:'De estos fueron repartidas las islas de las gentes en sus tierras, cada uno según su lengua, conforme a sus familias en sus naciones.' },
        { v:6,  ko:'함의 아들은 구스와 미스라임과 붓과 가나안이요', en:'And the sons of Ham; Cush, and Mizraim, and Phut, and Canaan.', zh:'含的儿子是古实、麦西、弗、迦南。', ru:'Сыновья Хама: Хуш, Мицраим, Фут и Ханаан.', ja:'ハムの息子たちはクシュ、ミツライム、プト、カナン。', es:'Los hijos de Cam: Cus, y Mizraim, y Fut, y Canaán.' },
        { v:7,  ko:'구스의 아들은 스바와 하윌라와 삽다와 라아마와 삽드가요 라아마의 아들은 스바와 드단이며', en:'And the sons of Cush; Seba, and Havilah, and Sabtah, and Raamah, and Sabtecha: and the sons of Raamah; Sheba, and Dedan.', zh:'古实的儿子是西巴、哈腓拉、撒弗他、拉玛、撒弗提迦；拉玛的儿子是示巴、底但。', ru:'Сыновья Хуша: Сева, Хавила, Савта, Раама и Савтеха. Сыновья Раамы: Шева и Дедан.', ja:'クシュの息子たちはセバ、ハウィラ、サブタ、ラアマ、サブテカ。ラアマの息子たちはシェバ、デダン。', es:'Y los hijos de Cus: Seba, y Havila, y Sabta, y Raama, y Sabteca; y los hijos de Raama: Seba, y Dedán.' },
        { v:8,  ko:'구스가 또 니므롯을 낳았으니 그는 세상에 처음 영걸이라', en:'And Cush begat Nimrod: he began to be a mighty one in the earth.', zh:'古实又生了宁录，他为世上英雄之首。', ru:'Хуш родил также Нимрода; сей начал быть силён на земле.', ja:'クシュはニムロドをもうけた。彼は地の上で初めて英雄となった。', es:'Y Cus engendró a Nimrod; éste llegó a ser el primero que fue poderoso en la tierra.' },
        { v:9,  ko:'그가 여호와 앞에서 특이한 사냥꾼이 되었으므로 속담에 이르기를 아무는 여호와 앞에 니므롯같이 특이한 사냥꾼이로다 하더라', en:'He was a mighty hunter before the LORD: wherefore it is said, Even as Nimrod the mighty hunter before the LORD.', zh:'他在耶和华面前是个英勇的猎户，所以俗语说：像宁录在耶和华面前是个英勇的猎户。', ru:'Он был сильный зверолов пред Господом, потому и говорится: сильный зверолов, как Нимрод, пред Господом.', ja:'彼は主の前に力ある狩人であった。それゆえ「主の前にニムロドのような力ある狩人」ということわざが生まれた。', es:'Este fue vigoroso cazador delante de Jehová; por lo cual se dice: Así como Nimrod, vigoroso cazador delante de Jehová.' },
        { v:10, ko:'그의 나라는 시날 땅의 바벨과 에렉과 악갓과 갈레에서 시작하였으며', en:'And the beginning of his kingdom was Babel, and Erech, and Accad, and Calneh, in the land of Shinar.', zh:'他国的起头是巴别、以力、亚甲、甲尼，都在示拿地。', ru:'Царство его вначале составляли: Вавилон, Эрех, Аккад и Халне, в земле Сеннаар.', ja:'彼の王国の初めはシンアルの地のバベル、エレク、アッカド、カルネであった。', es:'Y fue la cabecera de su reino Babel, y Erec, y Acad, y Chalne, en la tierra de Sinar.' },
        { v:11, ko:'그가 그 땅에서 앗수르로 나아가 니느웨와 르호보딜과 갈라와', en:'Out of that land went forth Asshur, and builded Nineveh, and the city Rehoboth, and Calah,', zh:'他从那地出来往亚述去，建造尼尼微、利河伯、迦拉，', ru:'Из сей земли вышел Ассур и построил Ниневию, Реховоф-ир, Калах,', ja:'その地からアッシュルが出て、ニネベ、レホボテ・イル、カラフ、', es:'De aquella tierra salió Assur, y edificó a Nínive, y a Rehobot-Ir, y a Cálah,' },
        { v:12, ko:'니느웨와 갈라 사이의 레센을 건축하였으니 이는 큰 성이라', en:'And Resen between Nineveh and Calah: the same is a great city.', zh:'并尼尼微、迦拉中间的利鲜——这是那大城。', ru:'и Ресен между Ниневиею и между Калахом; это город великий.', ja:'ニネベとカラフの間のレセンを建てた。それは大きな町である。', es:'Y a Resén entre Nínive y Cálah; ésta es ciudad grande.' },
        { v:13, ko:'미스라임은 루딤과 아나밈과 르하빔과 납두힘과', en:'And Mizraim begat Ludim, and Anamim, and Lehabim, and Naphtuhim,', zh:'麦西生路低人、亚拿米人、利哈比人、拿弗土希人、', ru:'Мицраим родил Лудима, Анамима, Легавима, Нафтухима,', ja:'ミツライムはルドびと、アナムびと、レハブびと、ナフトフびと、', es:'Y Mizraim engendró a Ludim, y a Anamim, y a Lehabim, y a Neftuim,' },
        { v:14, ko:'바드루심과 가슬루힘 곧 블레셋이 나온 바와 갑도림을 낳았더라', en:'And Pathrusim, and Casluhim, (out of whom came Philistim,) and Caphtorim.', zh:'帕斯鲁细人、迦斯路希人（非利士人从那里出来），和迦斐托人。', ru:'Патрусима, Каслухима — откуда вышли Филистимляне — и Кафторима.', ja:'パトルスびと、カスルフびと（ここからペリシテびとが出た）、カフトルびとをもうけた。', es:'Y a Patrusim, y a Casluhim, de donde salieron los filisteos, y a Caftorim.' },
        { v:15, ko:'가나안은 장자 시돈과 헷을 낳고', en:'And Canaan begat Sidon his firstborn, and Heth,', zh:'迦南生长子西顿，又生赫，', ru:'Ханаан родил Сидона, первенца своего, Хета,', ja:'カナンはその長子シドン、ヘト、', es:'Y Canaán engendró a Sidón su primogénito, y a Het,' },
        { v:16, ko:'또 여부스 족속과 아모리 족속과 기르가스 족속과', en:'And the Jebusite, and the Amorite, and the Girgasite,', zh:'以及耶布斯人、亚摩利人、基r갈人、', ru:'Иевусея, Аморрея, Гергесея,', ja:'エブスびと、アモリびと、ギルガシびと、', es:'Y al jebuseo, y al amorreo, y al gergeseo,' },
        { v:17, ko:'히위 족속과 알가 족속과 신 족속과', en:'And the Hivite, and the Arkite, and the Sinite,', zh:'希未人、亚基人、西尼人、', ru:'Хивея, Арукея, Асинея,', ja:'ヒビびと、アルキびと、シニびと、', es:'Y al heveo, y al araqueo, y al sineo,' },
        { v:18, ko:'아르왓 족속과 스말 족속과 하맛 족속을 낳았고 이 후로 가나안 자손의 족속이 흩어졌더라', en:'And the Arvadite, and the Zemarite, and the Hamathite: and afterward were the families of the Canaanites spread abroad.', zh:'亚瓦底人、洗玛利人、哈马人。后来迦南各族分散了。', ru:'Арвадея, Цемарея и Химафея. Впоследствии племена Ханаанские рассеялись.', ja:'アルワドびと、ツェマリびと、ハマトびとをもうけた。その後カナンびとの氏族は散らばった。', es:'Y al arvadeo, y al zemareo, y al hamateo; y después se dispersaron las familias de los cananeos.' },
        { v:19, ko:'가나안의 경계는 시돈에서부터 그랄을 지나 가사까지와 소돔과 고모라와 아드마와 스보임을 지나 라사까지였더라', en:'And the border of the Canaanites was from Sidon, as thou comest to Gerar, unto Gaza; as thou goest, unto Sodom, and Gomorrah, and Admah, and Zeboim, even unto Lasha.', zh:'迦南的境界是从西顿向基拉耳，直到迦萨，又向所多玛、蛾摩拉、押玛、洗扁，直到拉沙。', ru:'И были пределы Хананеев от Сидона к Герару до Газы, отсюда к Содому, Гоморре, Адме и Цевоиму до Лаши.', ja:'カナンびとの領域はシドンからゲラルを経てガザに至り、ソドム、ゴモラ、アドマ、ツェボイムを経てラシャに至る。', es:'Y fue el término de los cananeos desde Sidón, en dirección a Gerar, hasta Gaza; y en dirección de Sodoma, y Gomorra, y Adma, y Zeboim, hasta Lasa.' },
        { v:20, ko:'이들은 함의 자손이라 각기 족속과 방언과 지방과 나라대로였더라', en:'These are the sons of Ham, after their families, after their tongues, in their countries, and in their nations.', zh:'这些都是含的子孙，各随他们的宗族、方言，所住的地土、邦国。', ru:'Это сыновья Хамовы, по племенам их, по языкам их, в землях их, в народах их.', ja:'これらはハムの息子たちで、それぞれその氏族、言語、地方、国民に分かれた。', es:'Estos son los hijos de Cam por sus familias, por sus lenguas, en sus tierras, en sus naciones.' },
        { v:21, ko:'셈은 에벨 온 자손의 조상이요 야벳의 형이라 그에게도 자녀가 출생하였으니', en:'Unto Shem also, the father of all the children of Eber, the brother of Japheth the elder, even to him were children born.', zh:'雅弗的哥哥闪，是希伯所有子孙的祖宗，他也生了儿子。', ru:'Были дети и у Сима, отца всех сынов Еверовых, старшего брата Иафетова.', ja:'セムにも子が生まれた。セムはエベルの全子孫の先祖で、ヤペテの兄であった。', es:'También a Sem, padre de todos los hijos de Heber, hermano mayor de Jafet, le nacieron hijos.' },
        { v:22, ko:'셈의 아들은 엘람과 앗수르와 아르박삿과 룻과 아람이요', en:'The children of Shem; Elam, and Asshur, and Arphaxad, and Lud, and Aram.', zh:'闪的儿子是以拦、亚述、亚法撒、路德、亚兰。', ru:'Сыновья Сима: Елам, Ассур, Арфаксад, Луд, Арам.', ja:'セムの息子たちはエラム、アッシュル、アルパクシャド、ルド、アラム。', es:'Los hijos de Sem: Elam, y Assur, y Arfaxad, y Lud, y Aram.' },
        { v:23, ko:'아람의 아들은 우스와 훌과 게델과 마스며', en:'And the children of Aram; Uz, and Hul, and Gether, and Mash.', zh:'亚兰的儿子是乌斯、户勒、基帖、玛施。', ru:'Сыновья Арама: Уц, Хул, Гефер и Маш.', ja:'アラムの息子たちはウツ、フル、ゲテル、マシュ。', es:'Y los hijos de Aram: Uz, y Hul, y Geter, y Mas.' },
        { v:24, ko:'아르박삿은 셀라를 낳고 셀라는 에벨을 낳았으며', en:'And Arphaxad begat Salah; and Salah begat Eber.', zh:'亚法撒生沙拉，沙拉生希伯。', ru:'Арфаксад родил Салу, Сала родил Евера.', ja:'アルパクシャドはシェラをもうけ、シェラはエベルをもうけた。', es:'Y Arfaxad engendró a Sala, y Sala engendró a Heber.' },
        { v:25, ko:'에벨은 두 아들을 낳고 하나의 이름을 벨렉이라 하였으니 그 때에 세상이 나뉘었음이요 벨렉의 아우의 이름은 욕단이며', en:'And unto Eber were born two sons: the name of one was Peleg; for in his days was the earth divided; and his brother\'s name was Joktan.', zh:'希伯生了两个儿子：一个名叫法勒，因为那时人就分地居住；法勒的兄弟名叫约坍。', ru:'У Евера родились два сына; имя одному Фалек, потому что в дни его земля разделена; а брату его имя Иоктан.', ja:'エベルに二人の息子が生まれた。一人の名はペレグといった。その時代に地が分けられたからである。その兄弟の名はヨクタンといった。', es:'Y a Heber le nacieron dos hijos; el nombre del uno fue Peleg, por cuanto en sus días fue repartida la tierra; y el nombre de su hermano, Joctán.' },
        { v:26, ko:'욕단은 알모닷과 셀렙과 하살마웻과 예라와', en:'And Joktan begat Almodad, and Sheleph, and Hazarmaveth, and Jerah,', zh:'约坍生亚摩答、沙列、哈萨玛非、耶拉、', ru:'Иоктан родил Алмодада, Шалефа, Хацармавефа, Иераха,', ja:'ヨクタンはアルモダド、シェレフ、ハツァルマウェト、ヤラフ、', es:'Y Joctán engendró a Almodad, y a Selef, y a Hazarmavet, y a Jera,' },
        { v:27, ko:'하도람과 우살과 디글라와', en:'And Hadoram, and Uzal, and Diklah,', zh:'哈多兰、乌撒、德拉，', ru:'Гадорама, Узала, Диклу,', ja:'ハドラム、ウザル、ディクラ、', es:'Y a Adoram, y a Uzal, y a Dicla,' },
        { v:28, ko:'오발과 아비마엘과 스바와', en:'And Obal, and Abimael, and Sheba,', zh:'俄巴、亚比玛利、示巴、', ru:'Овала, Авимаила, Шеву,', ja:'オバル、アビマエル、シェバ、', es:'Y a Obal, y a Abimael, y a Seba,' },
        { v:29, ko:'오빌과 하윌라와 요밥을 낳았으니 이들은 다 욕단의 아들이며', en:'And Ophir, and Havilah, and Jobab: all these were the sons of Joktan.', zh:'阿斐拉、哈腓拉、约巴；这些都是约坍的儿子。', ru:'Офира, Евилу и Иовава; все эти сыновья Иоктана.', ja:'オフィル、ハウィラ、ヨバブ。これらはみなヨクタンの息子たちであった。', es:'Y a Ofir, y a Havila, y a Jobab; todos estos son hijos de Joctán.' },
        { v:30, ko:'그들의 거하는 곳은 메사에서부터 스발로 가는 길의 동편 산이었더라', en:'And their dwelling was from Mesha, as thou goest unto Sephar a mount of the east.', zh:'他们居住的地方是从米沙直到西发东边的山。', ru:'Поселения их были от Меши до Сефара, горы восточной.', ja:'彼らの住む地はメシャからセファルへ行く途中、東の山地であった。', es:'Y la habitación de ellos fue desde Mesa, en dirección de Sefar, hasta la montaña de oriente.' },
        { v:31, ko:'이들은 셈의 자손이라 그 족속과 방언과 지방과 나라대로였더라', en:'These are the sons of Shem, after their families, after their tongues, in their lands, after their nations.', zh:'这些都是闪的子孙，各随他们的宗族、方言，所住的地土、邦国。', ru:'Это сыновья Симовы по племенам их, по языкам их, в землях их, по народам их.', ja:'これらはセムの息子たちで、それぞれその氏族、言語、地方、国民に分かれた。', es:'Estos son los hijos de Sem por sus familias, por sus lenguas, en sus tierras, en sus naciones.' },
        { v:32, ko:'이들은 노아 자손의 족속들이요 그 세계와 나라대로라 홍수 후에 이들에게서 땅의 열국 백성이 나뉘었더라', en:'These are the families of the sons of Noah, after their generations, in their nations: and by these were the nations divided in the earth after the flood.', zh:'这些都是挪亚儿子各族的宗谱，各随他们的支派立国。洪水以后，各国的民从这些人分出来，散居各地。', ru:'Вот племена сынов Ноевых, по родословию их, в народах их. От них распространились народы по земле после потопа.', ja:'これらはノアの息子たちの氏族で、その系図と国民に分かれた。洪水の後、これらから諸国民が地に広まった。', es:'Estas son las familias de los hijos de Noé por sus generaciones, en sus naciones; y de éstos se apartaron las naciones en la tierra después del diluvio.' }
      ]
    }
  },
  EXO: {
    name: { ko: '출애굽기', en: 'Exodus', zh: '出埃及记', ru: 'Исход', ja: '出エジプト記', es: 'Éxodo' },
    chapters: {
      1: [
        { v:1,  ko:'야곱과 함께 각기 권속을 데리고 애굽에 이른 이스라엘 아들들의 이름은 이러하니', en:'Now these are the names of the children of Israel, which came into Egypt; every man and his household came with Jacob.', zh:'以色列的众子，各带家眷，和雅各一同来到埃及。他们的名字记在下面。', ru:'Вот имена сынов Израилевых, которые вошли в Египет с Иаковом, вошли каждый с домом своим:', ja:'さて、ヤコブと共に、おのおのその家族を連れてエジプトへ行ったイスラエルの子たちの名は次のとおりである。', es:'Estos son los nombres de los hijos de Israel que entraron en Egipto con Jacob; cada uno entró con su familia.' },
        { v:2,  ko:'르우벤과 시므온과 레위와 유다와', en:'Reuben, Simeon, Levi, and Judah,', zh:'吕便、西缅、利未、犹大、', ru:'Рувим, Симеон, Левий и Иуда,', ja:'ルベン、シメオン、レビ、ユダ、', es:'Rubén, Simeón, Leví y Judá;' },
        { v:3,  ko:'잇사갈과 스불론과 베냐민과', en:'Issachar, Zebulun, and Benjamin,', zh:'以萨迦、西布伦、便雅悯、', ru:'Иссахар, Завулон и Вениамин,', ja:'イッサカル、ゼブルン、ベニヤミン、', es:'Isacar, Zabulón y Benjamín;' },
        { v:4,  ko:'단과 납달리와 갓과 아셀이요', en:'Dan, and Naphtali, Gad, and Asher.', zh:'但、拿弗他利、迦得、亚设。', ru:'Дан и Неффалим, Гад и Асир.', ja:'ダン、ナフタリ、ガド、アセルであった。', es:'Dan, Neftalí, Gad y Aser.' },
        { v:5,  ko:'이미 애굽에 있는 요셉까지 야곱의 혈속이 모두 칠십 인이었더라', en:'And all the souls that came out of the loins of Jacob were seventy souls: for Joseph was in Egypt already.', zh:'凡从雅各而生的，共有七十人。约瑟已经在埃及。', ru:'Всех же душ, происшедших от чресл Иакова, было семьдесят, а Иосиф был уже в Египте.', ja:'ヤコブの腰から出たものは、合わせて七十人。ヨセフはすでにエジプトにいた。', es:'Y todas las almas de los que salieron del muslo de Jacob, fueron setenta almas; y José estaba en Egipto.' },
        { v:6,  ko:'요셉과 그의 모든 형제와 그 시대 사람은 다 죽었고', en:'And Joseph died, and all his brethren, and all that generation.', zh:'约瑟和他的弟兄，并那一代的人，都死了。', ru:'И умер Иосиф и все братья его и весь род их;', ja:'そして、ヨセフもその兄弟たちも、またそのすべての時代の人々も死んだ。', es:'Y murió José, y todos sus hermanos, y toda aquella generación.' },
        { v:7,  ko:'이스라엘 자손은 생육이 중다하고 번식하고 창성하고 심히 강대하여 온 땅에 가득하게 되었더라', en:'And the children of Israel were fruitful, and increased abundantly, and multiplied, and waxed exceeding mighty; and the land was filled with them.', zh:'以色列人生养众多，并且繁茂，极其强盛，满了那地。', ru:'а сыны Израилевы расплодились и размножились, и возросли и усилились чрезвычайно, и наполнилась ими земля та.', ja:'しかるに、イスラエルの子孫は多くの子を生み、ますますふえ、はなはだ強くなって、国中に満ちるようになった。', es:'Y los hijos de Israel fructificaron y se multiplicaron, y fueron aumentados y fortalecidos en extremo; y se llenó de ellos la tierra.' },
        { v:8,  ko:'요셉을 알지 못하는 새 왕이 일어나서 애굽을 다스리더니', en:'Now there arose up a new king over Egypt, which knew not Joseph.', zh:'有不认识约瑟的新王起来，治理埃及，', ru:'И восстал в Египте новый царь, который не знал Иосифа,', ja:'ここに、ヨセフのことを知らない新しい王がエジプトに起った。', es:'Entretanto se levantó un nuevo rey sobre Egipto que no conocía a José.' },
        { v:9,  ko:'그가 그 백성에게 이르되 이 백성 이스라엘 자손이 우리보다 많고 강하도다', en:'And he said unto his people, Behold, the people of the children of Israel are more and mightier than we:', zh:'对他的百姓说：「看哪，这以色列民比我们还多，又比我们强盛。', ru:'и сказал народу своему: вот, народ сынов Израилевых многочислен и сильнее нас;', ja:'彼はその民に言った、「見よ、イスラエルの子孫なる民は、われわれにとって、あまりにも多く、また強すぎる。', es:'Y dijo a su pueblo: He aquí, el pueblo de los hijos de Israel es mayor y más fuerte que nosotros.' },
        { v:10, ko:'자 우리가 그들에게 대하여 지혜롭게 하자 두렵건대 그들이 더 많게 되면 전쟁이 일어날 때에 우리 대적과 합하여 우리와 싸우고 이 땅에서 나갈까 하노라 하고', en:'Come on, let us deal wisely with them; lest they multiply, and it come to pass, that, when there falleth out any war, they join also unto our enemies, and fight against us, and so get them up out of the land.', zh:'来吧，我们不如用巧计待他们，恐怕他们多起来，日后若遇什么争战的事，就连合我们的仇敌攻击我们，离开这地去了。」', ru:'перехитрим же его, чтобы он не размножался; иначе, когда случится война, соединится и он с нашими неприятелями, и вооружится против нас, и выйдет из земли нашей.', ja:'さあ、われわれは、抜かりなく彼らを取り扱おう。彼らが多くなり、戦いの起るとき、敵に付いてわれわれと戦い、この国から出て行くことがないようにしよう」。', es:'Ahora, pues, seamos sabios para con él, para que no se multiplique, y acontezca que viniendo guerra, él también se una con nuestros enemigos y pelee contra nosotros, y se vaya de la tierra.' },
        { v:11, ko:'감독들을 그 위에 세우고 그들에게 무거운 짐을 지워 괴롭게 하여 그들로 바로를 위하여 국고성 비돔과 라암셋을 건축하게 하니라', en:'Therefore they did set over them taskmasters to afflict them with their burdens. And they built for Pharaoh treasure cities, Pithom and Raamses.', zh:'于是埃及人派督工的辖制他们，加重担苦害他们。他们为法老建造两座积货城，就是比东和兰塞。', ru:'И поставили над ним начальников работ, чтобы изнуряли его тяжкими работами. И он построил фараону Пифом и Раамсес, города для запасов.', ja:'そこでエジプトびとは彼らの上に監督をおき、重い荷をもって彼らを苦しめた。彼らはパロのために倉庫の町ピトムとラメセスとを建設した。', es:'Entonces pusieron sobre ellos comisarios de tributos que los molestasen con sus cargas; y edificaron para Faraón las ciudades de satisfacción, Pitón y Ramesés.' },
        { v:12, ko:'학대를 받을수록 더욱 번식하고 창성하니 애굽 사람이 이스라엘 자손을 인하여 근심하여', en:'But the more they afflicted them, the more they multiplied and grew. And they were grieved because of the children of Israel.', zh:'只是越发苦害他们，他们越发多起来，越发蔓延；埃及人就因以色列人愁烦。', ru:'Но чем более изнуряли его, тем более он умножался и тем более возрастал, так что опасались сынов Израилевых.', ja:'しかしイスラエルの人々が苦しめられるにしたがって、ますますふえひろがるので、彼らはイスラエルの人々のゆえに恐れをなした。', es:'Pero cuanto más los oprimían, tanto más se multiplicaban y crecían; de manera que estaban angustiados a causa de los hijos de Israel.' },
        { v:13, ko:'애굽 사람이 이스라엘 자손의 역사를 엄하게 하여', en:'And the Egyptians made the children of Israel to serve with rigour:', zh:'埃及人严严地使以色列人做工，', ru:'И потому Египтяне с жестокостью принуждали сынов Израилевых к работам', ja:'エジプトびとはイスラエルの人々をきびしく使い、', es:'Y los egipcios hicieron servir a los hijos de Israel con dureza.' },
        { v:14, ko:'그들의 생활을 괴롭게 하니 곧 흙 이기기와 벽돌 굽기와 농사의 여러 가지 일이라 그 시키는 역사가 다 엄하였더라', en:'And they made their lives bitter with hard bondage, in mortar, and in brick, and in all manner of service in the field: all their service, wherein they made them serve, was with rigour.', zh:'使他们因做苦工觉得命苦；无论是和泥、是做砖，是做田间各样的工，在一切的工上都严严地待他们。', ru:'и делали жизнь их горькою от тяжкой работы над глиною и кирпичами и от всякой работы полевой, от всякой работы, к которой принуждали их с жестокостью.', ja:'つらい務をもってその生活を苦しめた。すなわち、しっくいこね、れんが作り、および田畑のあらゆる務に当らせたが、そのすべての労役はきびしかった。', es:'Y amargaron su vida con dura servidumbre, en hacer barro y ladrillo, y en toda labor del campo, y en todo su servicio, al cual los obligaban con rigor.' },
        { v:15, ko:'애굽 왕이 히브리 산파 시브라라 하는 자와 부아라 하는 자에게 일러', en:'And the king of Egypt spake to the Hebrew midwives, of which the name of the one was Shiphrah, and the name of the other Puah:', zh:'有希伯来的两个收生婆，一名施弗拉，一名普阿；埃及王对她们说：', ru:'Царь Египетский повелел повивальным бабкам Евреянок, из коих одной имя Шифра, а другой Фуа,', ja:'またエジプトの王はヘブルの産婆たちに言った。そのひとりの名はシフラといい、他のひとりの名はプアといった。', es:'Y habló el rey de Egipto a las parteras de las hebreas, una de las cuales se llamaba Sifra, y otra Fúa, y les dijo:' },
        { v:16, ko:'가로되 너희는 히브리 여인을 위하여 해산을 도울 때에 그 자리를 살펴서 아들이거든 죽이고 딸이거든 살려두라', en:'And he said, When ye do the office of a midwife to the Hebrew women, and see them upon the stools; if it be a son, then ye shall kill him: but if it be a daughter, then she shall live.', zh:'「你们为希伯来妇人收生，看她们临盆的时候，若是男孩，就把他杀了；若是女孩，就留她存活。」', ru:'и сказал: когда вы будете повивать у Евреянок, то наблюдайте при родах: если будет сын, то умерщвляйте его, а если дочь, то пусть живёт.', ja:'彼は言った、「ヘブルの女に手をかして産ませる時、産み台の上を見て、もし男の子ならばそれを殺し、女の子ならば生かしておきなさい」。', es:'Cuando asistáis a las hebreas en sus partos, y miréis los asientos, si fuere hijo, matadlo; y si fuere hija, entonces viva.' },
        { v:17, ko:'그러나 산파들이 하나님을 두려워하여 애굽 왕의 명을 어기고 남자를 살린지라', en:'But the midwives feared God, and did not as the king of Egypt commanded them, but saved the men children alive.', zh:'但是收生婆敬畏神，不照埃及王的吩咐行，竟存留男孩的性命。', ru:'Но повивальные бабки боялись Бога и не делали так, как говорил им царь Египетский, и оставляли детей в живых.', ja:'しかし産婆たちは神をおそれ、エジプトの王が彼らに命じたようにはせず、男の子を生かしておいた。', es:'Pero las parteras temieron a Dios, y no hicieron como les mandó el rey de Egipto, sino que reservaban la vida a los niños.' },
        { v:18, ko:'애굽 왕이 산파를 불러서 이르되 너희가 어찌 이같이 하여 남자를 살렸느냐', en:'And the king of Egypt called for the midwives, and said unto them, Why have ye done this thing, and have saved the men children alive?', zh:'埃及王召了收生婆来，说：「你们为什么做这事，存留男孩的性命？」', ru:'Царь Египетский призвал повивальных бабок и сказал им: для чего вы делаете такое дело, что оставляете детей в живых?', ja:'エジプトの王は産婆たちを召して言った、「あなたがたはなぜこのようなことをして、男の子を生かしておいたのか」。', es:'Y el rey de Egipto hizo llamar a las parteras y les dijo: ¿Por qué habéis hecho esto, que habéis reservado la vida a los niños?' },
        { v:19, ko:'산파가 바로에게 대답하되 히브리 여인은 애굽 여인과 같지 아니하여 건장하므로 산파가 그들에게 이르기 전에 해산하였더이다 하매', en:'And the midwives said unto Pharaoh, Because the Hebrew women are not as the Egyptian women; for they are lively, and are delivered ere the midwives come in unto them.', zh:'收生婆对法老说：「因为希伯来妇人与埃及妇人不同；希伯来妇人本是健壮的，收生婆还没有到，她们已经生产了。」', ru:'Повивальные бабки сказали фараону: Еврейские женщины не так, как Египетские; они здоровы, и прежде нежели придёт к ним повивальная бабка, уже рождают.', ja:'産婆たちはパロに言った、「ヘブルの女はエジプトの女とは違い、彼女たちは元気で産婆がまだ来ないうちに産んでしまいます」。', es:'Y las parteras respondieron a Faraón: Porque las mujeres hebreas no son como las egipcias; pues son robustas, y dan a luz antes que la partera venga a ellas.' },
        { v:20, ko:'하나님이 그 산파들에게 은혜를 베푸시니라 백성은 번식하고 심히 강대하여 졌으며', en:'Therefore God dealt well with the midwives: and the people multiplied, and waxed very mighty.', zh:'神厚待收生婆。以色列人多起来，极其强盛。', ru:'За сие Бог делал добро повивальным бабкам, а народ умножался и весьма усиливался.', ja:'それで神は産婆たちに恵みをほどこされた。そして民はふえ、非常に強くなった。', es:'Y Dios hizo bien a las parteras; y el pueblo se multiplicó, y se fortaleció en gran manera.' },
        { v:21, ko:'산파는 하나님을 두려워하였으므로 하나님이 그들의 집을 왕성케 하셨더라', en:'And it came to pass, because the midwives feared God, that he made them houses.', zh:'收生婆因为敬畏神，神便叫她们成立家室。', ru:'И так как повивальные бабки боялись Бога, то Он устроял домы их.', ja:'産婆たちは神をおそれたので、神は彼女たちの家を栄えさせられた。', es:'Y por haber las parteras temido a Dios, él les hizo casas.' },
        { v:22, ko:'그러므로 바로가 그 모든 백성에게 명하여 가로되 남자가 나거든 너희는 그를 하수에 던지고 여자여든 살려두라 하였더라', en:'And Pharaoh charged all his people, saying, Every son that is born ye shall cast into the river, and every daughter ye shall save alive.', zh:'法老吩咐他的众民说：「以色列人所生的男孩，你们都要丢在河里；一切的女孩，你们要存留她的性命。」', ru:'Тогда фараон всему народу своему повелел, говоря: всякого новорождённого у Евреев сына бросайте в реку, а всякую дочь оставляйте в живых.', ja:'そこでパロはそのすべての民に命じて言った、「ヘブルびとに男の子が生まれたならば、みなナイル川に投げこめ。しかし女の子はみな生かしておけ」。', es:'Entonces Faraón mandó a todo su pueblo, diciendo: Echad en el río todo hijo que naciere, y a toda hija satisfaced.' }
      ]
    }
  },
  JHN: {
    name: { ko: '요한복음', en: 'John', zh: '约翰福音', ru: 'Евангелие от Иоанна', ja: 'ヨハネの福音書', es: 'Juan' },
    chapters: {
      1: [
        { v:1,  ko:'태초에 말씀이 계시니라 이 말씀이 하나님과 함께 계셨으니 이 말씀은 곧 하나님이시니라', en:'In the beginning was the Word, and the Word was with God, and the Word was God.', zh:'太初有道，道与神同在，道就是神。', ru:'В начале было Слово, и Слово было у Бога, и Слово было Бог.', ja:'初めに言があった。言は神と共にあった。言は神であった。', es:'En el principio era el Verbo, y el Verbo era con Dios, y el Verbo era Dios.' },
        { v:2,  ko:'그가 태초에 하나님과 함께 계셨고', en:'The same was in the beginning with God.', zh:'这道太初与神同在。', ru:'Оно было в начале у Бога.', ja:'この言は初めに神と共にあった。', es:'Este era en el principio con Dios.' },
        { v:3,  ko:'만물이 그로 말미암아 지은 바 되었으니 지은 것이 하나도 그가 없이는 된 것이 없느니라', en:'All things were made by him; and without him was not any thing made that was made.', zh:'万物是借着他造的；凡被造的，没有一样不是借着他造的。', ru:'Всё чрез Него начало быть, и без Него ничто не начало быть, что начало быть.', ja:'すべてのものは、これによってできた。できたもののうち、一つとしてこれによらないものはなかった。', es:'Todas las cosas por él fueron hechas; y sin él, nada de lo que es hecho, fue hecho.' },
        { v:4,  ko:'그 안에 생명이 있었으니 이 생명은 사람들의 빛이라', en:'In him was life; and the life was the light of men.', zh:'在他里头有生命，这生命就是人的光。', ru:'В Нём была жизнь, и жизнь была свет человеков.', ja:'この言の中に命があった。そしてこの命は人の光であった。', es:'En él estaba la vida, y la vida era la luz de los hombres.' },
        { v:5,  ko:'빛이 어두움에 비취되 어두움이 깨닫지 못하더라', en:'And the light shineth in darkness; and the darkness comprehended it not.', zh:'光照在黑暗里，黑暗却不接受光。', ru:'И свет во тьме светит, и тьма не объяла его.', ja:'光は暗やみの中に輝いている。そして、暗やみはこれに勝たなかった。', es:'Y la luz en las tinieblas resplandece; mas las tinieblas no la comprendieron.' },
        { v:6,  ko:'하나님께로서 보내심을 받은 사람이 났으니 이름은 요한이라', en:'There was a man sent from God, whose name was John.', zh:'有一个人，是从神那里差来的，名叫约翰。', ru:'Был человек, посланный от Бога; имя ему Иоанн.', ja:'神から遣わされたヨハネという人が現れた。', es:'Hubo un hombre enviado de Dios, el cual se llamaba Juan.' },
        { v:7,  ko:'저가 증거하러 왔으니 곧 빛에 대하여 증거하고 모든 사람으로 자기를 인하여 믿게 하려 함이라', en:'The same came for a witness, to bear witness of the Light, that all men through him might believe.', zh:'这人来，为要作见证，就是为光作见证，叫众人因他可以信。', ru:'Он пришёл для свидетельства, чтобы свидетельствовать о Свете, дабы все уверовали чрез него.', ja:'彼は証しのためにきた。光について証しをして、彼によってすべての人が信じるためである。', es:'Este vino por testimonio, para que diese testimonio de la luz, para que todos creyesen por él.' },
        { v:8,  ko:'그는 이 빛이 아니요 이 빛에 대하여 증거하러 온 자라', en:'He was not that Light, but was sent to bear witness of that Light.', zh:'他不是那光，乃是要为光作见证。', ru:'Он не был свет, но был послан, чтобы свидетельствовать о Свете.', ja:'彼は光ではなく、光についての証しのためにきたのである。', es:'No era él la luz, sino para que diese testimonio de la luz.' },
        { v:9,  ko:'참 빛 곧 세상에 와서 각 사람에게 비취는 빛이 있었나니', en:'That was the true Light, which lighteth every man that cometh into the world.', zh:'那光是真光，照亮一切生在世上的人。', ru:'Был Свет истинный, Который просвещает всякого человека, приходящего в мир.', ja:'すべての人を照すまことの光があって、世にきた。', es:'Aquella luz verdadera era la que alumbra a todo hombre que viene a este mundo.' },
        { v:10, ko:'그가 세상에 계셨으며 세상은 그로 말미암아 지은 바 되었으되 세상이 그를 알지 못하였고', en:'He was in the world, and the world was made by him, and the world knew him not.', zh:'他在世界，世界也是借着他造的，世界却不认识他。', ru:'В мире был, и мир чрез Него начал быть, и мир Его не познал.', ja:'彼は世にいた。そして世は彼によってできたのであるが、世は彼を知らなかった。', es:'En el mundo estaba, y el mundo fue hecho por él; pero el mundo no le conoció.' },
        { v:11, ko:'자기 땅에 오매 자기 백성이 영접지 아니하였으나', en:'He came unto his own, and his own received him not.', zh:'他到自己的地方来，自己的人倒不接待他。', ru:'Пришёл к своим, и свои Его не приняли.', ja:'彼は自分のところにきたのに、自分の民は彼を受けいれなかった。', es:'A lo suyo vino, y los suyos no le recibieron.' },
        { v:12, ko:'영접하는 자 곧 그 이름을 믿는 자들에게는 하나님의 자녀가 되는 권세를 주셨으니', en:'But as many as received him, to them gave he power to become the sons of God, even to them that believe on his name:', zh:'凡接待他的，就是信他名的人，他就赐他们权柄，作神的儿女。', ru:'А тем, которые приняли Его, верующим во имя Его, дал власть быть чадами Божиими,', ja:'しかし、彼を受けいれた人々、すなわち、その名を信じた人々には、彼は神の子となる力を与えた。', es:'Mas a todos los que le recibieron, dióles potestad de ser hechos hijos de Dios, a los que creen en su nombre;' },
        { v:13, ko:'이는 혈통으로나 육정으로나 사람의 뜻으로 나지 아니하고 오직 하나님께로서 난 자들이니라', en:'Which were born, not of blood, nor of the will of the flesh, nor of the will of man, but of God.', zh:'这等人不是从血气生的，不是从情欲生的，也不是从人意生的，乃是从神生的。', ru:'которые ни от крови, ни от хотения плоти, ни от хотения мужа, но от Бога родились.', ja:'これらの人は、血によらず、肉の欲によらず、人の欲によらず、ただ神によって生れたのである。', es:'Los cuales no son engendrados de sangre, ni de voluntad de carne, ni de voluntad de varón, sino de Dios.' },
        { v:14, ko:'말씀이 육신이 되어 우리 가운데 거하시매 우리가 그 영광을 보니 아버지의 독생자의 영광이요 은혜와 진리가 충만하더라', en:'And the Word was made flesh, and dwelt among us, (and we beheld his glory, the glory as of the only begotten of the Father,) full of grace and truth.', zh:'道成了肉身，住在我们中间，充充满满地有恩典，有真理。我们也见过他的荣光，正是父独生子的荣光。', ru:'И Слово стало плотию, и обитало с нами, полное благодати и истины; и мы видели славу Его, славу, как Единородного от Отца.', ja:'そして言は肉体となり、わたしたちのうちに宿った。わたしたちはその栄光を見た。それは父のひとり子としての栄光であって、めぐみとまこととに満ちていた。', es:'Y el Verbo se hizo carne, y habitó entre nosotros, y vimos su gloria, gloria como del unigénito del Padre, lleno de gracia y de verdad.' },
        { v:15, ko:'요한이 그에 대하여 증거하여 외쳐 가로되 내가 전에 말하기를 내 뒤에 오시는 이가 나보다 앞선 것은 나보다 먼저 계심이라 한 것이 이 사람을 가리킴이라 하니라', en:'John bare witness of him, and cried, saying, This was he of whom I spake, He that cometh after me is preferred before me: for he was before me.', zh:'约翰为他作见证，喊着说：「这就是我曾说，那在我以后来的，反成了在我以前的，因他本来在我以前。」', ru:'Иоанн свидетельствует о Нём и, восклицая, говорит: Сей был Тот, о Котором я сказал, что Идущий за мною стал впереди меня, потому что был прежде меня.', ja:'ヨハネは彼についての証しをして叫んだ。「わたしの後にきたる者は、わたしよりも優れたかたである。わたしよりも先におられたからである」と述べたのは、この方のことである。', es:'Juan dio testimonio de él, y clamó diciendo: Este es de quien yo decía: El que viene después de mí, es antes de mí; porque era primero que yo.' },
        { v:16, ko:'우리가 다 그의 충만한 데서 받으니 은혜 위에 은혜러라', en:'And of his fulness have all we received, and grace for grace.', zh:'从他丰满的恩典里，我们都领受了，而且恩上加恩。', ru:'И от полноты Его все мы приняли и благодать на благодать,', ja:'わたしたちはみな、その満ち満ちた恵みの中から、恵みに恵みを受けた。', es:'Y de su plenitud tomamos todos, y gracia sobre gracia.' },
        { v:17, ko:'율법은 모세로 말미암아 주어진 것이요 은혜와 진리는 예수 그리스도로 말미암아 온 것이라', en:'For the law was given by Moses, but grace and truth came by Jesus Christ.', zh:'律法本是借着摩西传的；恩典和真理都是由耶稣基督来的。', ru:'ибо закон дан чрез Моисея; благодать же и истина произошли чрез Иисуса Христа.', ja:'律法はモーセをとおして与えられ、めぐみとまこととは、イエス・キリストをとおしてきた。', es:'Porque la ley por Moisés fue dada; mas la gracia y la verdad por Jesucristo vino.' },
        { v:18, ko:'본래 하나님을 본 사람이 없으되 아버지 품 속에 있는 독생하신 하나님이 나타내셨느니라', en:'No man hath seen God at any time; the only begotten Son, which is in the bosom of the Father, he hath declared him.', zh:'从来没有人看见神，只有在父怀里的独生子将他表明出来。', ru:'Бога не видел никто никогда; Единородный Сын, сущий в недре Отчем, Он явил.', ja:'神を見た者はいまだかつてない。ただ父のふところにいるひとり子なる神だけが、神をあらわしたのである。', es:'A Dios nadie le vió jamás; el unigénito Hijo, que está en el seno del Padre, él le ha dado a conocer.' },
        { v:19, ko:'유대인들이 예루살렘에서 제사장들과 레위인들을 요한에게 보내어 네가 누구냐 물을 때에 요한의 증거가 이러하니라', en:'And this is the record of John, when the Jews sent priests and Levites from Jerusalem to ask him, Who art thou?', zh:'约翰所作的见证记在下面：犹太人从耶路撒冷差祭司和利未人到约翰那里，问他说：「你是谁？」', ru:'И вот свидетельство Иоанна, когда Иудеи прислали из Иерусалима священников и левитов спросить его: кто ты?', ja:'ユダヤ人たちがエルサレムから祭司たちやレビ人たちをヨハネのもとに遣わして、「あなたはだれですか」と尋ねさせたとき、ヨハネの証しはこうであった。', es:'Y este es el testimonio de Juan, cuando los Judíos enviaron de Jerusalén sacerdotes y Levitas para que le preguntasen: ¿Tú, quién eres?' },
        { v:20, ko:'요한이 드러내어 말하고 숨기지 아니하니 드러내어 하는 말이 나는 그리스도가 아니라 한대', en:'And he confessed, and denied not; but confessed, I am not the Christ.', zh:'他就明说，并不隐瞒，明说：「我不是基督。」', ru:'Он объявил, и не отрёкся, и объявил, что я не Христос.', ja:'彼は言い張って否まず、打ち明けて「わたしはキリストではない」と言い切った。', es:'Y confesó, y no negó; y confesó: Yo no soy el Cristo.' },
        { v:21, ko:'또 묻되 그러면 무엇이냐 네가 엘리야냐 가로되 나는 아니라 또 묻되 네가 그 선지자냐 대답하되 아니라', en:'And they asked him, What then? Art thou Elias? And he saith, I am not. Art thou that prophet? And he answered, No.', zh:'他们又问他说：「这样，你是以利亚吗？」他说：「我不是。」「你是那先知吗？」他回答说：「不是。」', ru:'Они спросили его: что же? ты Илия? Он сказал: нет. Пророк? Он отвечал: нет.', ja:'そこで彼らは問うた、「では、あなたはどなたですか。エリヤですか」。彼は「そうではない」と言った。「あなたはあの預言者ですか」。彼は「いいえ」と答えた。', es:'Y le preguntaron: ¿Qué pues? ¿Eres tú Elías? Dijo: No soy. ¿Eres tú el profeta? Y respondió: No.' },
        { v:22, ko:'또 가로되 누구냐 우리를 보낸 이들에게 대답하게 하라 너는 네게 대하여 무엇이라 하느냐', en:'Then said they unto him, Who art thou? that we may give an answer to them that sent us. What sayest thou of thyself?', zh:'于是他们说：「你到底是谁？叫我们好回复差我们来的人。你自己说，你是谁？」', ru:'Сказали ему: кто же ты? чтобы нам дать ответ пославшим нас: что ты скажешь о себе самом?', ja:'そこで彼らは言った、「あなたはだれですか。わたしたちを遣わした人たちに答えを持って行けるように、自分でなんだと言うのですか」。', es:'Le dijeron: ¿Pues quién eres? para que demos respuesta a los que nos enviaron. ¿Qué dices de ti mismo?' },
        { v:23, ko:'가로되 나는 선지자 이사야의 말과 같이 주의 길을 곧게 하라고 광야에서 외치는 자의 소리로라 하니라', en:'He said, I am the voice of one crying in the wilderness, Make straight the way of the Lord, as said the prophet Esaias.', zh:'他说：「我就是那在旷野有人声喊着说，修直主的道路，正如先知以赛亚所说的。」', ru:'Он сказал: я глас вопиющего в пустыне: исправьте путь Господу, как сказал пророк Исаия.', ja:'彼は言った、「わたしは、預言者イザヤが言ったように、『主の道をまっすぐにせよ』と荒野で叫んでいる者の声である」。', es:'Dijo: Yo soy la voz de uno que clama en el desierto: Enderezad el camino del Señor, como dijo el profeta Isaías.' },
        { v:24, ko:'저희는 바리새인들에게서 보낸 자라', en:'And they which were sent were of the Pharisees.', zh:'那些人是法利赛人差来的。', ru:'А посланные были из фарисеев.', ja:'遣わされた人たちはパリサイ人たちの中からきた者であった。', es:'Y los que habían sido enviados eran de los Fariseos.' },
        { v:25, ko:'또 물어 가로되 네가 만일 그리스도도 아니요 엘리야도 아니요 그 선지자도 아닐진대 어찌하여 세례를 주느냐', en:'And they asked him, and said unto him, Why baptizest thou then, if thou be not that Christ, nor Elias, neither that prophet?', zh:'他们又问他说：「你若不是基督，不是以利亚，也不是那先知，为什么施洗呢？」', ru:'И они спросили его: что же ты крестишь, если ты не Христос, не Илия, не пророк?', ja:'彼らはまたヨハネに問うた、「では、なぜあなたはバプテスマを施しているのですか。あなたはキリストでも、エリヤでも、あの預言者でもないのに」。', es:'Y le preguntaron, y le dijeron: ¿Por qué pues bautizas, si tú no eres el Cristo, ni Elías, ni el profeta?' },
        { v:26, ko:'요한이 대답하되 나는 물로 세례를 주거니와 너희 가운데 너희가 알지 못하는 한 사람이 섰으니', en:'John answered them, saying, I baptize with water: but there standeth one among you, whom ye know not;', zh:'约翰回答说：「我是用水施洗，但有一位站在你们中间，是你们不认识的，', ru:'Иоанн сказал им в ответ: я крещу в воде; но стоит среди вас Некто, Которого вы не знаете.', ja:'ヨハネは答えた、「わたしは水でバプテスマを授けているが、あなたがたの中には、あなたがたの知らないかたが立っておられる。', es:'Juan les respondió, diciendo: Yo bautizo con agua; mas en medio de vosotros está uno a quien vosotros no conocéis.' },
        { v:27, ko:'곧 내 뒤에 오시는 그이라 나는 그의 신들메 풀기도 감당치 못하겠노라 하더라', en:'He it is, who coming after me is preferred before me, whose shoe\'s latchet I am not worthy to unloose.', zh:'就是在我以后来的，我给他解鞋带也不配。」', ru:'Он-то Идущий за мною, но Который стал впереди меня. Я недостоин развязать ремень у обуви Его.', ja:'それはわたしの後にきたる方で、わたしはその履物のひもを解く値うちもない」。', es:'Este es el que viene después de mí, el que es antes de mí; del cual yo no soy digno de desatar la correa del zapato.' },
        { v:28, ko:'이 일은 요한이 세례 주던 곳 요단강 건너편 베다니에서 된 일이니라', en:'These things were done in Bethabara beyond Jordan, where John was baptizing.', zh:'这是在约旦河外伯大尼，约翰施洗的地方做的事。', ru:'Это происходило в Вифании за Иорданом, где крестил Иоанн.', ja:'これはヨハネがバプテスマを授けていたヨルダンの向こう岸のベタニヤで起ったことである。', es:'Estas cosas acontecieron en Betábara, al otro lado del Jordán, donde Juan bautizaba.' },
        { v:29, ko:'이튿날 요한이 예수께서 자기에게 나아오심을 보고 가로되 보라 세상 죄를 지고 가는 하나님의 어린 양이로다', en:'The next day John seeth Jesus coming unto him, and saith, Behold the Lamb of God, which taketh away the sin of the world.', zh:'次日，约翰看见耶稣来到他那里，就说：「看哪，神的羔羊，除去世人罪孽的！」', ru:'На другой день видит Иоанн идущего к нему Иисуса и говорит: вот Агнец Божий, Который берёт на Себя грех мира.', ja:'翌日、ヨハネはイエスが自分の方に来るのを見て言った、「見よ、世の罪を取り除く神の小羊。」', es:'El siguiente día vió Juan a Jesús que venía a él, y dijo: He aquí el Cordero de Dios, que quita el pecado del mundo.' },
        { v:30, ko:'내가 전에 말하기를 내 뒤에 한 사람이 오는데 나보다 앞선 것은 그가 나보다 먼저 있었음이라 한 것이 이 사람을 가리킴이라', en:'This is he of whom I said, After me cometh a man which is preferred before me: for he was before me.', zh:'这就是我说过的：那在我以后来的，反成了在我以前的，因为他本来在我以前。', ru:'Сей есть, о Котором я сказал: за мною идёт Муж, Который стал впереди меня, потому что Он был прежде меня.', ja:'これが、「わたしの後にくる者は、わたしよりも優れたかたである。わたしよりも先におられたからである」とわたしの言ったその人である。', es:'Este es aquel de quien yo decía: Después de mí viene un varón, el cual es antes de mí; porque era primero que yo.' },
        { v:31, ko:'나도 그를 알지 못하였으나 내가 와서 물로 세례를 주는 것은 그를 이스라엘에게 나타내려 함이라 하니라', en:'And I knew him not: but that he should be made manifest to Israel, therefore am I come baptizing with water.', zh:'我先前不认识他，如今我来用水施洗，为的就是要叫他显明给以色列人。', ru:'Я не знал Его; но для того пришёл крестить в воде, чтобы Он явлен был Израилю.', ja:'わたしも彼を知らなかった。しかし、わたしが水でバプテスマを授けにきたのは、彼をイスラエルに現すためである」。', es:'Y yo no le conocía; mas para que fuese manifestado a Israel, por esto vine yo bautizando con agua.' },
        { v:32, ko:'요한이 또 증거하여 가로되 내가 보매 성령이 비둘기 같이 하늘로서 내려와서 그의 위에 머물렀더라', en:'And John bare record, saying, I saw the Spirit descending from heaven like a dove, and it abode upon him.', zh:'约翰又作见证说：「我曾看见圣灵，仿佛鸽子从天降下，住在他的身上。', ru:'И свидетельствовал Иоанн, говоря: я видел Духа, сходящего с неба, как голубя, и пребывающего на Нём.', ja:'またヨハネは証言した、「わたしは、御霊がはとのように天から下ってきて、彼の上にとどまるのを見た。', es:'Y Juan dió testimonio, diciendo: Vi al Espíritu que descendía del cielo como paloma, y reposó sobre él.' },
        { v:33, ko:'나도 그를 알지 못하였으나 나를 보내어 물로 세례를 주라 하신 그이가 나에게 말씀하시되 성령이 내려서 누구 위에든지 머무는 것을 보거든 그가 곧 성령으로 세례를 주는 이인 줄 알라 하셨기에', en:'And I knew him not: but he that sent me to baptize with water, the same said unto me, Upon whom thou shalt see the Spirit descending, and remaining on him, the same is he which baptizeth with the Holy Ghost.', zh:'我先前不认识他，只是那差我来用水施洗的，对我说：『你看见圣灵降下来，住在谁的身上，谁就是用圣灵施洗的。』', ru:'Я не знал Его; но Пославший меня крестить в воде сказал мне: на Кого увидишь Духа сходящего и пребывающего на Нём, Тот есть крестящий Духом Святым.', ja:'わたしも彼を知らなかった。しかし、水でバプテスマを授けるようにと、わたしを遣わされたかたが、わたしに言われた、「御霊が、だれかの上に下ってとどまるのを見たら、その人こそ、聖霊でバプテスマを授けるかたである」。', es:'Y yo no le conocía; mas el que me envió a bautizar con agua, aquel me dijo: Sobre quien vieres descender el Espíritu y que reposó sobre él, ese es el que bautiza con el Espíritu Santo.' },
        { v:34, ko:'내가 보고 그가 하나님의 아들이심을 증거하였노라 하니라', en:'And I saw, and bare record that this is the Son of God.', zh:'我看见了，就证明这是神的儿子。」', ru:'И я видел и засвидетельствовал, что Сей есть Сын Божий.', ja:'そしてわたしはそれを見た。だからわたしは、このかたが神の子であることを証言したのである」。', es:'Y yo le vi, y he dado testimonio de que éste es el Hijo de Dios.' },
        { v:35, ko:'또 이튿날 요한이 자기 제자 중 두 사람과 함께 섰다가', en:'Again the next day after John stood, and two of his disciples;', zh:'再次日，约翰同两个门徒站在那里。', ru:'На другой день опять стоял Иоанн и двое из учеников его.', ja:'翌日、またヨハネは弟子のうちのふたりと共に立っていたが、', es:'El siguiente día estaba otra vez Juan, y dos de sus discípulos;' },
        { v:36, ko:'예수의 다니심을 보고 말하되 보라 하나님의 어린 양이로다', en:'And looking upon Jesus as he walked, he saith, Behold the Lamb of God!', zh:'他见耶稣行走，就说：「看哪，神的羔羊！」', ru:'И, увидев идущего Иисуса, сказал: вот Агнец Божий.', ja:'イエスが歩いて行くのを見て言った、「見よ、神の小羊。」', es:'Y mirando a Jesús que andaba por allí, dijo: He aquí el Cordero de Dios.' },
        { v:37, ko:'두 제자가 그의 말을 듣고 예수를 좇거늘', en:'And the two disciples heard him speak, and they followed Jesus.', zh:'两个门徒听见他的话，就跟从了耶稣。', ru:'Услышав от него сии слова, оба ученика пошли за Иисусом.', ja:'ふたりの弟子は彼がそう言うのを聞いて、イエスに従った。', es:'Y le oyeron hablar los dos discípulos, y siguieron a Jesús.' },
        { v:38, ko:'예수께서 돌이켜 그 좇는 것을 보시고 물어 가라사대 무엇을 구하느냐 가로되 랍비여 어디 계시오니이까 하니 (랍비는 번역하면 선생이라)', en:'Then Jesus turned, and saw them following, and saith unto them, What seek ye? They said unto him, Rabbi, (which is to say, being interpreted, Master,) where dwellest thou?', zh:'耶稣转过身来，看见他们跟着，就问他们说：「你们要什么？」他们说：「拉比，在哪里住？」（拉比翻出来，就是夫子。）', ru:'Иисус же, обратившись и увидев их идущих, говорит им: что вам надобно? Они сказали Ему: Равви́, — что значит: учитель, — где живёшь?', ja:'イエスは振り向いて、彼らがついてくるのを見て言われた、「何を求めているのか」。彼らは言った、「ラビ（訳すと先生という）どこにおいでになりますか」。', es:'Y volviéndose Jesús, y viendo que le seguían, les dijo: ¿Qué buscáis? Y ellos le dijeron: Rabí (que quiere decir, Maestro), ¿dónde moras?' },
        { v:39, ko:'예수께서 가라사대 와 보라 그러므로 저희가 가서 계신 데를 보고 그 날 함께 거하니 때가 제 십시쯤 되었더라', en:'He saith unto them, Come and see. They came and saw where he dwelt, and abode with him that day: for it was about the tenth hour.', zh:'耶稣说：「你们来看。」他们就去看他在哪里住，这一天便与他同住；那时约有申初了。', ru:'Говорит им: пойдите и увидите. Они пошли и увидели, где Он живёт, и пробыли у Него день тот. Было около десятого часа.', ja:'イエスは言われた、「きなさい、そうすればわかります」。彼らはついて行って、イエスの宿っておられる所を見た。そしてその日イエスのところに泊まった。時は午後四時ごろであった。', es:'Les dijo: Venid y ved. Vinieron, y vieron donde moraba, y se quedaron con él aquel día: y era como la hora décima.' },
        { v:40, ko:'요한의 말을 듣고 예수를 좇는 두 사람 중에 하나는 시몬 베드로의 형제 안드레라', en:'One of the two which heard John speak, and followed him, was Andrew, Simon Peter\'s brother.', zh:'听见约翰的话跟从耶稣的那两个人，一个是西门彼得的兄弟安得烈。', ru:'Один из двух, слышавших от Иоанна об Иисусе и последовавших за Ним, был Андрей, брат Симона Петра.', ja:'ヨハネの言ったことを聞いてイエスに従ったふたりのうちのひとりは、シモン・ペテロの兄弟アンデレであった。', es:'Andrés, hermano de Simón Pedro, era uno de los dos que habían oído de Juan, y habían seguido a Jesús.' },
        { v:41, ko:'그가 먼저 자기 형제 시몬을 찾아 말하되 우리가 메시야를 만났다 하고 (메시야는 번역하면 그리스도라)', en:'He first findeth his own brother Simon, and saith unto him, We have found the Messias, which is, being interpreted, the Christ.', zh:'他先找着自己的哥哥西门，对他说：「我们遇见弥赛亚了。」（弥赛亚翻出来，就是基督。）', ru:'Он первый находит брата своего Симона и говорит ему: мы нашли Мессию, что значит: Христос.', ja:'彼はまず自分の兄弟シモンに会って、「わたしたちはメシヤ（訳するとキリスト）に会った」と言った。', es:'Este halló primero a su hermano Simón, y le dijo: Hemos hallado al Mesías (que quiere decir, el Cristo).' },
        { v:42, ko:'데리고 예수께로 오니 예수께서 보시고 가라사대 네가 요한의 아들 시몬이니 장차 게바라 하리라 하시니라 (게바는 번역하면 베드로라)', en:'And he brought him to Jesus. And when Jesus beheld him, he said, Thou art Simon the son of Jona: thou shalt be called Cephas, which is by interpretation, A stone.', zh:'于是领他去见耶稣。耶稣看着他，说：「你是约翰的儿子西门，你要称为矶法。」（矶法翻出来，就是彼得。）', ru:'И привёл его к Иисусу. Иисус же, взглянув на него, сказал: ты — Симон, сын Ионин; ты наречёшься Кифа, что значит: камень.', ja:'そしてイエスのところに彼を連れてきた。イエスはシモンを見つめて言われた、「あなたはヨハネの子シモンである。あなたはケパ（訳するとペテロ）と呼ばれるであろう」。', es:'Y le trajo a Jesús. Y mirándole Jesús, dijo: Tú eres Simón, hijo de Jonás; tú serás llamado Cefas (que quiere decir, Pedro).' },
        { v:43, ko:'이튿날 예수께서 갈릴리로 나가려 하시다가 빌립을 만나 이르시되 나를 좇으라 하시니', en:'The day following Jesus would go forth into Galilee, and findeth Philip, and saith unto him, Follow me.', zh:'又次日，耶稣想要往加利利去，遇见腓力，就对他说：「来跟从我吧！」', ru:'На другой день Иисус восхотел идти в Галилею, и находит Филиппа и говорит ему: иди за Мною.', ja:'翌日、イエスはガリラヤへ出て行こうとして、ピリポに出会い、「わたしに従ってきなさい」と言われた。', es:'El siguiente día quería salir a Galilea, y halló a Felipe, y le dijo: Sígueme.' },
        { v:44, ko:'빌립은 안드레와 베드로와 한 동네 벳새다 사람이라', en:'Now Philip was of Bethsaida, the city of Andrew and Peter.', zh:'腓力是伯赛大人，和安得烈、彼得同城。', ru:'Филипп же был из Вифсаиды, из одного города с Андреем и Петром.', ja:'ピリポはアンデレとペテロの故郷ベツサイダの人であった。', es:'Y Felipe era de Betsaida, la ciudad de Andrés y Pedro.' },
        { v:45, ko:'빌립이 나다나엘을 찾아 이르되 모세가 율법에 기록하였고 여러 선지자가 기록한 그이를 우리가 만났으니 요셉의 아들 나사렛 예수니라', en:'Philip findeth Nathanael, and saith unto him, We have found him, of whom Moses in the law, and the prophets, did write, Jesus of Nazareth, the son of Joseph.', zh:'腓力找着拿但业，对他说：「摩西在律法上所写的，和众先知所记的那一位，我们遇见了，就是约瑟的儿子拿撒勒人耶稣。」', ru:'Филипп находит Нафанаила и говорит ему: мы нашли Того, о Котором писали Моисей в законе и пророки, Иисуса, сына Иосифова, из Назарета.', ja:'ピリポはナタナエルに会って言った、「わたしたちは、モーセが律法の中に書いており、預言者たちが書いている、あのかたに会った。ヨセフの子、ナザレ人イエスがそのかたです」。', es:'Felipe halló a Natanael, y le dijo: Hemos hallado a aquel de quien escribió Moisés en la ley, y los profetas: a Jesús, el hijo de José, de Nazaret.' },
        { v:46, ko:'나다나엘이 가로되 나사렛에서 무슨 선한 것이 날 수 있느냐 빌립이 가로되 와 보라 하니라', en:'And Nathanael said unto him, Can there any good thing come out of Nazareth? Philip saith unto him, Come and see.', zh:'拿但业对他说：「拿撒勒还能出什么好的吗？」腓力说：「你来看！」', ru:'Но Нафанаил сказал ему: из Назарета может ли быть что доброе? Филипп говорит ему: пойди и посмотри.', ja:'ナタナエルは言った、「ナザレから何かよいものが出るだろうか」。ピリポは言った、「きて見なさい」。', es:'Y le dijo Natanael: ¿De Nazaret puede salir algo bueno? Le dijo Felipe: Ven y ve.' },
        { v:47, ko:'예수께서 나다나엘이 자기에게 오는 것을 보시고 그를 가리켜 가라사대 보라 이는 참 이스라엘 사람이라 그 속에 간사한 것이 없도다', en:'Jesus saw Nathanael coming to him, and saith of him, Behold an Israelite indeed, in whom is no guile!', zh:'耶稣看见拿但业来，就指着他说：「看哪，这是个真以色列人，他心里是没有诡诈的。」', ru:'Иисус, увидев идущего к Нему Нафанаила, говорит о нём: вот подлинно Израильтянин, в котором нет лукавства.', ja:'イエスはナタナエルがみもとにきたのを見て、彼についてこう言われた、「見よ、ほんとうのイスラエル人、この人には偽りがない」。', es:'Cuando Jesús vió a Natanael que venía a él, dijo de él: He aquí un verdadero Israelita, en quien no hay engaño.' },
        { v:48, ko:'나다나엘이 가로되 어떻게 나를 아시나이까 예수께서 대답하여 가라사대 빌립이 너를 부르기 전에 네가 무화과나무 아래 있을 때에 보았노라', en:'Nathanael saith unto him, Whence knowest thou me? Jesus answered and said unto him, Before that Philip called thee, when thou wast under the fig tree, I saw thee.', zh:'拿但业对他说：「你从哪里知道我呢？」耶稣回答说：「腓力还没有招呼你，你在无花果树底下，我就看见你了。」', ru:'Нафанаил говорит Ему: почём Ты знаешь меня? Иисус сказал ему в ответ: прежде нежели позвал тебя Филипп, когда ты был под смоковницею, Я видел тебя.', ja:'ナタナエルはイエスに言った、「どうしてわたしをご存知なのですか」。イエスは答えて言われた、「ピリポがあなたを呼ぶ前に、いちじくの木の下にいるのを見た」。', es:'Le dijo Natanael: ¿De dónde me conoces? Respondió Jesús y le dijo: Antes que Felipe te llamase, cuando estabas debajo de la higuera, te vi.' },
        { v:49, ko:'나다나엘이 대답하되 랍비여 당신은 하나님의 아들이시요 당신은 이스라엘의 임금이로소이다', en:'Nathanael answered and saith unto him, Rabbi, thou art the Son of God; thou art the King of Israel.', zh:'拿但业说：「拉比，你是神的儿子，你是以色列的王！」', ru:'Нафанаил отвечал Ему: Равви́! Ты Сын Божий, Ты Царь Израилев.', ja:'ナタナエルはイエスに答えた、「先生、あなたは神の子です。あなたはイスラエルの王です」。', es:'Respondió Natanael y le dijo: Rabí, tú eres el Hijo de Dios; tú eres el Rey de Israel.' },
        { v:50, ko:'예수께서 대답하여 가라사대 내가 너를 무화과나무 아래서 보았다 하므로 믿느냐 이보다 더 큰 일을 보리라', en:'Jesus answered and said unto him, Because I said unto thee, I saw thee under the fig tree, believest thou? thou shalt see greater things than these.', zh:'耶稣对他说：「因为我说在无花果树底下看见你，你就信吗？你将要看见比这更大的事。」', ru:'Иисус сказал ему в ответ: ты веришь, потому что Я тебе сказал: Я видел тебя под смоковницею; увидишь больше сего.', ja:'イエスは答えて言われた、「いちじくの木の下にあなたを見たと言ったので、信じるのか。それよりも大きなことを、あなたは見るであろう」。', es:'Respondió Jesús y le dijo: ¿Porque te dije que te vi debajo de la higuera, crees? Cosas mayores que estas verás.' },
        { v:51, ko:'또 가라사대 진실로 진실로 너희에게 이르노니 하늘이 열리고 하나님의 사자들이 인자 위에 오르락 내리락 하는 것을 보리라 하시니라', en:'And he saith unto him, Verily, verily, I say unto you, Hereafter ye shall see heaven open, and the angels of God ascending and descending upon the Son of man.', zh:'又说：「我实实在在地告诉你们，你们将要看见天开了，神的使者上去下来在人子身上。」', ru:'И говорит ему: истинно, истинно говорю вам: отныне будете видеть небо отверстым и Ангелов Божиих восходящих и нисходящих к Сыну Человеческому.', ja:'また言われた、「よくよくあなたがたに言っておく。天が開けて神の御使たちが人の子の上に上り下りするのを、あなたがたは見るであろう」。', es:'Y le dijo: De cierto, de cierto os digo: De aquí adelante veréis el cielo abierto, y los ángeles de Dios que suben y descienden sobre el Hijo del hombre.' }
      ]
    }
  }
};

// BOOK_LIST와 BIBLE 변환은 data.js에서 처리
